INSERT INTO misconfigurations VALUES('e5bedb85-c9d4-496f-b15a-690bc23932e3',1,'apache-httpd','ServerTokens','Full','Prod','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27380-5','8.1','ServerTokens Full exposes detailed Apache version and module information, enabling attackers to target specific vulnerabilities for the disclosed version.','Set ''ServerTokens Prod'' to expose only the product name.','value','always','','{"description": "The ServerTokens directive controls the amount of information about the Apache server that is included in HTTP responses. Setting it to ''Full'' reveals detailed version and module information which can be exploited by attackers.", "potential_impact": ["Enables attackers to identify specific vulnerabilities for targeted attacks", "Increases the risk of automated exploitation due to known vulnerabilities", "Reduces the difficulty of crafting tailored exploits against disclosed modules"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request to any endpoint on the server and examines the Server header in the response.", "result": "The attacker gains detailed information about the Apache version and enabled modules, allowing them to craft targeted attacks."}, "metric_justifications": {"ac": "AC=L: The exposure of detailed server information is trivially exploitable by sending a standard HTTP request without any additional preconditions.", "c": "C=P: Discloses specific Apache version and module details, aiding in crafting precise exploits.", "i": "I=N: No direct modification or access to sensitive data is granted through the exposed information alone.", "a": "A=N: Availability of services is not directly impacted by exposing server tokens.", "gel": "GEL=M: Misconfigurations like this are frequently exploited due to their ease and effectiveness in aiding targeted attacks.", "grl": "GRL=H: There is extensive documentation available on how to properly configure ServerTokens for security."}}','2026-06-20T01:20:54.909Z','2026-06-24T21:03:38.631Z');
INSERT INTO misconfigurations VALUES('a0cb5507-cc24-4ef7-b65a-e5fd3ccee9fe',1,'apache-httpd','ServerTokens','OS','Prod','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27380-5','8.1','ServerTokens OS exposes the operating system version in every HTTP response header, enabling attackers to precisely target known CVEs for the disclosed OS.','Set ''ServerTokens Prod'' to expose only the product name.','value','always','','{"description": "The ServerTokens directive controls what information about the server is disclosed in HTTP responses. Setting it to OS reveals the operating system version, which can be exploited by attackers to target specific vulnerabilities.", "potential_impact": ["Enables attackers to identify and exploit known CVEs for the exposed OS", "Increases the risk of targeted attacks based on precise OS knowledge", "Reduces the difficulty of crafting exploits tailored to a specific environment"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request and examines the Server header in the response. For example: GET / HTTP/1.1\r\nHost: example.com", "result": "The attacker gains knowledge of the exact OS version, allowing them to search for specific vulnerabilities or exploits."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily discover the OS version by sending a standard HTTP request and examining the Server header.", "c": "Why C=P: The disclosure of the operating system version provides critical information to attackers, enabling targeted attacks.", "i": "Why I=N: There is no direct impact on data or configuration modification through this exposure alone.", "a": "Why A=N: Availability is not directly impacted by revealing OS details in HTTP headers.", "gel": "Why GEL=M: Misconfigurations like ServerTokens=OS are frequently exploited due to the ease of detection and exploitation.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure this directive for security."}}','2026-06-20T01:21:32.877Z','2026-06-24T21:03:38.642Z');
INSERT INTO misconfigurations VALUES('7436a34f-0b36-435b-bc59-894d9985da2e',1,'apache-httpd','ServerTokens','Minor','Prod','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27380-5','8.1','ServerTokens set to ''Minor'' still provides more information than necessary, including the Apache version and some module details, which can be used by attackers to target specific vulnerabilities.','Set ''ServerTokens Prod'' or ''ProductOnly'' to minimize exposed server information.','value','always','','{"description": "The ServerTokens directive controls how much information about the server is disclosed in response headers. Setting it to ''Minor'' reveals more details than necessary, including the Apache version and some module information, which can be exploited by attackers.", "potential_impact": ["Discloses specific Apache version allowing attackers to target known vulnerabilities", "Provides detailed module information enabling attackers to craft attacks based on installed modules", "Increases reconnaissance efficiency for attackers looking to exploit server-specific configurations"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends an HTTP request and examines the Server header in the response. For example: GET / HTTP/1.1\r\nHost: example.com", "result": "The attacker gains detailed information about the Apache version and installed modules, facilitating targeted attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily discover server details by sending a standard HTTP request without any special preconditions.", "c": "Why C=P: The directive discloses critical information such as the Apache version and module details, which are readable to attackers.", "i": "Why I=N: There is no direct impact on data or configuration modification through this disclosure alone.", "a": "Why A=N: Availability of services is not directly impacted by the information disclosed in ServerTokens.", "gel": "Why GEL=M: Misconfigurations like revealing server version details are frequently exploited due to their widespread use and ease of detection.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure ServerTokens for security."}}','2026-06-20T01:22:14.625Z','2026-06-24T21:03:38.646Z');
INSERT INTO misconfigurations VALUES('eb7ef5fb-242e-4123-af52-7cbbf88de2d7',1,'apache-httpd','ServerSignature','On','Off','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27883-8','8.2','ServerSignature On discloses the Apache version and server name in error pages, allowing attackers to target known vulnerabilities specific to that version.','Set ''ServerSignature Off'' to remove the signature from server-generated documents.','value','always','','{"description": "The ServerSignature directive controls whether Apache includes its version number and other information in server-generated error messages. Setting it to ''On'' reveals detailed information about the server''s software version, which can be exploited by attackers to target known vulnerabilities specific to that version.", "potential_impact": ["Discloses the exact version of Apache being used", "Enables attackers to craft targeted attacks based on known vulnerabilities for that version", "Reduces the difficulty of reconnaissance efforts for an attacker"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a crafted HTTP request designed to trigger an error page, such as sending a malformed URL or invalid HTTP method.", "result": "The server responds with an error message containing the Apache version number and other potentially sensitive information."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily discover the Apache version by simply triggering an error page, requiring no special privileges or conditions beyond sending a standard HTTP request.", "c": "Why C=P: The disclosure of the server''s software version and other information provides critical details that could be used to craft targeted attacks.", "i": "Why I=N: There is no direct impact on data modification or configuration changes due to this misconfiguration alone.", "a": "Why A=N: Availability is not directly impacted by ServerSignature being set to ''On''.", "gel": "Why GEL=M: Misconfigurations like revealing server version information are frequently exploited as they provide clear targets for attackers.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure the ServerSignature directive."}}','2026-06-20T01:22:52.191Z','2026-06-24T21:03:38.650Z');
INSERT INTO misconfigurations VALUES('6b1c674b-3905-43e4-911b-d3e37686536c',1,'apache-httpd','FileETag','All','MTime Size','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','','8.4','FileETag All exposes inode numbers in ETag headers, allowing attackers to discern sensitive file metadata and potentially assist in other attacks.','Set ''FileETag None'' or ''FileETag MTime Size'' to avoid disclosing inode information.','value','always','','{"description": "The FileETag directive controls what information is included in ETag headers sent to clients. Setting it to ''All'' exposes inode numbers, which can be used by attackers to gather sensitive file metadata and aid in other attacks.", "potential_impact": ["Disclose detailed file metadata", "Assist in identifying specific files for further exploitation", "Facilitate reconnaissance efforts against the server"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a standard HTTP request to retrieve resources from the web server. The response includes ETag headers with inode numbers.", "result": "The attacker gains detailed file metadata, which can be used for further reconnaissance or attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily trigger this by sending a standard HTTP request to the server and examining the ETag headers.", "c": "Why C=P: The configuration discloses inode numbers, which are sensitive file metadata that could be used for reconnaissance or other attacks.", "i": "Why I=N: There is no direct impact on data modification or configuration changes through this misconfiguration alone.", "a": "Why A=N: Availability of the server and its resources remains unaffected by the exposure of inode numbers in ETag headers.", "gel": "Why GEL=M: Misconfigurations like exposing sensitive metadata via ETags are moderately common and can be exploited to aid other attacks.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure FileETag to avoid such issues."}}','2026-06-20T01:23:32.527Z','2026-06-24T21:03:38.655Z');
INSERT INTO misconfigurations VALUES('3bb4c49d-9698-4a0d-83be-83eeec0fa488',1,'apache-httpd','Timeout','300','10','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27688-1','9.1','A high Timeout value of 300 seconds allows attackers to initiate many connections and keep them open for a long time, consuming server resources and making the service less responsive. This leads to gradual resource exhaustion but does not cause an immediate crash.','Set ''Timeout 10'' or shorter in the Apache configuration.','value','always','','{"description": "The Timeout directive sets the maximum number of seconds Apache will wait for certain events before closing inactive connections. A value of 300 seconds is dangerous because it allows attackers to maintain open connections for an extended period, leading to resource exhaustion and denial-of-service conditions.", "potential_impact": ["Consumes server resources such as memory and CPU cycles", "Reduces the responsiveness of the web service by keeping idle connections open", "Enables a slowloris attack where attackers can keep many connections open indefinitely"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends multiple HTTP requests to the server and keeps them open for up to 300 seconds, exhausting resources.", "result": "The web service becomes unresponsive due to resource exhaustion."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending multiple HTTP requests and keeping connections open for the full timeout period of 300 seconds, requiring no special preconditions beyond sending a request.", "c": "Why C=N: No sensitive information is disclosed or readable through this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified by an attacker due to this misconfiguration alone.", "a": "Why A=P: Availability of the web service is significantly impacted as server resources are consumed and connections remain open for extended periods, leading to denial-of-service conditions.", "gel": "Why GEL=M: This type of misconfiguration can be exploited with moderate frequency due to its potential impact on resource availability.", "grl": "Why GRL=H: Remediation documentation is widely available and straightforward, making it easy for administrators to correct this issue."}}','2026-06-20T01:24:17.565Z','2026-06-24T21:03:38.659Z');
INSERT INTO misconfigurations VALUES('4693f866-5f7e-496a-a8bc-e5a21a20c4d6',1,'apache-httpd','KeepAlive','Off','On','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27456-3','9.2','Disabling KeepAlive increases the number of TCP connections required to serve requests, potentially leading to resource exhaustion and degraded performance during high traffic or DoS attacks.','Set ''KeepAlive On'' in httpd.conf.','value','always','','{"description": "The KeepAlive directive enables persistent HTTP connections to reduce latency for multiple requests from the same client. Disabling it (KeepAlive Off) can lead to increased server load and potential resource exhaustion during high traffic or DoS attacks.", "potential_impact": ["Increases server load due to higher number of TCP connections", "Leads to degraded performance under high traffic conditions", "Facilitates easier execution of Denial-of-Service (DoS) attacks"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends multiple HTTP requests with KeepAlive disabled, forcing the server to establish a new TCP connection for each request.", "result": "The server''s resources are overwhelmed by the increased number of connections, leading to degraded performance or service disruption."}, "metric_justifications": {"ac": "AC=L: An attacker can easily exploit this misconfiguration by sending multiple HTTP requests without establishing persistent connections, which is trivial and does not require any special preconditions.", "c": "C=N: No sensitive information is disclosed as a result of KeepAlive being disabled; however, the server''s availability may be compromised.", "i": "I=N: The misconfiguration does not allow for modification of data or configuration files on the server.", "a": "A=P: Availability is significantly impacted due to increased resource consumption and potential service disruption during high traffic or DoS attacks.", "gel": "GEL=M: This type of misconfiguration can be exploited moderately frequently as it affects performance and availability under certain conditions.", "grl": "GRL=H: There are extensive resources available for remediation, including official Apache documentation and security guidelines."}}','2026-06-20T01:24:55.764Z','2026-06-24T21:03:38.663Z');
INSERT INTO misconfigurations VALUES('08c87bfa-f86d-4d13-8953-06a682705798',1,'apache-httpd','MaxKeepAliveRequests','0','100','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27830-9','9.3','Setting MaxKeepAliveRequests to 0 allows unlimited requests per connection, which can lead to resource exhaustion and gradual DoS conditions. However, the impact is not immediate system crash but rather degraded performance over time.','Set ''MaxKeepAliveRequests 100'' or a similar reasonable limit to mitigate DoS risks.','value','always','','{"description": "The MaxKeepAliveRequests directive sets the maximum number of requests that can be made on a persistent HTTP connection. Setting this value to 0 allows an unlimited number of requests per connection, which can lead to resource exhaustion and degrade server performance over time.", "potential_impact": ["Degraded server performance due to excessive keep-alive connections", "Resource exhaustion leading to denial-of-service conditions", "Increased load on the server''s resources such as CPU and memory"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can repeatedly send requests over a single persistent connection without limit, causing resource depletion.", "result": "The server becomes unresponsive or performs poorly due to excessive keep-alive connections."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending an unlimited number of requests over a single persistent connection, requiring no special preconditions beyond making HTTP requests.", "c": "Why C=N: No sensitive information is disclosed or readable due to the misconfiguration.", "i": "Why I=N: The configuration cannot be modified directly through this attack vector.", "a": "Why A=P: Availability is significantly impacted as resource exhaustion can lead to denial-of-service conditions.", "gel": "Why GEL=M: This type of misconfiguration is moderately likely to be exploited due to its potential for causing significant performance degradation and DoS conditions.", "grl": "Why GRL=H: Remediation documentation is readily available, making it easy to correct the configuration."}}','2026-06-20T01:25:44.423Z','2026-06-24T21:03:38.666Z');
INSERT INTO misconfigurations VALUES('4a83463d-cbfc-4ebf-8467-1f7d9374e5de',1,'apache-httpd','KeepAliveTimeout','300','15','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27330-0','9.4','A high KeepAliveTimeout value of 300 seconds increases the risk of resource exhaustion and DoS attacks, as it allows connections to remain open for longer periods, consuming more server resources.','Set ''KeepAliveTimeout 15'' or less in the Apache configuration.','value','always','','{"description": "The KeepAliveTimeout directive specifies how long Apache will wait for subsequent requests on an open connection. A value of 300 seconds is dangerous because it significantly increases the risk of resource exhaustion and Denial of Service (DoS) attacks by allowing connections to remain open longer, consuming more server resources.", "potential_impact": ["Exhausts server resources", "Increases susceptibility to DoS attacks", "Reduces overall system performance"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends multiple HTTP requests with Keep-Alive headers, keeping connections open for the full 300 seconds. This can be done using a simple script or tool.", "result": "The server''s resources are consumed by idle connections, leading to reduced availability and performance."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending HTTP requests with Keep-Alive headers, requiring no special preconditions beyond a standard HTTP request.", "c": "Why C=N: No sensitive information is disclosed or readable due to the misconfiguration alone.", "i": "Why I=N: The configuration itself cannot be modified directly through exploitation; however, server resources can be indirectly affected.", "a": "Why A=P: Availability is significantly impacted as idle connections consume valuable server resources, leading to potential DoS conditions.", "gel": "Why GEL=M: This type of misconfiguration is moderately common and can be exploited by attackers with basic knowledge.", "grl": "Why GRL=H: There are numerous remediation guides available for adjusting the KeepAliveTimeout setting."}}','2026-06-20T01:26:32.596Z','2026-06-24T21:03:38.671Z');
INSERT INTO misconfigurations VALUES('dd5ec089-e4d3-410b-a492-cd6ce1bff99a',1,'apache-httpd','LimitRequestLine','0','8190','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27426-6','10.1','Setting LimitRequestLine to ''0'' allows an attacker to send arbitrarily large request lines, potentially causing a buffer overflow that can degrade server performance or lead to resource exhaustion. This results in partial availability impact but does not disclose sensitive information or allow for direct modification of data.','Set ''LimitRequestLine 8190''.','value','always','','{"description": "The LimitRequestLine directive sets an upper limit on the size of the request line sent by clients. Setting it to ''0'' disables this protection entirely, allowing attackers to send arbitrarily large request lines which can lead to buffer overflow conditions and degrade server performance.", "potential_impact": ["Degradation of server performance", "Resource exhaustion leading to denial of service", "Buffer overflow conditions that may allow for further exploitation"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a POST request with an excessively long URI, such as: GET /verylonguriabcdefghijklmnopqrstuvwxyz1234567890 HTTP/1.1", "result": "The server may crash or become unresponsive due to buffer overflow conditions."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending a large request line, requiring no special privileges or knowledge beyond basic HTTP requests.", "c": "Why C=N: No sensitive information is disclosed as a result of the attack.", "i": "Why I=N: The configuration and data cannot be directly modified through this vulnerability.", "a": "Why A=P: Availability is partially impacted due to potential server crashes or resource exhaustion.", "gel": "Why GEL=M: This type of misconfiguration can be exploited with moderate frequency as it is a known security risk in web servers.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation, making it relatively easy to address."}}','2026-06-20T01:27:21.727Z','2026-06-24T21:03:38.677Z');
INSERT INTO misconfigurations VALUES('a858c3ce-266a-4741-8ad8-c6832e4a7316',1,'apache-httpd','LimitRequestFields','0','100','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27741-8','10.2','Setting LimitRequestFields to 0 allows an unlimited number of request fields, which can be exploited by sending oversized requests that may exhaust server resources and cause performance degradation or denial-of-service conditions.','Set ''LimitRequestFields 100'' in the Apache configuration file.','value','always','','{"description": "The LimitRequestFields directive sets an upper limit on the number of request header fields that can be sent to the server. Setting this value to 0 allows unlimited request header fields, which can lead to resource exhaustion and denial-of-service attacks.", "potential_impact": ["Exhaust server resources", "Cause performance degradation", "Trigger a denial-of-service condition"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends an HTTP request with an excessive number of header fields to the Apache server. The request could look like this: GET / HTTP/1.1\r\nX-Test: value1\r\nX-Test: value2\r\n... (repeated many times)", "result": "The server''s resources are overwhelmed by handling and processing an excessive number of header fields, leading to performance degradation or a denial-of-service condition."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending oversized requests with numerous header fields without any special preconditions beyond making HTTP requests.", "c": "Why C=N: No sensitive information is disclosed or readable as a result of the attack.", "i": "Why I=N: The configuration and data on the server cannot be modified directly through this vulnerability.", "a": "Why A=P: Availability is significantly impacted due to resource exhaustion caused by handling excessive header fields.", "gel": "Why GEL=M: This type of misconfiguration can be exploited frequently as it allows for straightforward denial-of-service attacks.", "grl": "Why GRL=H: There are numerous resources and documentation available on how to properly configure LimitRequestFields."}}','2026-06-20T01:28:07.443Z','2026-06-24T21:03:38.682Z');
INSERT INTO misconfigurations VALUES('57ac05d1-da19-43b6-a4ad-73aeb562940c',1,'apache-httpd','LimitRequestFieldSize','0','8190','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27554-5','10.3','Setting LimitRequestFieldSize to ''0'' allows any size of request headers, which can lead to resource exhaustion and degrade server performance but does not directly expose sensitive information or allow arbitrary code execution.','Set ''LimitRequestFieldsize 8190''.','value','always','','{"description": "The LimitRequestFieldSize directive restricts the size of request headers to prevent resource exhaustion attacks. Setting this value to ''0'' removes any limit on the size of request headers, allowing attackers to send excessively large requests and potentially causing server performance degradation or crashes.", "potential_impact": ["Degradation of server performance due to handling oversized request headers", "Resource exhaustion leading to denial-of-service conditions", "Increased risk of buffer overflow attacks if improperly handled by the server"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a POST request with an extremely large Content-Length header, causing the server to allocate excessive memory and potentially crash.", "result": "The Apache HTTP Server becomes unresponsive or crashes due to resource exhaustion."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending oversized request headers without any special preconditions, making it trivially exploitable.", "c": "Why C=N: No sensitive information is directly disclosed or readable due to the misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified through this vulnerability; however, server resources can be exhausted.", "a": "Why A=P: Availability of the Apache HTTP Server is significantly impacted as it may crash or become unresponsive under attack conditions.", "gel": "Why GEL=M: This type of misconfiguration has been observed in multiple instances and is known to be exploited by attackers seeking to disrupt service availability.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official Apache documentation and security advisories."}}','2026-06-20T01:28:52.139Z','2026-06-24T21:03:38.688Z');
INSERT INTO misconfigurations VALUES('6bed243b-3852-4a0d-8705-49c2a39aad8e',1,'apache-httpd','LimitRequestBody','0','102400','N','N','L','N','N','P',5.0,4.70000000000000017,'L','H','[]','CCE-27618-8','10.4','Unlimited request body size allows remote attackers to send large requests, potentially causing resource exhaustion and degrading service performance. This leads to a partial availability impact but does not result in full system compromise.','Set ''LimitRequestBody 102400'' or an appropriate value for your application''s needs.','value','always','','{"description": "The LimitRequestBody directive restricts the size of request bodies sent to the server. Setting this value to 0 removes any limit on request body sizes, allowing attackers to send arbitrarily large requests which can lead to resource exhaustion and denial-of-service conditions.", "potential_impact": ["Degradation of service performance", "Resource exhaustion leading to system unavailability", "Increased risk of server crashes due to excessive memory usage"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a POST request with an extremely large body, such as:\nPOST / HTTP/1.1\nHost: example.com\nContent-Length: 50000000\ndata: very large payload", "result": "The server''s resources are overwhelmed by the large request, potentially causing it to crash or become unresponsive."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending a single oversized HTTP request without any special privileges or additional prerequisites.", "c": "Why C=N: No sensitive information is disclosed as the attack focuses on resource exhaustion rather than data exfiltration.", "i": "Why I=N: The configuration and data integrity are not directly compromised, but availability is impacted due to resource exhaustion.", "a": "Why A=P: Availability is partially affected because the server becomes unresponsive or crashes when handling large requests.", "gel": "Why GEL=M: This type of misconfiguration can be exploited with moderate frequency as it is a common oversight in web application security configurations.", "grl": "Why GRL=H: Remediation documentation and best practices for setting appropriate LimitRequestBody values are widely available."}}','2026-06-20T01:29:45.141Z','2026-06-24T21:03:38.692Z');
INSERT INTO misconfigurations VALUES('9d09ef10-1da5-4b6a-b1a8-cc6a689a0711',1,'apache-httpd','TraceEnable','On','Off','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','["CVE-2004-2320", "CVE-2007-3008"]','CCE-27531-3','5.8','HTTP TRACE enables Cross-Site Tracing (XST) to steal cookies and other sensitive information, but requires a victim to visit a malicious page — AC is Medium. Impact is partial credential theft, not full system access.','Set ''TraceEnable Off'' in httpd.conf.','value','always','','{"description": "The TraceEnable directive in Apache HTTP Server allows clients to send TRACE requests which can be used for Cross-Site Tracing (XST) attacks. Setting it to ''On'' is dangerous because it enables attackers to steal cookies and other sensitive information from users.", "potential_impact": ["Steal session cookies and authentication tokens", "Perform Cross-Site Scripting (XSS) attacks by injecting malicious JavaScript code", "Expose internal network details through HTTP headers"], "exploitation_scenario": {"prerequisites": ["An attacker must诱使用户访问恶意网页或注入恶意脚本", "受害者必须点击包含恶意TRACE请求的链接或访问嵌入了恶意代码的页面"], "example": "A malicious user crafts a TRACE request to the server: OPTIONS / HTTP/1.1\r\nHost: example.com\r\nConnection: keep-alive\r\nUser-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.4389.82 Safari/537.36", "result": "The server responds with the full request and response headers, including sensitive information such as cookies."}, "metric_justifications": {"ac": "Why AC=M: The attacker needs to诱使用户访问恶意网页或注入恶意脚本，这增加了攻击难度。", "c": "Why C=P: 敏感信息如会话cookie和认证令牌被泄露。", "i": "Why I=N: 服务器配置和数据本身不会被修改。", "a": "Why A=N: 可用性不受影响。", "gel": "Why GEL=M: 这种类型的误配置在实际攻击中较为常见，但不是非常频繁。", "grl": "Why GRL=H: 有广泛的文档和资源可用于修复此问题。"}}','2026-06-20T01:30:39.681Z','2026-06-24T21:03:38.696Z');
INSERT INTO misconfigurations VALUES('2ccb27df-819a-4e21-9f5f-88b35cca0ae0',1,'apache-httpd','Options','Indexes','None','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27657-6','5.2','Enabling ''Indexes'' allows directory listings, which can disclose file structure and potentially sensitive information to remote attackers with a single HTTP request.','Set ''Options None'' or ''Options Multiviews'' in the web root <Directory> directive.','value','always','','{"description": "The ''Options Indexes'' directive allows directory listings to be displayed when a user requests a URL that corresponds to a directory. This can expose sensitive file structures and potentially reveal information about the server''s configuration or content.", "potential_impact": ["Discloses file structure", "Reveals sensitive files and directories", "Assists in reconnaissance for further attacks"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user sends an HTTP GET request to a directory URL, such as http://example.com/directory/. The server responds with a list of files and subdirectories within that directory.", "result": "The attacker gains visibility into the file structure of the web server, which can be used for further reconnaissance or exploitation."}, "metric_justifications": {"ac": "Why AC=L: Enabling ''Indexes'' allows any unauthenticated user to trigger a directory listing with a standard HTTP request, making it trivially exploitable.", "c": "Why C=P: The disclosure of file structure and potentially sensitive files can provide valuable information for an attacker to exploit other vulnerabilities or gain unauthorized access.", "i": "Why I=N: Directory listings do not allow modification of data or configuration directly through this feature alone, though they may aid in identifying targets for further attacks.", "a": "Why A=N: The availability of the web server is generally unaffected by directory listings; however, it can indirectly impact availability if attackers use the information to launch other types of attacks.", "gel": "Why GEL=M: Directory listing misconfigurations are commonly exploited as they provide easy reconnaissance opportunities for attackers.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly secure web server configurations, including disabling directory listings."}}','2026-06-20T01:31:20.963Z','2026-06-24T21:03:38.699Z');
INSERT INTO misconfigurations VALUES('04b497a9-e4b1-4873-b864-fd536fd685f2',1,'apache-httpd','Options','FollowSymLinks','SymLinksIfOwnerMatch','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27877-0','5.3','FollowSymLinks allows directory traversal via symlinks, but exploitation requires an attacker who already has write access to create the symlink — AC is Medium. Impact is limited to partial information disclosure and integrity modification within the web application scope.','Use ''Options SymLinksIfOwnerMatch'' instead of ''Options FollowSymLinks''.','value','always','','{"description": "The ''Options FollowSymLinks'' directive allows clients to access files via symbolic links within the web directory. This can lead to unauthorized file disclosure or modification if an attacker has write access to create malicious symlinks.", "potential_impact": ["Disclose sensitive information stored in linked directories", "Modify files and configurations through symlink attacks", "Compromise integrity of web application data"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the web directory or a subdirectory where they can create symlinks", "The Apache server is configured with ''Options FollowSymLinks''"], "example": "Attacker creates a symlink in /var/www/html pointing to /etc/shadow and accesses it via HTTP request.", "result": "Sensitive system files are accessible through the web directory, leading to unauthorized information disclosure."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires an attacker with write access to create symlinks, which is a moderate barrier but not extremely difficult.", "c": "Why C=P: Partial information disclosure occurs as attackers can read files they should not have access to via symlinks.", "i": "Why I=P: Integrity of web application data and configuration files may be compromised through symlink attacks that allow file modification.", "a": "Why A=N: Availability is generally unaffected, but specific files or directories might become inaccessible if the attacker disrupts them.", "gel": "Why GEL=L: While symlink attacks are common, they require a specific set of conditions to exploit successfully, making it less frequent than other types of vulnerabilities.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure Apache to mitigate symlink risks."}}','2026-06-20T01:32:10.400Z','2026-06-24T21:03:38.703Z');
INSERT INTO misconfigurations VALUES('685174c9-4709-4ab9-818c-598891bfb8bf',1,'apache-httpd','Options','All','None','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27877-0','5.1','Options All allows full control over the root directory, enabling execution of CGI scripts and server-side includes. Exploitation requires write access to create malicious files or scripts — AC is Medium. Impact is limited to partial information disclosure and integrity compromise within the web application scope.','Set ''Options None'' for the root <Directory> element in httpd.conf.','value','always','','{"description": "The ''Options All'' directive in Apache HTTP Server enables all options for the specified directory, including execution of CGI scripts and server-side includes. This is dangerous because it allows attackers with write access to create malicious files or scripts that can be executed on the server.", "potential_impact": ["Discloses sensitive information through crafted requests", "Enables unauthorized modification of web application data", "Allows for remote code execution if a vulnerability exists in CGI scripts"], "exploitation_scenario": {"prerequisites": ["Write access to the web root directory or subdirectory", "Knowledge of how to exploit server-side includes or CGI scripts"], "example": "An attacker uploads a malicious .cgi file and triggers it via an HTTP request to execute arbitrary commands on the server.", "result": "The attacker gains unauthorized control over the web application, potentially leading to data theft, modification, or complete compromise of the system."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires write access to the directory and knowledge of how to exploit server-side includes or CGI scripts, creating a moderate barrier.", "c": "Why C=P: Sensitive information can be disclosed through crafted requests that trigger malicious files or scripts.", "i": "Why I=P: Web application data can be modified by uploading and executing malicious files or scripts.", "a": "Why A=N: Availability is not directly affected, but the web application may become unavailable if critical system resources are consumed or corrupted.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited as it requires specific conditions to be met by an attacker.", "grl": "Why GRL=H: There is extensive documentation and guidance available for securing Apache HTTP Server configurations."}}','2026-06-20T01:32:58.866Z','2026-06-24T21:03:38.707Z');
INSERT INTO misconfigurations VALUES('9e9e1973-907c-43cb-86d5-8f1e20513b67',1,'apache-httpd','AllowOverride','All','None','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27536-2','4.4','AllowOverride All allows .htaccess files to override server configuration, but exploitation requires an attacker who already has write access to the web root — AC is Medium. Impact is limited to partial information disclosure and integrity modification within the web application scope.','Set ''AllowOverride None'' globally; enable selectively only where required.','value','always','','{"description": "The AllowOverride directive controls which .htaccess file directives can override server configuration settings. Setting it to ''All'' allows any .htaccess file in a directory to modify Apache''s behavior, potentially leading to security vulnerabilities if an attacker gains write access to the web root.", "potential_impact": ["Discloses sensitive information through improperly configured .htaccess files", "Enables unauthorized modification of server configurations and permissions", "Allows execution of arbitrary code via misconfigured directives"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the web root directory", "The attacker needs knowledge of how .htaccess files can be used to manipulate Apache settings"], "example": "Attacker uploads a malicious .htaccess file with directives like ''Options +ExecCGI'' and ''AddHandler cgi-script .pl'', allowing execution of arbitrary Perl scripts.", "result": "The attacker gains control over the web server''s configuration, potentially leading to full compromise of the application."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires an attacker with write access to the web root directory and knowledge of how .htaccess files can be used to manipulate Apache settings.", "c": "Why C=P: Sensitive information such as server configuration details or application-specific directives may be disclosed through improperly configured .htaccess files.", "i": "Why I=P: An attacker can modify server configurations, permissions, and execute arbitrary code via misconfigured .htaccess files, leading to partial integrity compromise within the web application scope.", "a": "Why A=N: Availability is not directly affected by this misconfiguration; however, it may indirectly impact availability if an attacker uses it to disrupt service or cause denial of service conditions.", "gel": "Why GEL=L: While exploitation requires specific preconditions (write access and knowledge), the frequency of successful attacks can be relatively low due to the need for these prerequisites.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure .htaccess files and mitigate risks associated with AllowOverride settings."}}','2026-06-20T01:33:48.663Z','2026-06-24T21:03:38.711Z');
INSERT INTO misconfigurations VALUES('f6e19a63-8581-4f55-a2fc-57db3674cd40',1,'apache-httpd','LoadModule','dav_module','#LoadModule dav_module','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27132-0','2.3','Enabling WebDAV modules exposes additional attack vectors for unauthorized file access and manipulation, but exploitation typically requires specific preconditions such as misconfigured access controls or local write access.','Comment out the ''LoadModule dav_module'' and ''LoadModule dav_fs_module'' directives in httpd.conf to disable WebDAV functionality.','value','always','','{"description": "The directive LoadModule dav_module enables the WebDAV module in Apache HTTP Server. Enabling this module can expose additional attack vectors for unauthorized file access and manipulation.", "potential_impact": ["Expose files to unauthorized read or write access", "Allow attackers to upload malicious scripts", "Enable directory traversal attacks"], "exploitation_scenario": {"prerequisites": ["Misconfigured access controls allowing write permissions", "Local network position for some types of attacks"], "example": "An attacker with local write access can use PUT requests to upload files. For example, a malicious user could send an HTTP request like: PUT /path/to/file.php HTTP/1.1 Host: target.example.com Content-Type: application/x-httpd-php", "result": "The attacker gains unauthorized control over the server''s file system and can modify or delete critical files."}, "metric_justifications": {"ac": "Why AC=M: Exploitation typically requires specific preconditions such as misconfigured access controls or local write access, making it moderately difficult.", "c": "Why C=P: Information disclosure occurs when attackers gain unauthorized read access to sensitive files and directories.", "i": "Why I=P: Attackers can modify or delete critical configuration files and scripts, leading to potential system compromise.", "a": "Why A=N: Availability is not directly affected unless the attacker uses WebDAV to disrupt services through file deletion or modification.", "gel": "Why GEL=L: Exploitation of this misconfiguration requires specific conditions that are less common in well-configured environments.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure and secure WebDAV functionality."}}','2026-06-20T01:34:37.466Z','2026-06-24T21:03:38.715Z');
INSERT INTO misconfigurations VALUES('26bc54ce-2427-4110-8d88-47acafd3e87f',1,'apache-httpd','LoadModule','status_module','#LoadModule status_module','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27357-3','2.4','Enabling mod_status provides detailed server performance statistics, which can be used by attackers to refine their attacks based on the current load and configuration of the server.','Comment out or remove the ''LoadModule status_module modules/mod_status.so'' directive in httpd.conf.','value','always','','{"description": "The LoadModule directive is used to enable Apache modules. Enabling status_module provides detailed server performance statistics via the server-status page, which can be accessed by any user and reveals sensitive information about the server''s configuration and load.", "potential_impact": ["Discloses internal server details that could aid in further attacks", "Enables attackers to monitor server performance for timing attacks", "Provides insights into Apache configurations that may contain vulnerabilities"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request to /server-status and retrieves detailed information about the server''s current state.", "result": "The attacker gains visibility into the server''s performance metrics, module status, and other sensitive details."}, "metric_justifications": {"ac": "Why AC=L: The status_module can be trivially accessed via a standard HTTP request without any authentication or additional preconditions.", "c": "Why C=P: The module exposes critical information about the server''s configuration, performance metrics, and current state to unauthorized users.", "i": "Why I=N: While the module provides read-only access, it does not allow for modification of data or configuration files directly through this interface.", "a": "Why A=N: There is no direct impact on availability as the server-status page only provides information without affecting service delivery.", "gel": "Why GEL=M: Misconfigurations like exposing status_module are common and frequently exploited by attackers to gather intelligence.", "grl": "Why GRL=H: Remediation steps for disabling status_module are well-documented in Apache''s official documentation and security advisories."}}','2026-06-20T01:35:20.518Z','2026-06-24T21:03:38.719Z');
INSERT INTO misconfigurations VALUES('9fea5f74-7028-4bd7-a46d-28e476e3c57e',1,'apache-httpd','LoadModule','info_module','#LoadModule info_module','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27852-3','2.8','Enabling the mod_info module allows attackers to access sensitive configuration information via /server-info, potentially exposing system paths, usernames/passwords, and database names.','Comment out or remove the ''LoadModule info_module modules/mod_info.so'' directive in httpd.conf.','value','always','','{"description": "The LoadModule directive enables Apache modules. Enabling info_module allows attackers to access detailed server configuration information via /server-info, which can expose sensitive data such as system paths and database credentials.", "potential_impact": ["Expose system paths", "Reveal usernames and passwords", "Disclose database names"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends an HTTP GET request to /server-info. The response contains detailed server configuration information.", "result": "The attacker gains access to sensitive configuration details that can be used for further attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily exploit this misconfiguration by sending a standard HTTP request to /server-info, requiring no special privileges or preconditions.", "c": "Why C=P: The module discloses critical configuration details that could be used for further attacks, such as identifying system paths and database credentials.", "i": "Why I=N: While the information is sensitive, enabling info_module does not allow modification of data or configuration directly through this endpoint.", "a": "Why A=N: Enabling info_module does not inherently affect server availability; however, it can lead to information disclosure that may indirectly impact availability if used in conjunction with other attacks.", "gel": "Why GEL=M: Misconfigurations like enabling the info_module are moderately common and often exploited by attackers looking for detailed system information.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this misconfiguration, making it relatively easy to find guidance."}}','2026-06-20T01:36:02.201Z','2026-06-24T21:03:38.724Z');
INSERT INTO misconfigurations VALUES('64112972-2a3b-4039-a8c2-fd10a4536387',1,'apache-httpd','LoadModule','autoindex_module','#LoadModule autoindex_module','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','','2.5','Enabling the autoindex module allows directory listings, revealing file and directory names which can aid attackers in understanding the server''s structure and identifying potential vulnerabilities.','Comment out or remove the ''LoadModule autoindex_module modules/mod_autoindex.so'' directive from httpd.conf to disable the mod_autoindex module.','value','always','','{"description": "The LoadModule directive enables Apache modules. Enabling autoindex_module allows directory listings to be displayed when a user requests a directory without an index file, revealing file and directory names which can aid attackers in understanding the server''s structure and identifying potential vulnerabilities.", "potential_impact": ["Discloses file and directory structures", "Aids reconnaissance efforts for further attacks", "Increases risk of information leakage"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends a request to a directory that does not have an index.html or similar default document. The server responds with a list of files and directories within the requested path.", "result": "The attacker gains visibility into the file structure, potentially identifying sensitive files or misconfigurations."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated user can easily trigger directory listings by requesting a directory without an index document. No special preconditions are required.", "c": "Why C=P: The module discloses file and directory names, providing valuable information to attackers for further reconnaissance or exploitation attempts.", "i": "Why I=N: Directory listing does not allow modification of data or configuration files directly through the autoindex_module itself.", "a": "Why A=N: Availability is not affected as the server continues to function normally while displaying directory listings.", "gel": "Why GEL=M: Misconfigurations allowing directory listings are common and frequently exploited by attackers for reconnaissance purposes.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure Apache to prevent directory listings."}}','2026-06-20T01:36:49.806Z','2026-06-24T21:03:38.729Z');
INSERT INTO misconfigurations VALUES('6f5046aa-144b-439e-928b-6e115732c1cd',1,'apache-httpd','LoadModule','userdir_module','#LoadModule userdir_module','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','CCE-27682-4','2.7','Enabling the UserDir module allows anonymous access to user home directories via HTTP requests, but exploitation requires an attacker to know specific usernames and paths — AC is Medium. This leads to partial information disclosure without full system compromise.','Comment out or remove the ''LoadModule userdir_module modules/mod_userdir.so'' directive in httpd.conf.','value','always','','{"description": "The LoadModule directive enables Apache modules. Enabling userdir_module allows anonymous access to user home directories via HTTP requests, which can lead to unauthorized information disclosure.", "potential_impact": ["Disclose sensitive files and directory structures", "Expose personal or development environments to the internet", "Reveal application configurations and source code"], "exploitation_scenario": {"prerequisites": ["Knowledge of specific usernames and paths on the server", "Access to a web browser or HTTP client"], "example": "An attacker can access user directories by making an HTTP request such as http://example.com/~username/", "result": "The attacker gains unauthorized read access to files within the specified user''s home directory."}, "metric_justifications": {"ac": "Why AC=M: Enabling userdir_module requires an attacker to know specific usernames and paths, creating a moderate barrier that is not trivial but also not highly complex.", "c": "Why C=P: Partial information disclosure occurs as sensitive files and directory structures are exposed without full system compromise.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration alone.", "a": "Why A=N: Availability is not affected; the server remains operational but vulnerable to information leakage.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited as it requires specific knowledge and does not offer a direct path to system compromise.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official Apache documentation and security guidelines."}}','2026-06-20T01:37:33.733Z','2026-06-24T21:03:38.734Z');
INSERT INTO misconfigurations VALUES('7b305930-3d9b-4a05-b220-71c3d3e0e32b',1,'apache-httpd','SSLProtocol','All','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','["CVE-2011-3389"]','CCE-27740-0','7.4','Enabling TLSv1.0 and TLSv1.1 exposes the server to vulnerabilities like BEAST, which can lead to information disclosure via CBC mode ciphers. Modern browsers no longer support these protocols, making exploitation more likely.','Set ''SSLProtocol +TLSv1.2 +TLSv1.3'' in the Apache configuration file.','value','always','','{"description": "The SSLProtocol directive specifies which versions of SSL/TLS are enabled for secure connections. Setting it to ''All'' enables outdated and insecure protocols like TLSv1.0 and TLSv1.1, exposing the server to known vulnerabilities such as BEAST.", "potential_impact": ["Expose the server to information disclosure via CBC mode ciphers", "Allow attackers to exploit deprecated SSL/TLS versions for man-in-the-middle attacks", "Reduce security posture by enabling insecure cryptographic protocols"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can send a specially crafted request using an outdated TLS version, such as TLSv1.0 or TLSv1.1, to exploit vulnerabilities like BEAST.", "result": "The server responds with encrypted data that the attacker can decrypt due to weaknesses in the deprecated protocols."}, "metric_justifications": {"ac": "Why AC=L: Any unauthenticated attacker can trigger this vulnerability by sending a standard HTTP request using an outdated TLS version, making exploitation trivial.", "c": "Why C=P: Confidentiality is partially impacted as attackers can exploit vulnerabilities in deprecated protocols to disclose sensitive information.", "i": "Why I=N: The misconfiguration does not allow for direct modification of data or configuration files on the server.", "a": "Why A=N: Availability is not directly affected by this misconfiguration, but it may indirectly impact service if exploited successfully.", "gel": "Why GEL=M: Exploitation frequency is moderate as attackers actively seek out and exploit servers with outdated TLS versions.", "grl": "Why GRL=H: There are numerous resources available for remediation of SSLProtocol misconfigurations, making it easy to find guidance on how to fix this issue."}}','2026-06-20T01:38:25.497Z','2026-06-24T21:03:38.739Z');
INSERT INTO misconfigurations VALUES('6acb5a79-889a-4284-86c3-1fc93742982e',1,'apache-httpd','SSLProtocol','+SSLv3','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','["CVE-2014-3566"]','CCE-27740-0','7.4','Enabling SSLv3 exposes the server to vulnerabilities like POODLE, which can lead to plaintext information disclosure. Any remote attacker can exploit this with a single HTTP request.','Set ''SSLProtocol TLSv1.2 +TLSv1.3'' in httpd.conf.','value','always','','{"description": "The SSLProtocol directive specifies which SSL/TLS protocols are enabled for secure connections. Enabling +SSLv3 exposes the server to vulnerabilities such as POODLE, which can lead to plaintext information disclosure.", "potential_impact": ["Disclose sensitive data in plaintext", "Enable man-in-the-middle attacks", "Expose the server to known SSLv3 vulnerabilities"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request to a vulnerable endpoint that supports SSLv3, initiating a connection using this outdated protocol.", "result": "The attacker can exploit the POODLE vulnerability to decrypt sensitive information transmitted over the SSLv3 connection."}, "metric_justifications": {"ac": "Why AC=L: Enabling +SSLv3 exposes the server to vulnerabilities like POODLE, which can be exploited with a single HTTP request. No special preconditions are required beyond sending an ordinary request.", "c": "Why C=P: The attacker can read sensitive data in plaintext due to vulnerabilities such as POODLE.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity from enabling SSLv3 alone.", "a": "Why A=N: Availability of services remains unaffected, but confidentiality and integrity are compromised.", "gel": "Why GEL=M: Exploitation of SSLv3 vulnerabilities like POODLE has been observed in the wild with moderate frequency.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate SSLv3 support, including detailed guides and best practices."}}','2026-06-20T01:39:11.249Z','2026-06-24T21:03:38.744Z');
INSERT INTO misconfigurations VALUES('342ce316-5e69-4ce6-86bf-54f23b11d2b2',1,'apache-httpd','SSLCompression','On','Off','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','["CVE-2012-4929"]','','7.7','Enabling SSL compression increases the risk of CRIME attacks, allowing an attacker to derive session cookie values and potentially impersonate users.','Set ''SSLCompression Off'' in the Apache configuration files.','value','always','','{"description": "The SSLCompression directive enables or disables compression for SSL/TLS connections. Setting it to ''On'' increases the risk of CRIME attacks, which can allow an attacker to derive session cookie values and potentially impersonate users.", "potential_impact": ["Disclose sensitive information such as session cookies", "Enable attackers to perform session hijacking", "Compromise user authentication and data integrity"], "exploitation_scenario": {"prerequisites": ["An attacker with the ability to intercept SSL/TLS traffic"], "example": "Attacker sends specially crafted requests to exploit compression-based attacks like CRIME, using statistical analysis of compressed data sizes.", "result": "The attacker successfully extracts session cookie values and can use them for unauthorized access."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it trivial to exploit once the vulnerability is known.", "c": "Why C=P: The attack allows an attacker to read sensitive information such as session cookies and other compressed data.", "i": "Why I=N: There is no direct impact on modifying server configuration or data due to this misconfiguration alone.", "a": "Why A=N: Availability of the service is not directly impacted by enabling SSL compression, though it may indirectly affect users through compromised sessions.", "gel": "Why GEL=M: This type of misconfiguration has been exploited in the past and remains a concern for systems with outdated configurations.", "grl": "Why GRL=H: There are numerous resources available online detailing how to remediate this issue, including official Apache documentation."}}','2026-06-20T01:39:50.187Z','2026-06-24T21:03:38.748Z');
INSERT INTO misconfigurations VALUES('d0bc2030-ccc8-44f3-97e3-9c231c5d3a99',1,'apache-httpd','User','root','apache','N','N','L','C','C','N',9.40000000000000035,8.69999999999999929,'L','H','[]','CCE-27756-6','3.1','Running Apache as the root user allows any web vulnerability to grant full system access, enabling attackers to compromise the entire server without further steps.','Set ''User apache'' and ''Group apache'' in httpd.conf to run Apache with a dedicated unprivileged account.','value','always','','{"description": "The User directive specifies which user account Apache runs under. Setting it to ''root'' allows Apache to execute all system commands and access any file on the server, significantly increasing the risk of a full system compromise if an attacker exploits a web vulnerability.", "potential_impact": ["Compromise the entire server", "Gain root privileges for the attacker", "Execute arbitrary code with elevated permissions"], "exploitation_scenario": {"prerequisites": ["An exploitable web application or Apache module"], "example": "An attacker sends a malicious request to an affected web application, triggering a vulnerability that allows them to execute commands as the root user.", "result": "The attacker gains full control over the server and can modify system configurations, steal sensitive data, or install backdoors."}, "metric_justifications": {"ac": "Why AC=L: Running Apache as ''root'' makes it trivial for an attacker to escalate privileges if any web application running under this configuration has a vulnerability. The attacker only needs to exploit the web application flaw.", "c": "Why C=C: An attacker can read or disclose sensitive system files and configurations, leading to potential data exfiltration or further exploitation.", "i": "Why I=C: With root privileges, an attacker can modify any file on the server, including critical system binaries and configuration files, potentially allowing for persistent backdoor installation.", "a": "Why A=N: The availability of services is not directly impacted by running Apache as ''root'', but the risk of service disruption or denial-of-service attacks increases due to compromised system integrity.", "gel": "Why GEL=M: Misconfigurations like running web servers with root privileges are common and frequently exploited, making this type of vulnerability a frequent target for attackers.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure Apache to run under a non-privileged user account, making it easy to find guidance on remediation."}}','2026-06-20T01:40:30.749Z','2026-06-24T21:03:38.752Z');
INSERT INTO misconfigurations VALUES('57b1c824-d59f-4531-bc27-1b3fee173f3c',1,'apache-httpd','Group','root','apache','N','N','L','P','C','N',8.5,7.90000000000000035,'L','H','[]','CCE-27566-9','3.1','Running Apache with Group ''root'' allows any web vulnerability to grant full system access via group permissions, enabling attackers to modify critical system files and escalate privileges.','Set ''Group apache'' in the httpd.conf file.','value','always','','{"description": "The Group directive in Apache HTTP Server specifies the group under which the server runs. Setting ''Group root'' allows the web server to have full system access via group permissions, potentially enabling any web vulnerability to be exploited for privilege escalation.", "potential_impact": ["Allows an attacker to modify critical system files", "Enables unauthorized execution of commands with elevated privileges", "Facilitates further exploitation and lateral movement within the network"], "exploitation_scenario": {"prerequisites": ["An existing web application vulnerability"], "example": "An attacker exploits a known vulnerability in an Apache module or CGI script, gaining control over the server process. By leveraging the ''Group root'' setting, they can modify system files such as /etc/passwd to escalate privileges.", "result": "The attacker gains full administrative access to the system."}, "metric_justifications": {"ac": "Why AC=L: An attacker only needs a web application vulnerability and no additional permissions beyond sending an HTTP request, making it easy to exploit.", "c": "Why C=P: The configuration allows for disclosure of sensitive information through file access or command execution.", "i": "Why I=C: Full system modification is possible due to the ''Group root'' setting, allowing attackers to alter critical files and configurations.", "a": "Why A=N: Availability may be affected if the attacker disrupts services by modifying configuration files or deleting essential system binaries.", "gel": "Why GEL=M: Misconfigurations like running Apache with group ''root'' are frequently exploited due to their ease of use and high impact.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure the Group directive for security best practices."}}','2026-06-20T01:41:08.673Z','2026-06-24T21:03:38.755Z');
INSERT INTO misconfigurations VALUES('65bf23b2-d7d6-48b4-8e2a-26d0357b6637',1,'apache-httpd','LogLevel','emerg','warn','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','CCE-27879-6','6.1','Setting LogLevel to ''emerg'' severely restricts the logging of errors, making it difficult to detect and respond to potential security issues. This can allow attackers to exploit vulnerabilities without being detected.','Set ''LogLevel notice core:info'' to ensure that all critical errors are logged for monitoring and forensic analysis.','value','always','','{"description": "The LogLevel directive controls the verbosity of Apache HTTP Server logs. Setting LogLevel to ''emerg'' restricts logging to only the most critical errors, which can prevent detection and response to security incidents.", "potential_impact": ["Prevent detection of unauthorized access attempts", "Hinder forensic analysis by limiting error log entries", "Allow attackers to exploit vulnerabilities without being logged"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends a malicious request that would normally trigger an error in the logs. Since LogLevel is set to ''emerg'', no logging occurs, and the attack goes undetected.", "result": "The attacker can exploit vulnerabilities without being logged or detected."}, "metric_justifications": {"ac": "Why AC=L: Setting LogLevel to ''emerg'' makes it easy for attackers to exploit vulnerabilities without detection because no logging occurs, making the attack chain straightforward and requiring minimal effort.", "c": "Why C=P: The configuration itself is readable by anyone with access to the server''s configuration files, allowing them to identify this misconfiguration easily.", "i": "Why I=N: There is no direct impact on data or configuration modification due to the logging level alone; however, it indirectly enables other attacks that could modify data or configurations.", "a": "Why A=N: The availability of the service itself is not directly impacted by this misconfiguration. However, it can lead to indirect impacts if attackers exploit vulnerabilities without detection.", "gel": "Why GEL=M: Misconfigurations like setting LogLevel to ''emerg'' are common and frequently exploited due to their ease of discovery and exploitation.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure the LogLevel directive, making it easy for administrators to identify and remediate this issue."}}','2026-06-20T01:41:51.872Z','2026-06-24T21:03:38.761Z');
INSERT INTO misconfigurations VALUES('374e1073-ceaf-4370-858b-764765217475',1,'apache-httpd','Order','Allow,Deny','Deny,Allow','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','CCE-27510-7','4.1','Order ''Allow,Deny'' allows access to the OS root directory unless explicitly denied elsewhere. This requires an attacker to have write access or a specific network position to exploit it — AC is Medium. The impact is limited to partial information disclosure.','Use ''Require all denied'' in the root <Directory> element to enforce default deny policy.','value','always','','{"description": "The ''Order Allow,Deny'' directive in Apache HTTP Server allows access to all users by default and then selectively denies access based on subsequent rules. This misconfiguration can lead to unauthorized access if not properly managed, as it does not enforce a strict deny-first policy.", "potential_impact": ["Discloses partial information about the file system structure", "Enables unauthorized read access to sensitive files or directories", "Allows an attacker with write permissions to modify web content"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the web root directory or a specific network position that allows them to upload malicious content.", "The attacker needs to identify files or directories that are not explicitly denied in other configuration directives."], "example": "A misconfigured .htaccess file with ''Order Allow,Deny'' can be exploited by an attacker who uploads a PHP script to the web root directory. The attacker then accesses this script via HTTP request.", "result": "The attacker gains unauthorized read access to sensitive files or directories and potentially executes arbitrary code on the server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to the web root directory or a specific network position, which adds an additional layer of difficulty compared to trivial exploitation. This moderate barrier aligns with Medium complexity.", "c": "Why C=P: The misconfiguration allows partial information disclosure about file system structure and sensitive files, but does not lead to full control over the server.", "i": "Why I=N: While write access can be achieved, there is no direct impact on data modification or configuration changes unless an attacker exploits additional vulnerabilities.", "a": "Why A=N: The availability of services is not directly impacted by this misconfiguration; however, it may indirectly affect service integrity if sensitive files are accessed or modified.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited in the wild as attackers often target more direct vulnerabilities for full control rather than partial information disclosure.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure Apache HTTP Server directives, including best practices for security."}}','2026-06-20T01:42:43.031Z','2026-06-24T21:03:38.765Z');
INSERT INTO misconfigurations VALUES('dc50f730-e90f-4cbe-a8a9-d52afc5be90b',1,'apache-httpd','SSLUseStapling','','SSLUseStapling On','N','N','M','P','N','N',0.0,0.0,'L','H','[]','','7.10','Without SSLUseStapling On, Apache does not perform OCSP stapling. Clients must contact the CA directly for revocation status, which leaks browsing activity to the CA, degrades performance, and can be suppressed if the OCSP responder is unavailable.','Add ''SSLUseStapling On'' and ''SSLStaplingCache shmcb:logs/ssl_staple_cache(512000)'' to the server-level configuration and every SSL-enabled VirtualHost.','absence','if_directive:SSLCertificateFile','','{"description": "The SSLUseStapling directive enables OCSP (Online Certificate Status Protocol) stapling in Apache. Without ''SSLUseStapling On'', clients must independently query CAs for certificate revocation status, leading to privacy leaks and potential performance degradation.", "potential_impact": ["Leak browsing activity to the CA", "Degrade client performance due to additional network requests", "Expose users to man-in-the-middle attacks if OCSP responder is unavailable"], "exploitation_scenario": {"prerequisites": ["An attacker must intercept traffic between a client and an Apache server", "The client''s browser must be configured to check for certificate revocation status"], "example": "Attacker monitors network traffic to identify requests made by the client to the CA for OCSP checks. Attacker uses this information to correlate user activity.", "result": "The attacker gains insight into which websites a user is visiting, potentially allowing them to track user behavior and target specific users with phishing attacks."}, "metric_justifications": {"ac": "AC=M: An attacker needs to be in a position to intercept network traffic between the client and CA for OCSP checks. This requires an active MITM (Man-In-The-Middle) attack, which is moderately difficult but feasible.", "c": "C=P: The information disclosed includes browsing activity patterns that can be used to infer user behavior and interests.", "i": "I=N: There are no direct modifications or data breaches as a result of the misconfiguration itself; however, indirect impacts on privacy and security exist.", "a": "A=N: Availability is not directly impacted by this misconfiguration. However, performance may degrade due to additional network requests for OCSP checks.", "gel": "GEL=L: While SSLUseStapling misconfigurations are common, they do not typically lead to widespread exploitation as the impact is primarily privacy-related and indirect.", "grl": "GRL=W: Remediation documentation is widely available in Apache''s official documentation and security guidelines."}}','2026-06-20T01:42:43.036Z','2026-06-24T21:03:38.768Z');
INSERT INTO misconfigurations VALUES('bebd1e7e-b8a6-461f-8c53-fb4cb102564a',1,'apache-httpd','Header','','Header always set Strict-Transport-Security "max-age=600; includeSubDomains"','N','N','M','P','P','N',0.0,0.0,'L','H','[]','','7.11','Without HSTS, browsers are not instructed to enforce HTTPS. This leaves users vulnerable to protocol downgrade attacks (sslstrip) and cookie hijacking on their first visit or after the HSTS policy expires.','Add ''Header always set Strict-Transport-Security "max-age=600; includeSubDomains"'' to every SSL-enabled VirtualHost.','absence','if_directive:SSLCertificateFile','Strict-Transport-Security','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.038Z','2026-06-24T21:03:38.772Z');
INSERT INTO misconfigurations VALUES('6e18490b-2467-4cc5-955c-3bbe62a7e61d',1,'apache-httpd','Header','','Header always append Content-Security-Policy "frame-ancestors ''self''"','N','N','L','P','P','N',0.0,0.0,'L','H','[]','','5.16','Without a Content-Security-Policy or X-Frame-Options header, Apache does not prevent clickjacking attacks where an attacker frames the site inside an iframe on a malicious page. UI redressing can trick users into performing unintended actions on the legitimate site.','Add ''Header always append Content-Security-Policy "frame-ancestors ''self''"'' to the server configuration.','absence','always','Content-Security-Policy','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.040Z','2026-06-24T21:03:38.777Z');
INSERT INTO misconfigurations VALUES('a5ce2711-6db4-46f6-a534-9fe99b40a410',1,'apache-httpd','Header','','Header set Referrer-Policy "strict-origin-when-cross-origin"','N','N','L','P','N','N',0.0,0.0,'L','H','[]','','5.17','Without an explicit Referrer-Policy header, browsers may send the full URL including sensitive query parameters (session tokens, PII) to third-party sites via the Referer header.','Add ''Header set Referrer-Policy "strict-origin-when-cross-origin"'' to the server configuration.','absence','always','Referrer-Policy','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.042Z','2026-06-24T21:03:38.782Z');
INSERT INTO misconfigurations VALUES('cd3aad2e-3ceb-4041-8073-d73aea8aa627',1,'apache-httpd','Header','','Header set Permissions-Policy "geolocation=(), microphone=(), camera=()"','N','N','L','P','N','N',0.0,0.0,'L','H','[]','','5.18','Without a Permissions-Policy header, browsers may allow web pages to access sensitive device features (geolocation, microphone, camera) without explicit restriction, violating the principle of least privilege.','Add ''Header set Permissions-Policy "geolocation=(), microphone=(), camera=()"'' to the server configuration, adjusted for the application''s actual needs.','absence','always','Permissions-Policy','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.045Z','2026-06-24T21:03:38.787Z');
INSERT INTO misconfigurations VALUES('01df25c0-aa24-49f8-8c04-cac2d531d15c',2,'nginx','server_tokens','on','off','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','2.5.1','ServerTokens on exposes the Apache version and OS in every HTTP response header, enabling attackers to conduct reconnaissance and target known vulnerabilities for the disclosed version.','Set ''server_tokens off'' to hide the server version and reduce attack surface.','value','always','','{"description": "The server_tokens directive in Nginx controls whether version information is included in HTTP responses. Setting it to ''on'' exposes detailed version and OS information which can be used by attackers for targeted attacks.", "potential_impact": ["Enables reconnaissance on the exact version of Nginx running, allowing attackers to identify known vulnerabilities specific to that version", "Increases risk of targeted exploitation based on disclosed version details", "Reduces overall security posture by providing unnecessary information to potential attackers"], "exploitation_scenario": {"prerequisites": ["An attacker with access to any HTTP request can exploit this misconfiguration."], "example": "Sending an OPTIONS or HEAD request to the server will reveal version details in the Server header.", "result": "The attacker gains detailed information about the Nginx version and OS, which can be used for further targeted attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily discover the server version by sending a standard HTTP request such as OPTIONS or HEAD.", "c": "Why C=P: The configuration information is disclosed, allowing attackers to conduct targeted reconnaissance and exploit known vulnerabilities.", "i": "Why I=N: No sensitive data or configurations are directly modified through this misconfiguration alone.", "a": "Why A=N: Availability of the service itself is not impacted by exposing version information in headers.", "gel": "Why GEL=M: Misconfigurations like server_tokens=on are frequently exploited due to their ease and effectiveness in reconnaissance.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, making it straightforward for administrators to fix."}}','2026-06-20T01:43:37.797Z','2026-06-20T03:39:44.636Z');
INSERT INTO misconfigurations VALUES('b335fba0-9275-4353-90b0-4c9637a99fda',2,'nginx','keepalive_timeout','65','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','2.4.3','A high keep-alive timeout can lead to resource exhaustion and degraded performance as too many persistent connections may remain open, consuming server resources over an extended period.','Set ''keepalive_timeout'' to a value of 10 seconds or less, but not 0. For example: ''keepalive_timeout 10;''','value','always','','{"description": "The keepalive_timeout directive sets the duration in seconds that Nginx will wait for subsequent requests on an open connection before closing it. A value of 65 seconds is excessively high and can lead to resource exhaustion as too many persistent connections may remain open, consuming server resources over a prolonged period.", "potential_impact": ["Degraded performance due to excessive open connections", "Resource exhaustion leading to denial-of-service conditions", "Increased vulnerability to specific attacks exploiting long-lived connections"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can exploit this misconfiguration by initiating a large number of keep-alive requests, causing the server to maintain these connections for up to 65 seconds. This can be done with standard HTTP requests.", "result": "The server''s resources are overwhelmed due to excessive open connections, leading to degraded performance and potential denial-of-service."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending a large number of keep-alive requests with standard HTTP methods, requiring no special preconditions beyond the ability to send HTTP requests.", "c": "Why C=N: No sensitive information is disclosed or readable as a result of this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified directly through exploitation; however, server resources can be consumed leading to indirect impact on other services.", "a": "Why A=P: Availability is significantly impacted due to resource exhaustion and degraded performance caused by excessive open connections.", "gel": "Why GEL=M: This type of misconfiguration is moderately common as administrators may not regularly review or adjust keepalive_timeout settings.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official Nginx documentation and security guidelines."}}','2026-06-20T01:44:20.797Z','2026-06-20T03:42:03.561Z');
INSERT INTO misconfigurations VALUES('de2faeca-57c0-4826-9ec5-b07a91a716da',2,'nginx','keepalive_timeout','0','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','2.4.3','Setting keepalive_timeout to ''0'' allows persistent connections to remain open indefinitely, potentially leading to resource exhaustion and denial of service attacks. However, the impact is gradual rather than immediate.','Set ''keepalive_timeout 10;'' or another value between 1-10 seconds.','value','always','','{"description": "The keepalive_timeout directive sets the duration in seconds that Nginx will wait for subsequent requests on an open connection before closing it. Setting this value to ''0'' disables the timeout entirely, allowing persistent connections to remain indefinitely and potentially leading to resource exhaustion.", "potential_impact": ["Exhaust server resources by maintaining large numbers of idle connections", "Enable denial-of-service attacks through resource starvation", "Impede legitimate users from accessing services due to limited connection slots"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can initiate a large number of HTTP requests with persistent keep-alive headers, maintaining connections indefinitely.", "result": "The server''s available connection slots are consumed by idle connections, preventing legitimate users from establishing new sessions."}, "metric_justifications": {"ac": "Setting the keepalive_timeout to ''0'' is easily exploitable as it requires only sending HTTP requests with persistent headers and maintaining those connections without further action.", "c": "No sensitive information is disclosed directly by this misconfiguration.", "i": "The configuration itself cannot be modified through this vulnerability, but server resources can be exhausted.", "a": "Availability is significantly impacted as the server''s ability to handle legitimate requests diminishes due to resource exhaustion.", "gel": "This type of misconfiguration is moderately likely to be exploited in environments where persistent connections are not properly managed.", "grl": "Remediation documentation for this issue is highly available, making it straightforward to correct."}}','2026-06-20T01:45:02.880Z','2026-06-20T03:43:57.487Z');
INSERT INTO misconfigurations VALUES('0f3ef6ed-98bf-41cd-8254-633631b75d1e',2,'nginx','send_timeout','0','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','2.4.4','Setting send_timeout to ''0'' allows for indefinite write operations, enabling slow HTTP denial of service attacks that can degrade server performance gradually.','Set ''send_timeout 10;'' in the Apache configuration to mitigate slow HTTP DoS attacks.','value','always','','{"description": "The send_timeout directive specifies the number of seconds Nginx waits for a client to send another request body part or message header. Setting it to ''0'' disables this timeout entirely, allowing clients to perform slow HTTP denial-of-service attacks by sending requests at an arbitrarily slow pace.", "potential_impact": ["Degradation of server performance", "Resource exhaustion leading to service unavailability", "Increased latency for legitimate users"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a request and deliberately pauses between sending each byte, ensuring the connection remains open without triggering any timeouts.", "result": "The server''s resources are gradually consumed by maintaining numerous idle connections, leading to denial of service for legitimate users."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily initiate a slow HTTP DoS attack with minimal effort and no special permissions required.", "c": "Why C=N: No sensitive information is disclosed as part of this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified by an attacker through this vulnerability.", "a": "Why A=P: Availability is significantly impacted due to resource exhaustion caused by slow HTTP DoS attacks.", "gel": "Why GEL=M: This type of misconfiguration can lead to frequent exploitation as it is well-known and easy to execute.", "grl": "Why GRL=H: There are numerous resources available for understanding and mitigating the risks associated with send_timeout misconfigurations."}}','2026-06-20T01:45:42.248Z','2026-06-20T03:45:53.416Z');
INSERT INTO misconfigurations VALUES('ffbd7a9d-f0bf-472d-b93d-203d6ce44fcb',2,'nginx','client_max_body_size','0','100k','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.2.2','Setting client_max_body_size to ''0'' immediately rejects all requests with a 413 error, preventing any legitimate user actions that require form submissions or file uploads. This can be exploited by attackers to cause resource exhaustion and degrade service availability.','Set ''client_max_body_size'' to an appropriate value based on application requirements, such as ''2M'', and override it for specific endpoints if necessary.','value','always','','{"description": "The directive client_max_body_size sets an upper limit on the size of request bodies that Nginx will accept. Setting this value to ''0'' immediately rejects all requests with a 413 error, which can be exploited by attackers to cause resource exhaustion and degrade service availability.", "potential_impact": ["Deny legitimate user actions requiring form submissions or file uploads", "Cause resource exhaustion through repeated attempts to trigger the 413 error", "Degrade service availability for all users"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends a series of HTTP requests with varying body sizes, triggering Nginx''s client_max_body_size=0 and causing it to respond with 413 errors.", "result": "The server resources are consumed by handling these erroneous requests, leading to denial-of-service for legitimate users."}, "metric_justifications": {"ac": "Why AC=L: Setting client_max_body_size to ''0'' makes the service immediately vulnerable to resource exhaustion attacks as any unauthenticated attacker can trigger this with a standard HTTP request.", "c": "Why C=N: No sensitive information is disclosed or readable due to the 413 error response.", "i": "Why I=N: The configuration cannot be modified by attackers since no write access is required to exploit this misconfiguration.", "a": "Why A=P: Availability is significantly impacted as legitimate users are denied service and server resources may become exhausted from handling erroneous requests.", "gel": "Why GEL=M: This type of misconfiguration can occur frequently due to oversight or misunderstanding of the directive''s impact.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available, making it easy to correct once identified."}}','2026-06-20T01:46:34.512Z','2026-06-20T03:48:07.405Z');
INSERT INTO misconfigurations VALUES('1264f888-7d71-4d72-a4c1-d37e166681a2',2,'nginx','ssl_protocols','TLSv1 TLSv1.1','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2014-3566", "CVE-2016-2107"]','','4.1.4','Enabling legacy TLS protocols (TLSv1 and TLSv1.1) exposes the server to known vulnerabilities such as POODLE and other attacks that exploit weaknesses in these older versions, allowing attackers to potentially steal sensitive data.','Set ''ssl_protocols TLSv1.3'' to use only modern and secure protocols.','value','always','','{"description": "The ssl_protocols directive specifies which TLS versions are supported by Nginx. Configuring it to use TLSv1 and TLSv1.1 exposes the server to vulnerabilities such as POODLE and other attacks that exploit weaknesses in these older protocols, potentially allowing attackers to steal sensitive data.", "potential_impact": ["Allows an attacker to perform a downgrade attack using known vulnerabilities like POODLE", "Enables exploitation of weaknesses in TLSv1 and TLSv1.1 for man-in-the-middle (MITM) attacks", "Increases the risk of session hijacking due to outdated encryption methods"], "exploitation_scenario": {"prerequisites": ["An attacker with network access between client and server"], "example": "Client requests a connection using TLSv1. An attacker intercepts this request, forcing a downgrade to SSLv3 or an earlier version, then uses the POODLE vulnerability to decrypt session cookies.", "result": "The attacker successfully steals sensitive data such as session tokens and can use them for unauthorized access."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker with network access between client and server can easily exploit vulnerabilities in TLSv1 and TLSv1.1, such as POODLE, without needing any special privileges or additional preconditions.", "c": "Why C=P: Confidentiality is partially compromised due to the ability of attackers to intercept and decrypt sensitive data transmitted over insecure connections.", "i": "Why I=N: The misconfiguration does not allow for modification of server-side configurations or data, but it can lead to unauthorized access through stolen credentials.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration; however, successful exploitation could indirectly affect availability if services are compromised and taken offline.", "gel": "Why GEL=M: This type of misconfiguration has been exploited moderately frequently due to the widespread use of older TLS versions before they were deprecated.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, including detailed guides and best practices from security organizations."}}','2026-06-20T01:47:31.502Z','2026-06-20T03:50:47.407Z');
INSERT INTO misconfigurations VALUES('abd678e9-8ab4-4531-83ae-a67726a50579',2,'nginx','ssl_protocols','SSLv3','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,5.0,'H','H','["CVE-2014-3566"]','','4.1.4','Enabling SSLv3 exposes the POODLE vulnerability, allowing attackers to exploit weaknesses in CBC encryption and obtain cleartext information. This is actively exploited in the wild.','Set ''ssl_protocols TLSv1.3'' to ensure only modern and secure protocols are used.','value','always','','{"description": "The ssl_protocols directive specifies which SSL/TLS protocols are enabled for secure connections. Enabling SSLv3 exposes the POODLE vulnerability, allowing attackers to exploit weaknesses in CBC encryption and obtain cleartext information.", "potential_impact": ["Disclose sensitive data through the POODLE attack", "Enable man-in-the-middle attacks by downgrading TLS to SSLv3", "Expose server to known vulnerabilities associated with SSLv3"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a specially crafted request to the server using SSLv3, initiating the POODLE attack.", "result": "The attacker can decrypt sensitive information transmitted over SSLv3 connections."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it trivial to exploit.", "c": "Why C=P: Confidentiality is partially compromised as the POODLE attack allows an attacker to decrypt sensitive data transmitted over SSLv3 connections.", "i": "Why I=N: Integrity is not directly impacted since no modifications can be made to the server''s configuration or data through this vulnerability alone.", "a": "Why A=N: Availability is not affected as the POODLE attack does not disrupt service availability, but it compromises confidentiality and integrity.", "gel": "Why GEL=H: The POODLE vulnerability is actively exploited in the wild due to its simplicity and effectiveness against SSLv3.", "grl": "Why GRL=H: There are extensive remediation guides available for disabling SSLv3 and enabling more secure protocols."}}','2026-06-20T01:48:19.672Z','2026-06-20T03:52:51.688Z');
INSERT INTO misconfigurations VALUES('e3becc61-4541-452d-875f-41c50f5c8d72',2,'nginx','ssl_session_tickets','off','on (or remove directive — default is on)','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','4.1.11','Disabling ssl_session_tickets in TLS 1.3 reduces performance by increasing handshake latency, but does not expose any sensitive information or allow direct attacks.','Ensure that the directive ''ssl_session_tickets'' is either removed or set to ''on''.','value','always','','{"description": "The ssl_session_tickets directive enables or disables session tickets in TLS 1.3 for resuming sessions without full handshakes. Disabling it with ''off'' reduces performance and increases handshake latency.", "potential_impact": ["Increases the overhead of establishing new connections due to lack of session resumption", "Reduces overall system performance by requiring more frequent full TLS handshakes"], "exploitation_scenario": {"prerequisites": [], "example": "A client connects to a server with ssl_session_tickets off and initiates multiple HTTPS requests. Each request requires a new full TLS handshake.", "result": "The server experiences increased CPU load and higher latency due to repeated full handshakes."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily observe the performance degradation without needing any special permissions or conditions beyond making HTTP requests.", "c": "Why C=N: No sensitive information is disclosed as a result of disabling ssl_session_tickets.", "i": "Why I=N: The configuration cannot be modified by an attacker due to lack of disclosure or exploitable vulnerabilities.", "a": "Why A=P: Availability is impacted because the server must perform full TLS handshakes for each connection, leading to increased latency and potential performance degradation.", "gel": "Why GEL=M: This misconfiguration can occur frequently in environments where security configurations are not properly reviewed or updated.", "grl": "Why GRL=H: There is extensive documentation available on how to configure Nginx correctly for TLS 1.3, making remediation straightforward."}}','2026-06-20T01:48:57.076Z','2026-06-20T03:54:49.332Z');
INSERT INTO misconfigurations VALUES('99ca918a-1052-4793-94a9-d1d3012d0435',2,'nginx','proxy_pass','http://127.0.0.1:8080','https://backend with restrictions','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','2.5.4','Not stripping sensitive headers like X-Powered-By and Server allows attackers to gather information about the backend infrastructure, enabling targeted attacks based on known vulnerabilities.','Add ''proxy_hide_header X-Powered-By;'' and ''proxy_hide_header Server;'' in the NGINX configuration to prevent disclosure of sensitive information.','value','always','','{"description": "The directive proxy_pass is used to forward client requests to another server. Using http://127.0.0.1:8080 exposes internal backend services directly without proper security measures like encryption or header stripping, making it vulnerable to information disclosure and targeted attacks.", "potential_impact": ["Expose sensitive headers such as X-Powered-By and Server", "Allow attackers to gather detailed information about the backend infrastructure", "Enable targeted attacks based on known vulnerabilities of exposed services"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a standard HTTP request to the Nginx server, which forwards it internally to http://127.0.0.1:8080 without stripping sensitive headers.", "result": "The attacker receives detailed information about the backend infrastructure and can use this data for targeted attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily exploit this misconfiguration by sending a standard HTTP request to trigger the exposure of sensitive headers.", "c": "Why C=P: The configuration allows an attacker to read and gather detailed information about the backend infrastructure, including version numbers and technologies used.", "i": "Why I=N: There is no direct impact on data or configuration modification through this misconfiguration alone.", "a": "Why A=N: Availability of services is not directly affected by this misconfiguration.", "gel": "Why GEL=M: This type of misconfiguration can be exploited frequently as it exposes sensitive information that attackers can use for targeted attacks.", "grl": "Why GRL=H: There are numerous resources and documentation available to remediate such misconfigurations, making the risk high."}}','2026-06-20T01:49:46.671Z','2026-06-20T03:57:02.361Z');
INSERT INTO misconfigurations VALUES('23333440-2ecf-4795-abad-270448009d49',2,'nginx','proxy_ssl_verify','','proxy_ssl_verify on;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.10','Without proxy_ssl_verify on, NGINX does not validate the upstream server''s TLS certificate. This is equivalent to a browser ignoring all certificate warnings, making the proxy-to-backend channel vulnerable to man-in-the-middle attacks within the internal network.','Add ''proxy_ssl_verify on;'' to location blocks that use proxy_pass. Also configure proxy_ssl_trusted_certificate and proxy_ssl_name.','absence','if_directive:proxy_pass','','{"description": "The directive proxy_ssl_verify is used to enable TLS certificate verification for proxied requests. Without this directive set to ''on'', Nginx does not validate the upstream server''s TLS certificate, making it vulnerable to man-in-the-middle attacks within the internal network.", "potential_impact": ["Expose sensitive data in transit", "Allow attackers to intercept and modify traffic between Nginx and backend servers", "Compromise integrity of communications by injecting malicious content"], "exploitation_scenario": {"prerequisites": ["An attacker must be positioned within the internal network to perform a man-in-the-middle attack", "The attacker needs to have some level of control over the network infrastructure or be able to inject traffic between Nginx and backend servers"], "example": "Attacker uses ARP spoofing to intercept traffic between Nginx and backend server, then modifies requests or responses in transit.", "result": "The attacker can read, modify, or inject data into the communication channel between Nginx and the backend server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be positioned within the internal network and have some level of control over the network infrastructure, which presents a moderate barrier.", "c": "Why C=P: Sensitive data in transit can be exposed and read by an attacker.", "i": "Why I=P: The integrity of communications can be compromised as attackers can modify or inject malicious content into traffic between Nginx and backend servers.", "a": "Why A=N: Availability is not directly affected, but the reliability of data transmission may be compromised due to tampering.", "gel": "Why GEL=L: While exploitation requires specific conditions within an internal network, it remains a relatively low-frequency event compared to external attacks.", "grl": "Why GRL=W: Remediation documentation is widely available and straightforward to implement."}}','2026-06-20T01:49:46.676Z','2026-06-20T03:59:24.344Z');
INSERT INTO misconfigurations VALUES('c3fff043-48f4-423b-b330-78d1227dc39f',2,'nginx','proxy_ssl_trusted_certificate','','proxy_ssl_trusted_certificate /etc/nginx/ssl/upstream_ca.crt;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.10','Without proxy_ssl_trusted_certificate, NGINX cannot verify the upstream server''s certificate against a trusted CA even when proxy_ssl_verify is on, leaving the mTLS chain incomplete.','Add ''proxy_ssl_trusted_certificate /path/to/ca.crt;'' to location blocks that use proxy_pass with upstream TLS.','absence','if_directive:proxy_pass','','{"description": "The directive proxy_ssl_trusted_certificate is used to specify the path to a file containing trusted CA certificates for verifying the SSL/TLS certificate of an upstream server. Without this directive set, Nginx cannot verify the identity of the upstream server even if proxy_ssl_verify is enabled, leading to potential man-in-the-middle attacks.", "potential_impact": ["Expose sensitive data over untrusted connections", "Allow attackers to intercept and modify traffic between Nginx and the backend server", "Compromise integrity of TLS communication"], "exploitation_scenario": {"prerequisites": ["An attacker must be able to perform a man-in-the-middle attack on the connection between Nginx and the upstream server.", "The attacker needs to have control over the network path where the traffic flows."], "example": "An attacker intercepts the SSL/TLS handshake between Nginx and an upstream server, presenting their own certificate. Since proxy_ssl_trusted_certificate is not set, Nginx does not verify the certificate against a trusted CA.", "result": "The attacker can successfully establish a TLS connection with Nginx, allowing them to intercept and modify all traffic between Nginx and the backend server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be positioned in the network path where they can perform a man-in-the-middle attack. This requires some level of control over the network, making it moderately difficult but not impossible.", "c": "Why C=P: The attacker can read and potentially modify sensitive data transmitted between Nginx and the backend server.", "i": "Why I=P: The attacker can inject malicious content into the communication stream, leading to potential data corruption or injection attacks.", "a": "Why A=N: Availability is not directly impacted as the service remains operational; however, it may be compromised through data tampering.", "gel": "Why GEL=L: While a man-in-the-middle attack requires specific conditions and skills, such attacks are relatively common in targeted scenarios where attackers have network control.", "grl": "Why GRL=W: There is extensive documentation available on how to properly configure proxy_ssl_trusted_certificate for securing TLS connections."}}','2026-06-20T01:49:46.678Z','2026-06-20T04:02:08.598Z');
INSERT INTO misconfigurations VALUES('0674b54f-adfd-469c-a17f-59c55d09f1e5',2,'nginx','proxy_ssl_name','','proxy_ssl_name your-upstream-hostname.com;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.10','Without proxy_ssl_name, NGINX does not verify that the upstream server''s certificate Subject Name matches the expected hostname, allowing certificate substitution attacks even with proxy_ssl_verify on.','Add ''proxy_ssl_name your-upstream-hostname.com;'' to location blocks that use proxy_pass. The value must match the upstream server''s hostname.','absence','if_directive:proxy_pass','','{"description": "The directive proxy_ssl_name is used to specify the expected hostname of the upstream server for SSL verification. Without this directive, Nginx does not verify that the upstream server''s certificate Subject Name matches the expected hostname, allowing potential man-in-the-middle attacks even if proxy_ssl_verify is enabled.", "potential_impact": ["Expose sensitive data over an insecure connection", "Allow attackers to intercept and modify traffic between Nginx and the backend server", "Enable unauthorized access to backend services through certificate substitution"], "exploitation_scenario": {"prerequisites": ["An attacker must be able to perform a man-in-the-middle attack on the network"], "example": "Attacker performs a DNS spoofing attack, redirecting traffic intended for your-upstream-hostname.com to an attacker-controlled server with a valid but incorrect certificate. Nginx forwards requests without verifying the hostname.", "result": "The attacker can intercept and modify all data exchanged between Nginx and the backend server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to perform a man-in-the-middle attack, which requires network-level access or control over DNS resolution. This is not trivial but also not extremely difficult for an experienced attacker.", "c": "Why C=P: The confidentiality of data exchanged between Nginx and the backend server can be compromised, leading to exposure of sensitive information.", "i": "Why I=P: An attacker can modify or inject malicious content into requests forwarded by Nginx, potentially altering application behavior or causing service disruptions.", "a": "Why A=N: Availability is not directly impacted as the service remains operational. However, data integrity and confidentiality are compromised.", "gel": "Why GEL=L: While certificate substitution attacks can be sophisticated, they occur with some frequency in environments where proper SSL verification is neglected.", "grl": "Why GRL=W: There is extensive documentation available on how to properly configure proxy_ssl_name for secure communication between Nginx and backend servers."}}','2026-06-20T01:49:46.680Z','2026-06-20T04:04:36.243Z');
INSERT INTO misconfigurations VALUES('632a46c4-a052-4b55-ac31-f764822e85a4',2,'nginx','add_header','','add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.8','Without the Strict-Transport-Security (HSTS) header, browsers are not instructed to enforce HTTPS. This leaves users vulnerable to protocol downgrade attacks and cookie hijacking on their first visit, before any HTTPS redirect has been applied.','Add ''add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;'' to the server block serving HTTPS.','absence','if_directive:ssl_certificate','Strict-Transport-Security','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.682Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('cd5a041a-dc20-485e-8938-96551fcb518a',2,'nginx','add_header','','add_header X-Content-Type-Options "nosniff" always;','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.3.1','Without X-Content-Type-Options: nosniff, browsers may perform MIME type sniffing and execute files as a different content type than declared. This enables drive-by download attacks and MIME confusion attacks where a text file is executed as a script.','Add ''add_header X-Content-Type-Options "nosniff" always;'' to the server block.','absence','always','X-Content-Type-Options','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.684Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('98d7b150-444b-43ae-b744-588d6a964190',2,'nginx','add_header','','add_header Content-Security-Policy "default-src ''self''; frame-ancestors ''self'';" always;','N','N','L','P','P','N',0.0,0.0,'L','W','[]','','5.3.2','Without a Content-Security-Policy header, browsers apply only the Same-Origin Policy, which does not prevent XSS attacks from loading external scripts or data exfiltration. CSP significantly reduces the XSS attack surface by whitelisting approved content sources.','Add a Content-Security-Policy header tailored to the application. Start with ''Content-Security-Policy-Report-Only'' to audit before enforcing. Minimum: default-src ''self''; frame-ancestors ''self''.','absence','always','Content-Security-Policy','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.685Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('afed1911-148f-4697-9520-814c7d5e2231',2,'nginx','add_header','','add_header Referrer-Policy "strict-origin-when-cross-origin" always;','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.3.3','Without an explicit Referrer-Policy, browsers fall back to their defaults which may send the full URL (including query parameters with session tokens or PII) to third-party sites as the Referer header.','Add ''add_header Referrer-Policy "strict-origin-when-cross-origin" always;'' to the server block.','absence','always','Referrer-Policy','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.687Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('1a38b798-dc0d-4879-9187-46ba3daec2a1',2,'nginx','ssl_protocols','','ssl_protocols TLSv1.2 TLSv1.3;','N','N','M','P','N','N',0.0,0.0,'L','W','[]','','4.1.4','Without an explicit ssl_protocols directive, Nginx uses the OpenSSL default which historically includes TLSv1.0 and TLSv1.1. Explicit configuration is required to exclude deprecated protocol versions.','Add ''ssl_protocols TLSv1.2 TLSv1.3;'' to the http block.','absence','if_directive:ssl_certificate','','{"description": "The ssl_protocols directive specifies which SSL/TLS protocol versions are allowed for secure connections. Without an explicit configuration, Nginx may default to using deprecated protocols like TLSv1.0 and TLSv1.1, exposing the server to vulnerabilities such as POODLE or BEAST attacks.", "potential_impact": ["Expose the server to known vulnerabilities in older TLS versions", "Allow attackers to perform downgrade attacks", "Reduce security posture by enabling insecure ciphers"], "exploitation_scenario": {"prerequisites": ["An attacker must be able to intercept or manipulate network traffic between clients and the Nginx server.", "The attacker needs knowledge of vulnerabilities associated with older TLS versions."], "example": "An attacker could use a man-in-the-middle attack to force a client to downgrade its connection from a secure protocol like TLSv1.2 to an insecure one such as TLSv1.0, exploiting known weaknesses in the latter.", "result": "The attacker can intercept and decrypt sensitive data transmitted between clients and the server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be positioned within the network to perform a man-in-the-middle attack or have knowledge of specific vulnerabilities in older TLS versions, which requires some level of expertise.", "c": "Why C=P: Confidentiality is partially compromised as an attacker can exploit weaknesses in deprecated TLS versions to intercept and decrypt sensitive data.", "i": "Why I=N: The misconfiguration does not directly allow for the modification of server-side files or configurations; however, it may indirectly lead to data leakage through vulnerabilities in older protocols.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration as services remain accessible. However, a successful attack could disrupt service if clients refuse connections due to detected security issues.", "gel": "Why GEL=L: While exploitation of deprecated TLS versions can occur, it typically requires specific conditions and knowledge, making widespread attacks less frequent.", "grl": "Why GRL=W: There is extensive documentation available on how to properly configure Nginx for secure TLS usage."}}','2026-06-20T01:49:46.689Z','2026-06-20T04:16:14.845Z');
INSERT INTO misconfigurations VALUES('e5ab88ed-96c2-47b0-af8b-0e419f14833c',2,'nginx','ssl_stapling','','ssl_stapling on; ssl_stapling_verify on;','N','N','M','P','N','N',0.0,0.0,'L','W','[]','','4.1.7','Without OCSP stapling, clients must perform live OCSP lookups to the CA to verify certificate validity. This leaks browsing activity to the CA, degrades performance, and may allow revocation checks to be suppressed if the OCSP responder is unavailable.','Add ''ssl_stapling on; ssl_stapling_verify on; resolver 8.8.8.8;'' to the server block.','absence','if_directive:ssl_certificate','','{"description": "The directive ''ssl_stapling'' is used to enable OCSP (Online Certificate Status Protocol) stapling in Nginx. Without it enabled (''ssl_stapling on; ssl_stapling_verify on;''), clients must perform their own OCSP checks, which can leak browsing activity and degrade performance.", "potential_impact": ["Leak user''s browsing activity to the CA", "Decrease website performance due to additional network requests for OCSP", "Allow revocation checks to be suppressed if the OCSP responder is unavailable"], "exploitation_scenario": {"prerequisites": ["An attacker must observe or manipulate traffic between client and server", "Client''s browser must perform an OCSP check"], "example": "Attacker monitors network traffic for OCSP requests from a client to the CA. Client sends HTTP request to Nginx, which does not have ssl_stapling enabled, forcing the client to contact the CA directly.", "result": "The attacker gains visibility into the user''s browsing activity and can potentially manipulate or suppress revocation checks."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be in a position to observe network traffic between the client and server, which requires some level of network access or control.", "c": "Why C=P: The CA can see the user''s browsing activity when OCSP checks are performed by clients directly.", "i": "Why I=N: There is no direct impact on data modification as ssl_stapling does not affect server-side configurations or data integrity.", "a": "Why A=N: Availability is impacted due to potential performance degradation and network delays caused by client-initiated OCSP requests.", "gel": "Why GEL=L: While exploitation requires specific conditions, the misconfiguration can be commonly observed in less security-aware environments.", "grl": "Why GRL=W: Remediation steps are well-documented and straightforward to implement."}}','2026-06-20T01:49:46.691Z','2026-06-20T04:18:40.679Z');
INSERT INTO misconfigurations VALUES('931d9794-b653-4993-81c4-db38c237f5b8',3,'ssh','PermitRootLogin','yes','no','N','N','L','P','C','N',8.5,8.5,'H','H','[]','','5.1.20','PermitRootLogin set to ''yes'' allows direct root login via SSH, enabling any attacker who can guess or brute-force a password to gain full system access without further steps.','Set ''PermitRootLogin no'' in the /etc/ssh/sshd_config file and restart the sshd service.','value','always','','{"description": "The PermitRootLogin directive controls whether root login is allowed via SSH. Setting it to ''yes'' permits direct root access, which significantly increases the risk of unauthorized system compromise.", "potential_impact": ["Compromise full system control", "Execute arbitrary commands with root privileges", "Gain persistent access through compromised credentials"], "exploitation_scenario": {"prerequisites": ["Knowledge of a valid user account", "Ability to perform brute-force or dictionary attacks"], "example": "An attacker uses an SSH client to attempt login as root with guessed passwords: ssh root@target_ip -p 22", "result": "If the password is correct, the attacker gains full system access."}, "metric_justifications": {"ac": "Why AC=L: PermitRootLogin set to ''yes'' allows any attacker who can guess or brute-force a root password to gain immediate and unrestricted access without additional steps.", "c": "Why C=P: Sensitive information such as system configuration files, logs, and user data may be read by the attacker once they have gained root access.", "i": "Why I=C: The attacker can modify critical system configurations, install backdoors, or alter sensitive files to maintain persistent control over the compromised host.", "a": "Why A=N: Availability is not directly impacted as the service remains operational; however, denial-of-service attacks may be executed by the attacker once root access is obtained.", "gel": "Why GEL=H: PermitRootLogin set to ''yes'' is a common misconfiguration that frequently leads to successful exploitation due to its direct impact on system security.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation, making it easy to understand the risks and apply corrections."}}','2026-06-20T17:39:32.624Z','2026-06-20T17:52:35.572Z');
INSERT INTO misconfigurations VALUES('762bd697-4ca9-42f8-8d28-16284fd5081a',3,'ssh','PermitEmptyPasswords','yes','no','N','N','L','N','C','P',8.5,8.5,'H','H','["CVE-2016-6210", "CVE-2018-15473"]','','5.1.19','Allowing empty passwords enables attackers to easily brute-force accounts with weak or empty passwords, leading to full account compromise and potential system access.','Set ''PermitEmptyPasswords no'' in the /etc/ssh/sshd_config file.','value','always','','{"description": "The PermitEmptyPasswords directive allows users to log in with an empty password if set to ''yes'', which is highly insecure. This misconfiguration enables attackers to easily brute-force accounts and gain unauthorized access.", "potential_impact": ["Compromise user accounts", "Gain full system access", "Install backdoors or malware"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can attempt to log in with an empty password and gain unauthorized access if the account is not protected by other measures.", "result": "The attacker successfully logs into a user account, potentially escalating privileges and compromising system integrity."}, "metric_justifications": {"ac": "Why AC=L: Allowing empty passwords makes it trivial for an attacker to brute-force accounts with weak or no password protection. No special preconditions are required beyond sending login attempts.", "c": "Why C=N: The misconfiguration does not directly disclose sensitive information but allows unauthorized access, which can lead to further data exposure.", "i": "Why I=C: Once an attacker gains access through a compromised account, they may modify system configurations or install malicious software.", "a": "Why A=P: Availability is affected as the attacker can disrupt services by installing malware or altering critical system files.", "gel": "Why GEL=H: PermitEmptyPasswords misconfigurations are frequently exploited due to their simplicity and effectiveness in compromising systems.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, making it easy for attackers to find instructions."}}','2026-06-20T17:40:23.534Z','2026-06-20T17:54:35.799Z');
INSERT INTO misconfigurations VALUES('96eb094d-eba2-48e3-9eb0-b347c3fa172e',3,'ssh','GSSAPIAuthentication','yes','no','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2016-0738", "CVE-2019-6114"]','','5.1.9','Enabling GSSAPIAuthentication exposes the system to potential attacks leveraging GSSAPI, allowing an attacker to exploit vulnerabilities in this protocol. While it does not directly lead to full system compromise, it increases the attack surface and can be exploited if the attacker has knowledge of specific GSSAPI weaknesses.','Set ''GSSAPIAuthentication no'' in /etc/ssh/sshd_config.d/*.conf or /etc/ssh/sshd_config.','value','always','','{"description": "Enabling GSSAPIAuthentication allows for authentication using GSSAPI mechanisms. Setting this directive to ''yes'' exposes the system to potential attacks leveraging vulnerabilities in GSSAPI, such as CVE-2016-0738 and CVE-2019-6114.", "potential_impact": ["Exploits vulnerabilities in GSSAPI mechanisms", "Increases attack surface by enabling an additional authentication method", "Allows attackers to perform unauthorized actions if they can exploit specific weaknesses"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a malicious request exploiting a known vulnerability in GSSAPI, such as CVE-2016-0738 or CVE-2019-6114.", "result": "The attacker gains unauthorized access to the system through compromised authentication mechanisms."}, "metric_justifications": {"ac": "Why AC=L: Enabling GSSAPIAuthentication with ''yes'' makes it easy for an attacker to exploit known vulnerabilities in GSSAPI without any special preconditions.", "c": "Why C=P: The attacker can potentially disclose sensitive information or gain unauthorized access to system resources.", "i": "Why I=N: While the attack surface is increased, direct modification of data or configuration is not a guaranteed outcome and depends on further exploitation steps.", "a": "Why A=N: Availability is not directly impacted by enabling GSSAPIAuthentication; however, successful exploitation could lead to service disruption if critical resources are compromised.", "gel": "Why GEL=M: Exploitation of GSSAPI vulnerabilities has been observed in the wild and can be targeted with specific knowledge of system configurations.", "grl": "Why GRL=H: Detailed documentation on how to remediate GSSAPI vulnerabilities is widely available, making it easier for administrators to address these issues."}}','2026-06-20T17:41:26.540Z','2026-06-20T17:56:55.857Z');
INSERT INTO misconfigurations VALUES('6318fc26-6467-4b19-acb0-12dc8b3b7ee5',3,'ssh','HostbasedAuthentication','yes','no','N','N','M','P','C','N',7.79999999999999982,7.29999999999999982,'L','H','[]','','5.1.10','Enabling HostbasedAuthentication allows authentication via .rhosts and /etc/hosts.equiv files, which can be exploited by attackers with write access to these files. This requires local or network position to modify the files — AC is Medium.','Set ''HostbasedAuthentication no'' in the sshd configuration file.','value','always','','{"description": "HostbasedAuthentication allows authentication based on .rhosts and /etc/hosts.equiv files. Setting this to ''yes'' is dangerous because it permits unauthorized access if an attacker can modify these files.", "potential_impact": ["Compromise user accounts", "Gain unauthorized system access", "Deploy malicious code"], "exploitation_scenario": {"prerequisites": ["Write access to .rhosts or /etc/hosts.equiv files", "Network position to modify the files"], "example": "An attacker modifies a user''s .rhosts file in their home directory to include an entry for a compromised host, allowing them to authenticate without a password.", "result": "The attacker gains unauthorized access to the system as the targeted user."}, "metric_justifications": {"ac": "Why AC=M: Enabling HostbasedAuthentication requires an attacker to have write access to .rhosts or /etc/hosts.equiv files, which is a moderate barrier.", "c": "Why C=P: The attacker can read sensitive information and gain unauthorized access to user accounts.", "i": "Why I=C: The attacker can modify system configurations and deploy malicious code on the compromised host.", "a": "Why A=N: Availability is not directly affected, but the system becomes vulnerable to further attacks.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to other vulnerabilities due to its specific requirements.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation."}}','2026-06-20T17:42:12.104Z','2026-06-20T17:58:54.229Z');
INSERT INTO misconfigurations VALUES('cd39e793-cef1-494e-af9b-f7fcd1647745',3,'ssh','IgnoreRhosts','no','yes','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','5.1.11','Setting IgnoreRhosts to ''no'' allows .rhosts and .shosts files to be used for authentication, which can lead to unauthorized access if these files exist on the system. Exploitation requires an attacker to have local or network access to place such files.','Set ''IgnoreRhosts yes'' in /etc/ssh/sshd_config.d/*.conf.','value','always','','{"description": "The IgnoreRhosts directive in OpenSSH Server is set to ''no'', which allows .rhosts and .shosts files to be used for authentication. This configuration can lead to unauthorized access if these files exist on the system, as they may contain insecurely configured host-based authentication.", "potential_impact": ["Allows an attacker to gain unauthorized access by placing malicious entries in .rhosts or .shosts files", "Enables a compromised user account to escalate privileges through improperly secured host-based authentication mechanisms", "Increases the attack surface for lateral movement within the network"], "exploitation_scenario": {"prerequisites": ["An attacker must have local or remote write access to place .rhosts or .shosts files on the target system", "The attacker needs knowledge of existing host-based authentication configurations"], "example": "An attacker places a malicious entry in the user''s home directory .rhosts file, such as ''user otherhost'', allowing them to authenticate without a password from that specific host.", "result": "The attacker gains unauthorized access to the system using the compromised host-based authentication mechanism."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires an attacker to have local or network write access, which presents a moderate barrier compared to trivially exploitable configurations.", "c": "Why C=P: The configuration allows for the disclosure of sensitive information through unauthorized access gained via compromised host-based authentication files.", "i": "Why I=P: An attacker can modify system configurations and data by leveraging improperly secured .rhosts or .shosts files to gain elevated privileges.", "a": "Why A=N: Availability is not directly impacted, but the system becomes vulnerable to further attacks due to unauthorized access.", "gel": "Why GEL=L: While exploitation requires specific conditions, it remains a common misconfiguration that can be easily overlooked in security audits.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation of this configuration issue."}}','2026-06-20T17:43:02.914Z','2026-06-20T18:01:23.021Z');
INSERT INTO misconfigurations VALUES('00a62236-5f74-402e-a340-016f5b9d4293',3,'ssh','PermitUserEnvironment','yes','no','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','5.1.21','Enabling PermitUserEnvironment allows users to set environment variables, potentially bypassing security controls and executing trojaned programs. However, exploitation requires the attacker to have SSH access, making AC Medium.','Set ''PermitUserEnvironment no'' in /etc/ssh/sshd_config or a configuration file included by it.','value','always','','{"description": "The PermitUserEnvironment directive allows users to set environment variables when they log in via SSH. Setting this value to ''yes'' is dangerous because it can enable attackers with SSH access to bypass security controls and execute malicious programs.", "potential_impact": ["Bypasses security controls", "Executes trojaned programs", "Modifies system configurations"], "exploitation_scenario": {"prerequisites": ["SSH access is required", "User has the ability to modify environment variables"], "example": "An attacker modifies their .ssh/environment or ~/.ssh/environment file to set malicious environment variables.", "result": "The system executes trojaned programs and potentially exposes sensitive information."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires SSH access, which is a moderate barrier as it necessitates authentication credentials or other means of gaining entry to the server.", "c": "Why C=P: Sensitive information can be disclosed through environment variables that are set by users with malicious intent.", "i": "Why I=P: The attacker can modify system configurations and execute arbitrary code via trojaned programs.", "a": "Why A=N: Availability is not directly impacted, but the integrity of the system may be compromised leading to indirect availability issues.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited as it requires specific conditions such as SSH access and user permissions.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official documentation and security guidelines."}}','2026-06-20T17:43:47.500Z','2026-06-20T18:03:47.795Z');
INSERT INTO misconfigurations VALUES('f2be14ed-84a3-4093-ba31-7315be358ea2',3,'ssh','UsePAM','no','yes','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','5.1.22','Disabling UsePAM prevents PAM account and session processing, which can lead to degraded security features such as restricted access based on IP or time. However, this does not directly expose sensitive information or allow for immediate exploitation by remote attackers.','Set ''UsePAM yes'' in the sshd configuration file to enable proper PAM authentication and account/session processing.','value','always','','{"description": "The UsePAM directive enables PAM authentication and account/session processing for OpenSSH. Disabling it (setting to ''no'') can lead to a lack of security features such as IP or time-based access restrictions, which are crucial for securing SSH access.", "potential_impact": ["Decreases the ability to enforce strict access controls based on PAM policies", "Prevents use of advanced authentication methods and session management provided by PAM modules", "Reduces overall security posture due to missing critical security features"], "exploitation_scenario": {"prerequisites": ["An attacker must have knowledge of the disabled UsePAM configuration", "The attacker needs to exploit other vulnerabilities or gain initial access to the system"], "example": "A misconfigured SSH server with UsePAM set to ''no'' allows an attacker who has gained low-privilege access to bypass IP-based restrictions and time-of-day limitations that would normally be enforced by PAM.", "result": "The attacker can establish a persistent, unauthorized SSH session despite the presence of other security measures."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs additional knowledge about the system''s configuration and may require initial low-level access to exploit this misconfiguration effectively.", "c": "Why C=N: No sensitive information is directly exposed by disabling UsePAM, but security features are weakened.", "i": "Why I=N: The configuration itself cannot be modified without administrative privileges, but the system''s security posture can be exploited indirectly.", "a": "Why A=P: Availability may be affected if an attacker uses this misconfiguration to establish a persistent unauthorized session or escalate privileges.", "gel": "Why GEL=L: While not trivially exploitable by any attacker, the impact is significant for systems where PAM-based security measures are critical.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure UsePAM in OpenSSH."}}','2026-06-20T17:44:37.622Z','2026-06-20T18:06:50.378Z');
INSERT INTO misconfigurations VALUES('b8bb484b-e312-48a5-8283-0cba4e46f323',3,'ssh','LogLevel','QUIET','VERBOSE','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.14','Setting LogLevel to QUIET disables most logging, making it difficult to detect and respond to security incidents. This can lead to gradual degradation of system monitoring capabilities.','Set ''LogLevel VERBOSE'' or ''LogLevel INFO'' in the sshd_config file.','value','always','','{"description": "The LogLevel directive in OpenSSH Server controls the verbosity of logging. Setting LogLevel to QUIET disables most logging, which can severely hinder incident detection and response efforts.", "potential_impact": ["Disable critical security event logging", "Compromise forensic capabilities during an attack", "Reduce visibility into unauthorized access attempts"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by simply connecting to the SSH server and performing malicious actions without being logged. The lack of logging makes it difficult to trace back any suspicious activities.", "result": "The attacker''s actions go undetected due to the absence of logs, allowing them to potentially escalate privileges or exfiltrate data."}, "metric_justifications": {"ac": "Why AC=L: Setting LogLevel to QUIET is trivially exploitable by any user who connects to the SSH server. No special conditions are required beyond initiating a connection.", "c": "Why C=N: There is no direct confidentiality impact as sensitive information is not disclosed through logging.", "i": "Why I=N: The misconfiguration does not allow for immediate modification of system data or configuration files.", "a": "Why A=P: Availability can be indirectly affected due to the inability to detect and respond to security incidents in a timely manner.", "gel": "Why GEL=M: Misconfigurations like this are moderately common as administrators may overlook the importance of logging verbosity.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure LogLevel for OpenSSH Server."}}','2026-06-20T17:45:16.577Z','2026-06-20T18:09:06.033Z');
INSERT INTO misconfigurations VALUES('94495d9b-f3ff-4d0c-9e04-b3d449b2cc0f',3,'ssh','MaxAuthTries','6','4','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.16','Increasing MaxAuthTries to 6 allows more login attempts, increasing the risk of successful brute force attacks. This can lead to gradual degradation of system security through unauthorized access.','Set ''MaxAuthTries 4'' in /etc/ssh/sshd_config.d/*.conf or directly in /etc/ssh/sshd_config.','value','always','','{"description": "The MaxAuthTries directive limits the number of authentication attempts before disconnecting the client. Setting it to 6 increases the risk of successful brute force attacks by allowing more login attempts.", "potential_impact": ["Increases likelihood of unauthorized access through brute force", "Exposes system to prolonged attack vectors", "Reduces security posture over time due to repeated failed attempts"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker uses a tool like Hydra or Medusa to repeatedly attempt login with different credentials. The SSH server allows up to 6 incorrect password attempts before disconnecting.", "result": "The attacker gains unauthorized access if they discover the correct credentials within the allowed number of attempts."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily perform brute force attacks by sending multiple login requests, each attempt being simple and requiring no special permissions.", "c": "Why C=N: No sensitive information is disclosed beyond the fact that authentication attempts are allowed up to 6 times.", "i": "Why I=N: The configuration does not allow for modification of system data or settings through brute force attacks alone.", "a": "Why A=P: Availability can be impacted as repeated login attempts may cause denial-of-service conditions by consuming server resources.", "gel": "Why GEL=M: This type of misconfiguration is frequently exploited due to the ease and effectiveness of automated brute force tools.", "grl": "Why GRL=H: There are numerous guides and documentation available on how to properly secure SSH servers, including setting appropriate MaxAuthTries values."}}','2026-06-20T17:46:04.399Z','2026-06-20T18:11:18.781Z');
INSERT INTO misconfigurations VALUES('836f8499-68b4-41d4-a270-e28ccf2e614d',3,'ssh','MaxSessions','20','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.18','Setting MaxSessions to a high value like ''20'' can lead to resource exhaustion and degrade the availability of SSH services, making it easier for attackers to perform DoS attacks.','Set ''MaxSessions 10'' or lower in /etc/ssh/sshd_config.d/*.conf file.','value','always','','{"description": "The MaxSessions directive limits the maximum number of concurrent sessions per connection. Setting it to ''20'' can lead to resource exhaustion and degrade SSH service availability, making DoS attacks more feasible.", "potential_impact": ["Degradation of SSH service availability", "Resource exhaustion on the server", "Increased susceptibility to DoS attacks"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can initiate multiple simultaneous connections, each with a high number of sessions (up to 20), overwhelming the SSH service and causing resource depletion.", "result": "The SSH server becomes unresponsive or unavailable for legitimate users."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily initiate multiple simultaneous connections with a high number of sessions, exploiting the MaxSessions setting without needing special privileges or conditions beyond sending requests.", "c": "Why C=N: No sensitive information is disclosed directly by this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified through this vulnerability alone.", "a": "Why A=P: Availability of the SSH service can be significantly impacted due to resource exhaustion and DoS attacks.", "gel": "Why GEL=M: This type of misconfiguration is moderately likely to be exploited in environments where attackers seek to disrupt services.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official documentation and security guidelines."}}','2026-06-20T17:46:48.854Z','2026-06-20T18:13:35.745Z');
INSERT INTO misconfigurations VALUES('a8660d73-2e3e-46cf-ab1c-49e42dbd51d1',3,'ssh','LoginGraceTime','120','60','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.13','A longer LoginGraceTime increases the window for brute force attacks and unauthorized access attempts, potentially leading to service degradation due to excessive unauthenticated connections.','Set ''LoginGraceTime 60'' in /etc/ssh/sshd_config.d/*.conf or directly in /etc/ssh/sshd_config.','value','always','','{"description": "The LoginGraceTime directive sets the time limit for users to authenticate after attempting to log in via SSH. A value of 120 seconds increases the window during which brute force attacks can occur, making it easier for attackers to attempt multiple login combinations without being disconnected.", "potential_impact": ["Increases the likelihood of successful brute-force attacks due to extended authentication time", "Leads to service degradation as more unauthenticated connections are maintained longer", "Potentially exposes sensitive information during prolonged connection attempts"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker uses an automated tool like Hydra or Medusa to perform SSH login brute force attacks, taking advantage of the extended grace period to attempt numerous password guesses.", "result": "The attacker successfully gains unauthorized access after multiple attempts within the 120-second window."}, "metric_justifications": {"ac": "Why AC=L: The ease with which an attacker can exploit a longer LoginGraceTime is low, as it only requires sending repeated login requests without any additional technical barriers.", "c": "Why C=N: No sensitive information is disclosed beyond what would normally be exposed during a failed SSH authentication attempt.", "i": "Why I=N: The configuration itself cannot be modified directly through this attack vector; however, the system''s availability can be impacted.", "a": "Why A=P: Availability is affected as the server may become unresponsive due to excessive connection attempts and prolonged grace periods for failed logins.", "gel": "Why GEL=M: This type of misconfiguration is frequently exploited by attackers looking to gain unauthorized access through brute force methods.", "grl": "Why GRL=H: Remediation documentation is widely available, making it straightforward to correct the LoginGraceTime setting."}}','2026-06-20T17:47:39.311Z','2026-06-20T18:17:15.273Z');
INSERT INTO misconfigurations VALUES('bcb40611-ca1e-4d0e-90a4-ed88b0372118',3,'ssh','Ciphers','3des-cbc','aes256-ctr,aes192-ctr,aes128-ctr','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2023-48795"]','','5.1.6','Using the weak cipher ''3des-cbc'' can allow attackers to exploit known vulnerabilities in this encryption algorithm, leading to potential data compromise and unauthorized access.','Remove ''3des-cbc'' from the list of ciphers and ensure that only strong ciphers such as chacha20-poly1305@openssh.com are used.','value','always','','{"description": "The Ciphers directive specifies the encryption algorithms used for SSH connections. Using ''3des-cbc'' is dangerous because it is known to be vulnerable to various cryptographic attacks that can lead to data compromise.", "potential_impact": ["Compromise sensitive information transmitted over the network", "Allow attackers to decrypt intercepted traffic", "Enable unauthorized access to systems"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can exploit a known vulnerability in 3des-cbc by intercepting and analyzing encrypted SSH traffic.", "result": "The attacker gains the ability to decrypt sensitive data transmitted over the compromised connection."}, "metric_justifications": {"ac": "Why AC=L: An attacker with access to network traffic can easily exploit vulnerabilities in ''3des-cbc'' without any special preconditions, making it trivial.", "c": "Why C=P: The confidentiality of data transmitted over the SSH connection is compromised as attackers can decrypt intercepted communications.", "i": "Why I=N: There are no known mechanisms for an attacker to modify or inject data into the encrypted stream using ''3des-cbc'' alone.", "a": "Why A=N: Availability is not directly impacted by the use of ''3des-cbc''; however, successful exploitation can lead to denial-of-service if legitimate users cannot authenticate due to compromised credentials.", "gel": "Why GEL=M: Misconfigurations involving weak ciphers like ''3des-cbc'' are frequently exploited in real-world scenarios due to their known vulnerabilities.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to remediate the use of weak ciphers, making it straightforward for security professionals to address this issue."}}','2026-06-20T17:48:35.396Z','2026-06-20T18:20:46.064Z');
INSERT INTO misconfigurations VALUES('191a249a-da35-41c6-8459-22177f6f93a1',3,'ssh','MACs','hmac-md5','hmac-sha2-256,hmac-sha2-512','N','N','M','P','P','N',5.79999999999999982,5.79999999999999982,'H','H','["CVE-2023-48795"]','','5.1.15','Using weak MAC algorithms like hmac-md5 increases the risk of SSH downgrade attacks, allowing an attacker with a MITM position to decrypt the SSH tunnel and capture credentials. This requires specific network conditions but is actively exploited.','Remove ''hmac-md5'' from the list of allowed MACs in /etc/ssh/sshd_config.d/*.conf and ensure only strong algorithms are used.','value','always','','{"description": "The MACs directive specifies message authentication codes used to ensure data integrity and authenticity in SSH sessions. Using hmac-md5 is dangerous because it is a weak algorithm that can be exploited by attackers to perform downgrade attacks, compromising the security of SSH communications.", "potential_impact": ["Decrypt SSH tunnel traffic", "Capture credentials during login attempts", "Perform man-in-the-middle (MITM) attacks"], "exploitation_scenario": {"prerequisites": ["Attacker must be in a position to intercept network traffic between the client and server", "Client and server must negotiate hmac-md5 as an acceptable MAC algorithm"], "example": "An attacker can use tools like Wireshark or custom scripts to monitor SSH sessions and exploit weak MAC algorithms. For instance, by capturing and analyzing packets during a session setup, they could identify the use of hmac-md5 and attempt to downgrade the connection.", "result": "The attacker successfully decrypts the SSH tunnel traffic, allowing them to capture sensitive information such as login credentials."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs a specific network position to intercept and manipulate SSH sessions. This moderate barrier makes it less trivial than low but not as complex as high.", "c": "Why C=P: The confidentiality of sensitive data, such as login credentials, is compromised due to the ability to decrypt intercepted traffic.", "i": "Why I=P: While integrity may be affected by the attacker''s ability to manipulate sessions, there are no direct modifications to system configurations or data.", "a": "Why A=N: Availability is not directly impacted; however, successful exploitation can lead to denial of service if legitimate users cannot authenticate due to compromised credentials.", "gel": "Why GEL=H: Weak MAC algorithms like hmac-md5 are frequently targeted and exploited in real-world scenarios, making this a high-exploitation likelihood issue.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate weak MAC configurations, including detailed guides and best practices."}}','2026-06-20T17:49:32.551Z','2026-06-20T18:24:30.079Z');
INSERT INTO misconfigurations VALUES('6923d461-0ad0-4df2-aec0-efda9f35784f',3,'ssh','ClientAliveInterval','','ClientAliveInterval 15','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.7','Without ClientAliveInterval, sshd never probes idle clients, so a session whose network connection has dropped can remain open and consume resources or be hijacked from an unattended terminal.','Set ''ClientAliveInterval 15'' (with ClientAliveCountMax 3).','absence','always','','{"description": "The ClientAliveInterval directive in OpenSSH Server specifies how often the server sends a null packet to clients to check if they are still connected. Without setting this value (i.e., leaving it as default or unset), an idle SSH session can remain open indefinitely, potentially leading to resource consumption and security risks.", "potential_impact": ["Consumes unnecessary system resources by maintaining idle connections", "Allows unauthorized access from hijacked terminals if the user leaves their terminal unattended", "Increases risk of data leakage or command injection through compromised sessions"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit an open, idle SSH session by gaining physical access to a terminal where an authenticated user has left the system unattended. The attacker then uses this opportunity to hijack the session.", "result": "The attacker gains unauthorized access to the system through the compromised SSH session."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit an idle SSH session by simply gaining physical or network access to a terminal where an unattended, authenticated user''s session is open. No special preconditions are required.", "c": "Why C=P: The attacker can potentially read sensitive data or execute commands on the system through the hijacked SSH session.", "i": "Why I=N: There is no direct modification of data or configuration possible through this misconfiguration alone, but indirect modifications could occur via command execution in the hijacked session.", "a": "Why A=N: The availability impact is primarily due to resource consumption from idle sessions and potential disruption caused by unauthorized access.", "gel": "Why GEL=L: This type of misconfiguration is common and frequently exploited when not properly managed, especially in environments with lax security practices or unattended terminals.", "grl": "Why GRL=W: There are numerous resources available for remediation, including official documentation and best practice guides from the OpenSSH project."}}','2026-06-20T17:49:32.554Z','2026-06-20T18:27:53.653Z');
INSERT INTO misconfigurations VALUES('64a96c46-4e6b-4215-a413-55221af75b2d',3,'ssh','ClientAliveCountMax','','ClientAliveCountMax 3','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.7','Without ClientAliveCountMax, sshd does not bound how many missed keepalive probes are tolerated, so unresponsive sessions are not terminated, leaving idle authenticated channels open.','Set ''ClientAliveCountMax 3'' (with ClientAliveInterval 15).','absence','always','','{"description": "The ClientAliveCountMax directive sets the maximum number of client keepalive probe failures before an idle SSH session is terminated. Without this setting (i.e., when it''s not configured), unresponsive sessions remain open indefinitely, allowing authenticated users to maintain persistent access even if their connection drops or becomes inactive.", "potential_impact": ["Allows unauthorized persistence in the network by maintaining idle SSH connections", "Enables attackers to exploit idle sessions for lateral movement and reconnaissance", "Increases risk of resource exhaustion on the server due to excessive open connections"], "exploitation_scenario": {"prerequisites": ["Establish an authenticated SSH session", "Ensure no ClientAliveCountMax is set"], "example": "ssh user@host -N -T & (to establish a background idle connection)", "result": "An attacker can maintain an open, unmonitored SSH session indefinitely, allowing them to re-establish access without needing credentials again."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply establishing and maintaining an idle SSH connection. No special preconditions are required beyond having authenticated access.", "c": "Why C=P: The impact is primarily on the server''s resource utilization, but no specific information disclosure occurs directly from this misconfiguration alone.", "i": "Why I=N: There is no direct modification of data or configuration possible through this vulnerability; it merely extends session persistence.", "a": "Why A=N: Availability can be indirectly affected due to potential resource exhaustion from excessive idle connections, but the server remains operational.", "gel": "Why GEL=L: This type of misconfiguration is common and easily exploitable by attackers once they have initial access, making it a frequent target in opportunistic attacks.", "grl": "Why GRL=W: Remediation documentation for setting ClientAliveCountMax is widely available and straightforward to implement."}}','2026-06-20T17:49:32.556Z','2026-06-20T18:32:34.161Z');
INSERT INTO misconfigurations VALUES('d6a6f9c8-4fb7-4d40-9879-112fc53cdff6',3,'ssh','Banner','','Banner /etc/issue.net','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.5','Without a Banner, sshd presents no legal/authorised-use warning before authentication, weakening the deterrent and legal posture against unauthorised access.','Set ''Banner /etc/issue.net'' and populate the banner file.','absence','always','','{"description": "The Banner directive in OpenSSH Server is used to display a message before authentication occurs. Without setting this directive to ''Banner /etc/issue.net'', there is no legal or authorized-use warning presented to users, which can weaken deterrence against unauthorized access.", "potential_impact": ["Exposes the system to potential legal and reputational risks due to lack of clear usage policies", "Reduces the effectiveness of legal warnings in discouraging malicious activities", "Decreases user awareness about proper use and security measures"], "exploitation_scenario": {"prerequisites": [], "example": "A user connects to the SSH server using a standard SSH client. Upon connection, no banner message is displayed.", "result": "The user does not see any legal or authorized-use warning before attempting authentication."}, "metric_justifications": {"ac": "AC=L: Displaying a banner upon SSH login requires no special conditions beyond connecting to the server; it is trivially easy for an attacker to observe.", "c": "C=P: No sensitive information is disclosed, but the lack of a warning message can lead to misuse or unauthorized access.", "i": "I=N: There is no direct impact on system configuration or data modification through this misconfiguration alone.", "a": "A=N: Availability is not directly impacted by the absence of a banner; however, it indirectly affects security posture and user behavior.", "gel": "GEL=L: This type of misconfiguration is common and frequently exploited due to its simplicity in detection and lack of deterrent effect.", "grl": "GRL=W: Remediation steps are well-documented and straightforward, requiring only the addition of a banner file and configuration directive."}}','2026-06-20T17:49:32.559Z','2026-06-20T18:35:27.315Z');
INSERT INTO misconfigurations VALUES('8190b181-6674-4881-a6c6-838ace975ed9',3,'ssh','DisableForwarding','','DisableForwarding yes','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.8','Without DisableForwarding, sshd permits TCP/X11/agent forwarding by default, which can be abused to pivot through the host or tunnel traffic past network controls.','Set ''DisableForwarding yes'' unless forwarding is required.','absence','always','','{"description": "The DisableForwarding directive in OpenSSH Server prevents users from forwarding TCP connections, X11 sessions, and SSH agent connections. Without ''DisableForwarding yes'', an attacker can exploit these features to pivot through the host or tunnel traffic past network controls.", "potential_impact": ["Abuse TCP forwarding to exfiltrate data", "Establish a reverse shell for persistent access", "Bypass network security measures by tunneling traffic"], "exploitation_scenario": {"prerequisites": ["An attacker with SSH login credentials"], "example": "A user logs in and runs ''ssh -R 0:localhost:22 user@target'' to set up a reverse SSH tunnel.", "result": "The attacker can now use the compromised host as an intermediary to access other internal systems or bypass network restrictions."}, "metric_justifications": {"ac": "Why AC=L: An attacker with valid credentials can easily exploit TCP forwarding without any additional steps, making it trivially exploitable.", "c": "Why C=P: The attacker can potentially exfiltrate sensitive data through the forwarded connections.", "i": "Why I=N: While the configuration itself cannot be modified directly via this vulnerability, the impact is on network and system access rather than direct modification of files or settings.", "a": "Why A=N: Availability is not directly impacted as the service continues to function normally; however, availability of other systems through pivoting can be compromised.", "gel": "Why GEL=L: This type of misconfiguration is frequently exploited in real-world scenarios due to its simplicity and effectiveness.", "grl": "Why GRL=W: There are numerous resources available for remediation including official documentation and security guidelines."}}','2026-06-20T17:49:32.561Z','2026-06-20T18:38:20.149Z');
INSERT INTO misconfigurations VALUES('c647122b-2e35-460f-a419-8b238dac5d9b',4,'mysql','ssl_cipher','*','ECDHE-ECDSA-AES128-GCM-SHA256','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','','2.10','Module enabled unnecessarily.','Disable this module.','value','always','','{"description": "The ssl_cipher directive specifies which SSL/TLS ciphers are allowed for encrypted connections. Setting it to ''*'' allows all available ciphers, including weak and deprecated ones, making the connection vulnerable to various attacks.", "potential_impact": ["Expose the server to downgrade attacks where weaker ciphers can be forced", "Enable interception of data by attackers using known vulnerabilities in older ciphers", "Reduce overall security posture due to lack of cipher suite control"], "exploitation_scenario": {"prerequisites": ["An attacker with network access to intercept traffic"], "example": "Attacker sends a request to the server specifying an insecure cipher like RC4-SHA and forces the connection to use it.", "result": "The encrypted communication is vulnerable, allowing interception and decryption of sensitive data."}, "metric_justifications": {"ac": "AC=L: An attacker can easily exploit this misconfiguration by simply forcing a weak cipher during the SSL/TLS handshake without needing any special privileges or additional preconditions.", "c": "C=P: The exposure allows attackers to read and potentially decrypt sensitive data transmitted over the connection.", "i": "I=N: While the server''s configuration can be modified, there is no direct impact on modifying data through this misconfiguration alone.", "a": "A=N: Availability of services is not directly impacted by this misconfiguration; however, it may indirectly affect service integrity if sensitive data is compromised.", "gel": "GEL=L: This type of misconfiguration is frequently exploited due to the ease with which attackers can force weak ciphers and intercept communications.", "grl": "GRL=H: There are extensive resources available for remediation, including detailed documentation on configuring secure cipher suites."}}','2026-06-21T23:27:20.271Z','2026-06-22T00:38:30.641Z');
INSERT INTO misconfigurations VALUES('0af46c3f-f419-4aa9-aa8d-176eb4cd28be',4,'mysql','plugin-load','','validate_password.so','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','2.6','Not loading the validate_password plugin allows users to set weak passwords, potentially leading to database compromise through brute-force or guessing attacks. However, exploitation requires an attacker to have access to the system where they can modify password policies.','Ensure ''plugin-load=validate_password.so'' is present in my.cnf and configure global validate_password settings as per organizational policy.','value','always','','{"description": "The ''plugin-load'' directive specifies which plugins are loaded at MySQL startup. Not loading the validate_password plugin allows users to set weak passwords, potentially leading to database compromise through brute-force or guessing attacks.", "potential_impact": ["Allows attackers to exploit weak password policies", "Increases risk of unauthorized access via compromised credentials", "Reduces overall security posture by enabling insecure practices"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the MySQL configuration files or the ability to modify server settings", "The attacker needs knowledge of how to exploit weak password policies"], "example": "A malicious user modifies the my.cnf file to include ''validate_password=off'' and restarts the MySQL service, disabling the validate_password plugin.", "result": "The attacker can now create a new database account with a very weak password, such as ''password123'', making it easy for them to gain unauthorized access."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires write access to the MySQL configuration files or server settings, which is not trivial but still feasible with sufficient privileges.", "c": "Why C=P: No sensitive information is directly disclosed; however, the attacker can exploit weak credentials to gain unauthorized access.", "i": "Why I=N: The misconfiguration does not allow for direct data modification without first compromising a user account using weak passwords.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration, but compromised accounts could be used in denial-of-service attacks or other disruptive activities.", "gel": "Why GEL=L: While the impact can be severe, exploitation typically requires specific conditions to be met and is less frequent than low-hanging fruit vulnerabilities.", "grl": "Why GRL=H: There are numerous resources available for understanding and mitigating this type of misconfiguration, including official MySQL documentation."}}','2026-06-21T23:30:34.241Z','2026-06-22T00:43:20.986Z');
INSERT INTO misconfigurations VALUES('d4d82ca8-dbc8-4d17-a3c7-78f9c8ea6a8d',4,'mysql','block_encryption_mode','aes-128-ecb','aes-256-cbc','N','N','M','P','P','N',5.79999999999999982,5.79999999999999982,'H','H','["CVE-2016-8619", "CVE-2017-1309"]','','2.7','Using ''aes-128-ecb'' for encryption is highly insecure due to its susceptibility to known plaintext attacks and lack of diffusion. While an attacker needs specific preconditions (such as access to encrypted data), the misconfiguration significantly increases the risk of data compromise.','Set ''block_encryption_mode=aes-256-cbc'' in /etc/my.cnf for enhanced security.','value','always','','{"description": "The ''block_encryption_mode'' directive in MySQL determines the encryption mode used for data at rest. Using ''aes-128-ecb'' is highly insecure due to its susceptibility to known plaintext attacks and lack of diffusion, making it easier for attackers to decrypt sensitive information.", "potential_impact": ["Disclose sensitive data stored in encrypted tables", "Enable unauthorized access to database contents", "Compromise the confidentiality of user credentials"], "exploitation_scenario": {"prerequisites": ["Access to encrypted MySQL data files or backups", "Knowledge of the encryption key used by MySQL"], "example": "An attacker with access to a MySQL backup file can use known plaintext attacks to decrypt sensitive information stored in tables using aes-128-ecb.", "result": "The attacker gains unauthorized access to encrypted data, compromising confidentiality and integrity."}, "metric_justifications": {"ac": "Medium: An attacker needs specific preconditions such as access to encrypted MySQL data files or backups, making it moderately difficult but not impossible for an attacker to exploit this misconfiguration.", "c": "Partial: The configuration allows attackers to read and decrypt sensitive information stored in the database.", "i": "Partial: While the encryption mode does not directly allow modification of data, the exposure of decrypted data can lead to further attacks that modify or corrupt the database.", "a": "None: There is no direct impact on availability; however, compromised confidentiality may indirectly affect system integrity and availability through secondary attacks.", "gel": "High: Known plaintext attacks against aes-128-ecb are well-documented and frequently exploited in real-world scenarios.", "grl": "High: Extensive documentation exists for understanding the risks associated with using weak encryption modes like aes-128-ecb."}}','2026-06-21T23:34:01.743Z','2026-06-22T00:48:12.037Z');
INSERT INTO misconfigurations VALUES('de446755-ee1a-4d2d-a82f-7912ab005f5b',4,'mysql','bind_address','*','192.0.2.24','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','2.9','Setting bind_address to ''*'' allows MySQL to accept connections from any IP address, potentially exposing the database to unauthorized access and attacks from remote unauthenticated attackers.','Set ''bind_address'' to a specific IPv4 or IPv6 address in the [mysqld] section of /etc/my.cnf.','value','always','','{"description": "The bind_address directive specifies which IP address MySQL listens on for incoming connections. Setting it to ''*'' allows MySQL to accept connections from any IP address, potentially exposing the database to unauthorized access and attacks from remote unauthenticated attackers.", "potential_impact": ["Expose the database to unauthorized access", "Allow remote attackers to exploit vulnerabilities in MySQL", "Enable data exfiltration or modification by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can connect to the MySQL server using a standard SQL client and attempt to log in with default credentials or through brute force attacks.", "result": "The attacker gains unauthorized access to the database, potentially allowing them to read sensitive data, modify records, or execute arbitrary commands."}, "metric_justifications": {"ac": "Why AC=L: Setting bind_address to ''*'' makes it trivial for any unauthenticated attacker to connect and attempt exploitation with a standard SQL client.", "c": "Why C=P: The exposure allows attackers to read sensitive data stored in the database, such as user credentials or financial information.", "i": "Why I=N: While the configuration does not inherently allow modification of all data, it enables unauthorized access which can be leveraged for further attacks that modify data.", "a": "Why A=N: The availability of the service is not directly impacted by this misconfiguration; however, successful exploitation could lead to denial-of-service conditions if the attacker disrupts database operations.", "gel": "Why GEL=M: Misconfigurations like exposing MySQL to all IP addresses are common and frequently exploited in automated attacks.", "grl": "Why GRL=H: There is extensive documentation available on how to properly secure MySQL, including setting bind_address to a specific IP address."}}','2026-06-21T23:35:55.370Z','2026-06-22T00:52:33.905Z');
INSERT INTO misconfigurations VALUES('08d625b2-3475-4efc-a129-625f7cfc3d22',4,'mysql','allow-suspicious-udfs','ON','OFF','N','N','M','P','C','N',7.79999999999999982,7.29999999999999982,'L','H','[]','','4.3','Allowing suspicious user-defined functions can enable attackers with write access to the web root or specific network positions to load arbitrary shared libraries, potentially leading to remote code execution. However, this requires additional preconditions such as local file write access.','Set ''allow-suspicious-udfs'' to ''OFF''.','value','always','','{"description": "The directive ''allow-suspicious-udfs'' enables MySQL to load and execute user-defined functions from shared libraries. Setting this value to ON is dangerous because it allows attackers with write access to the web root or specific network positions to inject malicious code, potentially leading to remote code execution.", "potential_impact": ["Discloses system information", "Enables unauthorized modification of database configurations and data", "Potentially leads to full server compromise"], "exploitation_scenario": {"prerequisites": ["Write access to the MySQL configuration or web root directory", "Ability to place a malicious shared library in the specified path"], "example": "An attacker with write access places a malicious .so file in /var/lib/mysqludf/. The attacker then uses SQL commands like CREATE FUNCTION to load this UDF into MySQL.", "result": "The attacker can execute arbitrary code on the server, leading to full control over the database and potentially the entire system."}, "metric_justifications": {"ac": "Why AC=M: Allowing suspicious user-defined functions requires an attacker to have write access to specific directories or network positions, which is a moderate barrier but not trivial.", "c": "Why C=P: The configuration and system information can be disclosed through the execution of malicious UDFs.", "i": "Why I=C: Database configurations and data can be modified by executing arbitrary code via suspicious user-defined functions.", "a": "Why A=N: Availability is not directly affected, but the server may become unstable or crash due to malicious activities.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited in practice compared to more common vulnerabilities.", "grl": "Why GRL=H: There are extensive remediation guides and documentation available for securing MySQL against suspicious UDFs."}}','2026-06-21T23:37:38.995Z','2026-06-22T00:57:00.338Z');
INSERT INTO misconfigurations VALUES('07ada9e8-a0a8-4b66-9568-c7ca1118afcb',4,'mysql','local_infile','ON','OFF','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','["CVE-2016-6662", "CVE-2017-3594"]','','4.4','Enabling local_infile allows an attacker to read files from the MySQL client''s filesystem via SQL injection, but this requires a specific vulnerability and access to execute SQL commands.','Set ''local_infile=OFF'' in the [mysqld] section of the MySQL configuration file and restart the service.','value','always','','{"description": "The local_infile directive allows MySQL clients to load data from local files when executing SQL commands. Setting it to ON is dangerous because an attacker can exploit this feature via SQL injection to read sensitive files on the server.", "potential_impact": ["Read arbitrary files on the filesystem", "Steal credentials and configuration details", "Gain insights into system architecture"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to execute SQL commands", "The target MySQL server has local_infile enabled"], "example": "A malicious user injects an SQL command like ''SELECT LOAD_FILE(''/etc/passwd'') INTO OUTFILE ''/tmp/output.txt'';'' into a vulnerable application.", "result": "The attacker successfully reads the contents of /etc/passwd and writes it to /tmp/output.txt."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to execute SQL commands, which is not trivial but still feasible in many environments.", "c": "Why C=P: The attacker can read sensitive files such as configuration and credential files.", "i": "Why I=P: The attacker may modify data or configurations by writing malicious content back to the filesystem via SQL commands.", "a": "Why A=N: Availability is not directly impacted, but persistent access could lead to further exploitation affecting availability.", "gel": "Why GEL=L: This type of misconfiguration is exploited less frequently as it requires specific conditions and vulnerabilities.", "grl": "Why GRL=H: There are extensive resources available for understanding and mitigating the risks associated with local_infile."}}','2026-06-21T23:39:30.645Z','2026-06-22T01:01:04.405Z');
INSERT INTO misconfigurations VALUES('17851e85-f7cf-4e7e-a269-a5f4ab8e4b92',4,'mysql','skip-grant-tables','TRUE','FALSE','N','N','L','C','C','N',9.40000000000000035,9.40000000000000035,'H','H','[]','','4.5','Enabling ''--skip-grant-tables'' allows all clients unrestricted access to the MySQL server, leading to full data disclosure and arbitrary database modifications without authentication.','Set ''skip-grant-tables = FALSE'' in the MySQL configuration file (e.g., my.cnf).','value','always','','{"description": "The ''--skip-grant-tables'' directive in MySQL allows all clients unrestricted access to the server when set to TRUE. This is extremely dangerous as it bypasses all authentication mechanisms, enabling any user to perform administrative actions without credentials.", "potential_impact": ["Discloses full database content", "Enables arbitrary data modifications", "Allows creation of new users and privileges"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A malicious user connects to the MySQL server using a simple SQL client command: mysql -h hostname -u anyuser. Since skip-grant-tables is enabled, no password or authentication is required.", "result": "The attacker gains full administrative access and can read/write/delete all data in the database."}, "metric_justifications": {"ac": "Why AC=L: Enabling ''--skip-grant-tables'' makes it trivial for any user to connect without authentication, requiring no special skills or preconditions.", "c": "Why C=C: All sensitive information stored in the MySQL database is readable by anyone who can connect to the server.", "i": "Why I=C: The attacker can modify all data and create new users with administrative privileges, leading to full control over the system.", "a": "Why A=N: Availability is not directly impacted as the service remains operational; however, it becomes a critical security risk due to unauthorized access.", "gel": "Why GEL=H: Misconfigurations like ''--skip-grant-tables'' are common and frequently exploited by attackers seeking easy access to databases.", "grl": "Why GRL=H: There is extensive documentation available on how to properly secure MySQL, making it clear that this setting should be disabled."}}','2026-06-21T23:41:24.116Z','2026-06-22T01:05:14.658Z');
INSERT INTO misconfigurations VALUES('7eaf780e-c497-422a-a4dd-b0d979f98fd5',4,'mysql','skip-symbolic-links','NO','YES','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','4.6','Disabling skip-symbolic-links allows MySQL to follow symbolic links, which requires an attacker to have write access to create symlinks pointing to sensitive files. This limits the attack vector but still poses a risk of partial data integrity and confidentiality issues.','Set ''skip-symbolic-links = YES'' in the MySQL configuration file (my.cnf) under the [mysqld] section.','value','always','','{"description": "The ''skip-symbolic-links'' directive in MySQL configuration prevents the server from following symbolic links when accessing files. Setting this to NO allows MySQL to follow symlinks, which can expose sensitive data and configurations if an attacker has write access.", "potential_impact": ["Expose sensitive database files", "Modify or delete critical system files through symlink attacks", "Compromise the integrity of the database by altering configuration files"], "exploitation_scenario": {"prerequisites": ["An attacker must have write permissions to create symlinks in directories accessible by MySQL", "MySQL user privileges that allow file operations"], "example": "A malicious user creates a symbolic link from /var/lib/mysql/sensitive_data.txt to /etc/passwd. When the MySQL server attempts to access sensitive_data.txt, it reads /etc/passwd instead.", "result": "The attacker can read or modify critical system files and configurations through symlink attacks."}, "metric_justifications": {"ac": "AC=M: An attacker needs write permissions on directories accessible by the MySQL server to create symlinks, which is a moderate barrier but not insurmountable.", "c": "C=P: Confidentiality of sensitive data and system files can be compromised when MySQL follows symbolic links created by an attacker.", "i": "I=P: Integrity of critical database configurations and data may be altered through symlink attacks, leading to potential misconfigurations or data corruption.", "a": "A=N: Availability is not directly impacted as the server continues to function but can lead to indirect availability issues if critical files are compromised.", "gel": "GEL=L: The likelihood of this specific misconfiguration being exploited in a real-world scenario is low, but it remains a potential risk.", "grl": "GRL=H: There is extensive documentation and guidance available on how to properly configure MySQL to mitigate symlink risks."}}','2026-06-21T23:44:37.650Z','2026-06-22T01:09:44.897Z');
INSERT INTO misconfigurations VALUES('bb4527ec-7359-4279-8f58-bab10e749c78',4,'mysql','secure_file_priv','','/path/to/safe/directory','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','["CVE-2016-6662"]','','4.8','An empty secure_file_priv setting allows an attacker to read sensitive files via SQL injection, but requires the presence of a SQL injection vulnerability and write access to the MySQL configuration file — AC is Medium. The impact is limited to partial information disclosure and potential integrity compromise within the database context.','Set ''secure_file_priv'' to NULL or a secure directory path in the [mysqld] section of the MySQL configuration file.','value','always','','{"description": "The directive secure_file_priv is intended to restrict file operations performed by LOAD DATA INFILE and SELECT ... INTO OUTFILE SQL statements. An empty or missing value for this setting allows any user with FILE privileges to read arbitrary files on the server''s filesystem via SQL injection, which can lead to sensitive data exposure.", "potential_impact": ["Disclose sensitive system files such as /etc/passwd", "Read database configuration files like my.cnf to obtain credentials", "Compromise integrity by altering critical MySQL files"], "exploitation_scenario": {"prerequisites": ["An attacker must have FILE privilege in the MySQL server.", "The presence of a SQL injection vulnerability within an application connected to the database."], "example": "A malicious user with FILE privileges can execute: SELECT ''<?php echo file_get_contents(\"/etc/passwd\"); ?>'' INTO OUTFILE ''/var/www/html/output.php'';", "result": "An attacker gains unauthorized access to sensitive system files and potentially manipulates web content or database configurations."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs both FILE privileges and a SQL injection vulnerability, which requires specific conditions to be met, making it moderately difficult but not impossible.", "c": "Why C=P: Partial information disclosure occurs as attackers can read sensitive files like system configurations or database credentials.", "i": "Why I=P: The integrity of the MySQL server is partially compromised due to potential alterations in critical configuration and data files.", "a": "Why A=N: Availability is not directly impacted, but indirect effects such as web content manipulation may occur.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to other vulnerabilities because it requires specific conditions.", "grl": "Why GRL=H: There are numerous resources and documentation available for securing MySQL configurations, including the official MySQL documentation."}}','2026-06-21T23:48:00.654Z','2026-06-22T01:14:16.195Z');
INSERT INTO misconfigurations VALUES('e3b3f998-51ce-4a41-acc9-f0369727496b',4,'mysql','sql_mode','NO_ENGINE_SUBSTITUTION','NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION','N','N','L','N','P','N',5.0,4.70000000000000017,'L','H','[]','','7.4','Without NO_AUTO_CREATE_USER, a GRANT statement can accidentally create users with blank passwords, allowing partial integrity impact by creating unauthorized accounts.','Add ''NO_AUTO_CREATE_USER'' to the sql_mode setting in the MySQL configuration file (my.cnf).','value','always','','{"description": "The sql_mode directive in MySQL controls the SQL mode of the server which affects how SQL statements are executed. The value NO_ENGINE_SUBSTITUTION is not inherently dangerous but omitting NO_AUTO_CREATE_USER can lead to unintended user creation with blank passwords, compromising security.", "potential_impact": ["Allows unauthorized users to be created with empty passwords", "Enables attackers to gain partial integrity impact by creating unauthorized accounts", "Increases the risk of privilege escalation if combined with other vulnerabilities"], "exploitation_scenario": {"prerequisites": ["Access to MySQL GRANT statement execution"], "example": "A malicious user executes a GRANT statement without specifying a password, inadvertently creating an account with an empty password.", "result": "An unauthorized user is created with no password requirement, allowing easy login and potential further exploitation."}, "metric_justifications": {"ac": "AC=L: The absence of NO_AUTO_CREATE_USER in sql_mode makes it trivial for any attacker to exploit this misconfiguration by executing a GRANT statement without specifying a password.", "c": "C=N: No sensitive information is disclosed directly, but the creation of unauthorized accounts can indirectly lead to data exposure.", "i": "I=P: The integrity of the database system is compromised as new users with empty passwords can be created, potentially leading to further security breaches.", "a": "A=N: Availability is not directly impacted by this misconfiguration; however, newly created unauthorized accounts could affect service availability if exploited.", "gel": "GEL=L: This type of misconfiguration is frequently encountered in improperly configured MySQL installations and can be easily exploited once discovered.", "grl": "GRL=H: There are numerous resources available for remediation including official documentation and community forums."}}','2026-06-21T23:51:05.162Z','2026-06-22T02:13:51.328Z');
INSERT INTO misconfigurations VALUES('aedeb9ee-2bc5-439b-a2e2-60d8942347a8',4,'mysql','log_error','','/path/to/error/log','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','6.1','Logging errors to the console instead of a file can expose sensitive information to unauthorized users who have access to the console output. This requires an attacker to gain local or remote console access, making AC Medium.','Set ''log_error'' to a specific path in the MySQL configuration file (my.cnf or my.ini).','value','always','','{"description": "The ''log_error'' directive in MySQL specifies where error logs should be written. Logging errors to the console instead of a file can expose sensitive information such as database credentials and error details to unauthorized users who have access to the console output.", "potential_impact": ["Expose sensitive information like database credentials and error messages", "Allow attackers to gain insights into system configurations and vulnerabilities", "Enable attackers to perform further reconnaissance on the system"], "exploitation_scenario": {"prerequisites": ["An attacker must have local or remote console access to the MySQL server", "The attacker needs to monitor or intercept console output"], "example": "An attacker with SSH access to a MySQL server can tail -f /var/log/mysql.err and observe error logs in real-time.", "result": "Attackers gain valuable information from error messages, aiding them in further attacks."}, "metric_justifications": {"ac": "Why AC=M: Logging errors to the console requires an attacker to have local or remote console access, which is a moderate barrier as it involves gaining unauthorized access to the system.", "c": "Why C=P: The sensitive information disclosed through error logs can be read by attackers who gain console access, leading to potential compromise of the system.", "i": "Why I=N: There is no direct impact on data or configuration modification from logging errors to the console; however, it aids in reconnaissance and further attacks.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration as the service continues to function normally. However, it can indirectly affect availability if attackers use the information for more severe attacks.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to other vulnerabilities but remains a risk due to its potential impact on system security.", "grl": "Why GRL=H: There are numerous resources and documentation available that explain how to properly configure MySQL logging, making it easy for administrators to remediate this issue."}}','2026-06-21T23:54:11.630Z','2026-06-22T01:27:06.564Z');
INSERT INTO misconfigurations VALUES('ff7920fb-4476-4201-8c9d-77f79c1f5913',4,'mysql','audit_log','','FORCE_PLUS_PERMANENT','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','6.11','If the audit_log plugin can be unloaded, an attacker with sufficient privileges could disable logging temporarily or permanently, leading to partial confidentiality and integrity impacts by preventing auditing of actions.','Set ''audit_log = FORCE_PLUS_PERMANENT'' in the MySQL configuration file (my.cnf) under the [mysqld] section.','value','always','','{"description": "The audit_log directive enables logging of MySQL events for auditing purposes. Disabling this feature by setting it to an empty value allows attackers with sufficient privileges to disable logging temporarily or permanently, leading to a loss of critical audit trails.", "potential_impact": ["Compromise confidentiality and integrity of the database by preventing logging of actions", "Enable unauthorized modifications without traceability", "Reduce forensic capabilities in case of security incidents"], "exploitation_scenario": {"prerequisites": ["Sufficient privileges to modify MySQL configuration", "Access to restart or reload MySQL service"], "example": "An attacker with root access modifies the my.cnf file to remove the audit_log plugin setting and then restarts the MySQL server.", "result": "The audit logging is disabled, preventing any future actions from being logged."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to the MySQL configuration files and the ability to restart or reload the MySQL service, which represents a moderate barrier.", "c": "Why C=P: Sensitive information about database actions is no longer logged, leading to potential data exfiltration without audit trails.", "i": "Why I=P: The attacker can modify the database schema or data without being recorded in logs, compromising integrity.", "a": "Why A=N: Availability of the MySQL service remains unaffected as logging does not impact performance or uptime.", "gel": "Why GEL=L: Exploitation requires specific conditions to be met and is less likely to occur frequently.", "grl": "Why GRL=H: There are extensive resources available for remediation, including official documentation on enabling audit_log."}}','2026-06-21T23:55:54.203Z','2026-06-22T01:31:09.733Z');
INSERT INTO misconfigurations VALUES('eb79d7a0-712c-4a00-a8a1-01f8a98ffb50',4,'mysql','log-bin','/var/log/mysql/bin-log.*|/usr/local/mysql/data/bin-log.*|/','/non-system-partition/path/to/binary-logs','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','6.2','Logging MySQL binary logs on the system partition can lead to denial of service if disk space is exhausted, but this requires specific conditions and does not directly expose sensitive information or allow arbitrary file writes.','Move log-bin files to a non-system partition such as /mnt/logs/mysql/','value','always','','{"description": "The MySQL directive ''log-bin'' specifies the location for storing binary logs. Storing these logs in system partitions such as /var/log/mysql/bin-log.* or /usr/local/mysql/data/bin-log.* can lead to disk space exhaustion, impacting system stability and availability.", "potential_impact": ["Exhaust disk space on critical system partitions", "Cause denial of service due to full disk conditions", "Impede database recovery operations"], "exploitation_scenario": {"prerequisites": ["An attacker must have the ability to manipulate MySQL configuration or cause excessive logging activity", "The system partition where logs are stored needs to be near capacity"], "example": "A malicious user could exploit a vulnerability that allows them to flood the binary log with large volumes of data, causing disk space exhaustion.", "result": "MySQL services may become unavailable due to lack of disk space for logging."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs specific permissions or conditions such as exploiting a vulnerability that allows them to manipulate MySQL configuration or cause excessive logging activity, which is not trivial but still feasible.", "c": "Why C=N: No sensitive information is directly exposed by this misconfiguration; however, the impact on system availability can be severe.", "i": "Why I=N: The misconfiguration does not inherently allow for arbitrary file writes or modifications to other critical configurations beyond logging.", "a": "Why A=P: Availability of MySQL services and overall system stability are significantly impacted when disk space is exhausted due to excessive binary log storage on system partitions.", "gel": "Why GEL=L: While the misconfiguration can be exploited, it requires specific conditions that may not occur frequently in all environments.", "grl": "Why GRL=H: There is extensive documentation and guidance available for securing MySQL configurations, including best practices for binary log management."}}','2026-06-21T23:58:55.666Z','2026-06-22T01:35:44.613Z');
INSERT INTO misconfigurations VALUES('9fe6f8dd-00db-4b18-901f-619dc24e182a',4,'mysql','log-warnings','1','2','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','6.3','Setting log_warnings to ''1'' enables logging of warning messages but not critical information. This can disclose communication errors and aborted connections, potentially revealing sensitive operational details.','Set ''log-warnings = 2'' in the MySQL configuration file (my.cnf) under the mysqld section.','value','always','','{"description": "The MySQL directive ''log-warnings'' is set to 1, which enables logging of warning messages but not critical information such as aborted connections and communication errors. This can potentially reveal sensitive operational details.", "potential_impact": ["Disclose communication errors that may indicate issues with database integrity or security", "Reveal aborted connections that could provide insights into failed login attempts or unauthorized access", "Expose internal MySQL operations which might aid in understanding the database environment"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can analyze the MySQL logs to gather information about communication errors and aborted connections.", "result": "The attacker gains insights into potential security weaknesses or operational issues within the MySQL server."}, "metric_justifications": {"ac": "AC=L: The misconfiguration is easily exploitable by analyzing standard log files without any special preconditions, making it trivial for an attacker to discover sensitive information.", "c": "C=P: The configuration allows disclosure of critical communication errors and aborted connections that can be used to infer security weaknesses or operational issues.", "i": "I=N: There is no direct impact on data modification or configuration changes through this misconfiguration alone.", "a": "A=N: Availability is not directly impacted by the logging level set to 1, but sensitive information disclosure could indirectly affect system security.", "gel": "GEL=M: Misconfigurations like this are moderately exploited as they provide valuable insights for attackers without requiring complex techniques.", "grl": "GRL=H: Remediation documentation is widely available and straightforward, making it easy to correct the misconfiguration."}}','2026-06-22T00:00:34.841Z','2026-06-22T01:39:43.365Z');
INSERT INTO misconfigurations VALUES('c405bd49-409e-449c-ae3a-fef32e285c14',4,'mysql','log-raw','ON','OFF','N','N','L','C','N','N',7.79999999999999982,7.79999999999999982,'M','H','[]','','6.4','Enabling log-raw allows plain text passwords to be logged, exposing sensitive information to anyone with access to the logs.','Set ''log-raw = OFF'' in the MySQL configuration file (my.cnf).','value','always','','{"description": "The ''log-raw'' directive in MySQL logs all raw queries to the error log. When set to ON, it includes plain text passwords in these logs, exposing sensitive information to unauthorized users who can access the logs.", "potential_impact": ["Expose database credentials", "Allow unauthorized access to the database", "Compromise data integrity and confidentiality"], "exploitation_scenario": {"prerequisites": ["Access to MySQL error log files"], "example": "An attacker with read access to the MySQL error logs can easily find plain text passwords in the raw query logs.", "result": "The attacker gains unauthorized access to the database using the exposed credentials."}, "metric_justifications": {"ac": "AC=L: An attacker only needs read access to the MySQL error log files, which is trivial for someone with low-level system privileges or a misconfigured file permissions setup.", "c": "C=C: The logs contain sensitive information such as plain text passwords and other critical data that can be used to compromise the database.", "i": "I=N: There is no direct impact on modifying data or configuration through this vulnerability, but it enables lateral movement within the system.", "a": "A=N: Availability of services is not directly impacted by logging raw queries; however, the risk of service disruption increases due to potential misuse of exposed credentials.", "gel": "GEL=M: Misconfigurations like enabling ''log-raw'' are moderately common and can be exploited frequently if discovered.", "grl": "GRL=H: There is extensive documentation available on how to remediate this issue, including official MySQL guides and security advisories."}}','2026-06-22T00:02:08.134Z','2026-06-22T01:43:42.988Z');
INSERT INTO misconfigurations VALUES('ca9a2186-1266-494e-942f-d8c4ead44413',4,'mysql','audit_log_connection_policy','NONE','ERRORS|ALL','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','6.5','Setting audit_log_connection_policy to NONE disables logging of failed and successful connection events, allowing attackers to evade detection for malicious activities.','Set ''audit_log_connection_policy'' to either ERRORS or ALL in the MySQL configuration file to ensure proper auditing of connection events.','value','always','','{"description": "The audit_log_connection_policy directive in MySQL controls whether connection events are logged. Setting this to NONE disables logging of both successful and failed connection attempts, which can allow attackers to evade detection for malicious activities.", "potential_impact": ["Allows unauthorized access without trace", "Enables lateral movement within the network undetected", "Hinders forensic analysis after a breach"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by attempting to brute-force login credentials or using stolen credentials. Since logging is disabled, these activities leave no trace in the audit logs.", "result": "The attacker gains unauthorized access and performs malicious actions without being detected."}, "metric_justifications": {"ac": "AC=L: Setting audit_log_connection_policy to NONE makes it easy for any attacker to exploit this misconfiguration by simply attempting login attempts, as there are no logging barriers.", "c": "C=P: The configuration detail is publicly readable and can be easily discovered through SQL queries or MySQL documentation.", "i": "I=N: There is no direct impact on data integrity since the misconfiguration does not allow for unauthorized modification of data or configurations beyond evading detection.", "a": "A=N: Availability is unaffected as disabling logging does not disrupt service availability, but it hinders monitoring and response efforts.", "gel": "GEL=M: This type of misconfiguration can be exploited moderately frequently due to its ease of discovery and exploitation.", "grl": "GRL=H: There are numerous resources available for remediation, including official MySQL documentation and security guidelines."}}','2026-06-22T00:05:07.499Z','2026-06-22T01:47:45.951Z');
INSERT INTO misconfigurations VALUES('0cadc554-69e5-4a03-952d-1aad07faa1ec',4,'mysql','audit_log_exclude_accounts','','NULL','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','6.6','Setting audit_log_exclude_accounts to an empty string allows any user''s activities to go unlogged, potentially enabling malicious actions without trace in the audit log.','Set ''audit_log_exclude_accounts = NULL'' to ensure all user activities are logged appropriately.','value','always','','{"description": "The directive ''audit_log_exclude_accounts'' is intended to specify accounts whose activities should not be logged. Setting this value to an empty string allows any user''s actions to go unlogged, potentially enabling malicious actions without trace in the audit log.", "potential_impact": ["Allows unauthorized access and activity to remain undetected", "Enables attackers to perform actions that can compromise data integrity and confidentiality", "Facilitates lateral movement within the system by hiding the attacker''s footprint"], "exploitation_scenario": {"prerequisites": ["An attacker with any level of MySQL user access"], "example": "Setting audit_log_exclude_accounts = '''' in the MySQL configuration file to disable logging for all users.", "result": "All user activities are no longer logged, allowing malicious actions to go undetected."}, "metric_justifications": {"ac": "Why AC=L: Setting ''audit_log_exclude_accounts'' to an empty string is trivially exploitable by any MySQL user with access, as it requires only changing the configuration setting.", "c": "Why C=P: The attacker can potentially gain full control over the system without leaving a trace in logs, leading to potential data exfiltration and other malicious activities.", "i": "Why I=N: While the misconfiguration does not directly modify data or configurations, it enables attackers to perform actions that can compromise integrity and confidentiality.", "a": "Why A=N: The availability of the system is not directly impacted by this misconfiguration; however, it indirectly affects security posture by enabling undetected malicious activities.", "gel": "Why GEL=M: This type of misconfiguration is moderately likely to be exploited as it provides a significant advantage to attackers in covering their tracks.", "grl": "Why GRL=H: There are extensive remediation steps and documentation available for securing MySQL configurations, making it relatively easy to correct this issue."}}','2026-06-22T00:06:53.880Z','2026-06-22T01:52:12.822Z');
INSERT INTO misconfigurations VALUES('87f28ea0-27c1-4be3-ac7f-a4bd09f23c2d',4,'mysql','audit_log_include_accounts','','NULL','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','6.7','Setting audit_log_include_accounts to an empty string allows only explicitly listed MySQL accounts to be logged, potentially excluding malicious activity from the audit log. This requires insider or local access to modify the configuration.','Set ''audit_log_include_accounts = NULL'' in my.cnf or execute ''SET GLOBAL audit_log_include_accounts = NULL;''','value','always','','{"description": "The directive ''audit_log_include_accounts'' should be set to NULL to ensure that all MySQL accounts are logged by default. Setting it to an empty string can exclude certain activities from being audited, potentially allowing malicious actions to go undetected.", "potential_impact": ["Allows unauthorized access attempts and suspicious activities to remain unlogged", "Enables attackers with insider knowledge or local access to evade detection", "Reduces the ability of security teams to track and respond to potential threats"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to MySQL configuration files or execute SQL commands as a superuser", "The attacker needs knowledge of the current audit_log_include_accounts setting"], "example": "SET GLOBAL audit_log_include_accounts = '''';", "result": "All accounts except those explicitly listed in the audit log will not be logged, allowing malicious activities to go unnoticed."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to MySQL configuration files or execute SQL commands as a superuser, which is a moderate barrier but still achievable for insiders with certain privileges.", "c": "Why C=P: The information disclosed includes potential evasion of audit trails and the ability to hide malicious activities from security monitoring systems.", "i": "Why I=N: While the configuration can be modified, there is no direct data or configuration modification impact beyond altering logging behavior.", "a": "Why A=N: Availability is not directly impacted as MySQL continues to function normally; however, the lack of comprehensive audit logs may hinder incident response efforts.", "gel": "Why GEL=L: This type of misconfiguration can be exploited by insiders with specific privileges but is less likely to be discovered and used by external attackers without such access.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official MySQL documentation and security guidelines."}}','2026-06-22T00:08:48.704Z','2026-06-22T01:56:44.505Z');
INSERT INTO misconfigurations VALUES('f07ea0a0-8351-4921-8311-1e7ad7e15ca6',4,'mysql','old_passwords','1','0','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','7.1','Setting ''old_passwords'' to 1 uses a weak hashing algorithm, making it easier for attackers to crack passwords if they are captured. This can lead to partial confidentiality impact as sensitive information may be compromised.','Set ''old_passwords'' to 0 or 2 to use the mysql_native_password or sha256_password plugin respectively.','value','always','','{"description": "The ''old_passwords'' directive in MySQL determines whether to use the old or new password hashing algorithm. Setting it to 1 enables the weaker MySQL native password hashing method, which is vulnerable to offline brute-force attacks and makes passwords easier to crack.", "potential_impact": ["Compromise sensitive information through cracked passwords", "Enable unauthorized access to databases with weak credentials", "Reduce overall security posture due to outdated encryption methods"], "exploitation_scenario": {"prerequisites": ["Access to a MySQL database", "Captured password hashes"], "example": "An attacker captures the password hash of a user and uses a tool like John the Ripper or Hashcat to crack it offline, exploiting the weak hashing algorithm.", "result": "The attacker gains unauthorized access to the database using the cracked credentials."}, "metric_justifications": {"ac": "Why AC=L: Setting ''old_passwords'' to 1 makes password cracking trivial for attackers with captured hashes and common tools, requiring no special conditions beyond sending a request.", "c": "Why C=P: The confidentiality of sensitive information is partially compromised as weak passwords can be easily cracked offline.", "i": "Why I=N: There is no direct impact on data or configuration modification through this misconfiguration alone.", "a": "Why A=N: Availability is not directly impacted by the ''old_passwords'' setting, but successful exploitation could indirectly affect availability if critical services are compromised.", "gel": "Why GEL=M: This type of misconfiguration is frequently exploited due to its ease and the widespread use of weak password hashing algorithms.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, including official MySQL guides."}}','2026-06-22T00:12:08.879Z','2026-06-22T02:00:58.206Z');
INSERT INTO misconfigurations VALUES('a0d142f5-801f-4f53-84d2-d69ec6fc450f',4,'mysql','secure_auth','OFF','ON','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','7.2','Disabling secure_auth allows clients to use accounts with passwords stored in the insecure mysql_old_password format, enabling attackers who can authenticate using these accounts to exploit vulnerabilities related to weak or outdated encryption.','Set ''secure_auth=ON'' to prevent connections from clients using old password formats and ensure secure communication over the network.','value','always','','{"description": "The directive secure_auth is designed to prevent clients from using accounts with passwords stored in the insecure mysql_old_password format. Disabling this feature (secure_auth=OFF) allows connections from clients using these outdated password formats, increasing vulnerability to attacks exploiting weak encryption.", "potential_impact": ["Allows attackers to authenticate using weak or outdated password hashes", "Enables exploitation of vulnerabilities related to old authentication methods", "Increases the risk of unauthorized access due to insecure communication"], "exploitation_scenario": {"prerequisites": ["An attacker must have knowledge of a username and its corresponding mysql_old_password hash", "The attacker needs network access to attempt connections"], "example": "An attacker uses a tool like John the Ripper or Hashcat to crack an old password hash, then connects to the MySQL server using the cracked credentials.", "result": "Successful authentication with an insecure password format grants the attacker unauthorized access to the database."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs knowledge of a specific username and its corresponding mysql_old_password hash, which requires reconnaissance or prior compromise. This moderate barrier makes exploitation more challenging than trivial but not extremely difficult.", "c": "Why C=P: The disclosure of sensitive data is possible through unauthorized access granted by insecure authentication methods.", "i": "Why I=N: While the attacker can gain unauthorized access, there are no specific mechanisms in place to allow for direct modification or deletion of critical configurations or data beyond what standard user privileges permit.", "a": "Why A=N: The availability of services is not directly impacted by this misconfiguration; however, successful exploitation could lead to denial-of-service if the attacker disrupts normal operations through unauthorized access.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited in practice due to the increasing adoption of more secure authentication methods and practices.", "grl": "Why GRL=H: There are numerous resources available for understanding and mitigating this risk, including official MySQL documentation and security advisories."}}','2026-06-22T00:14:05.288Z','2026-06-22T02:09:37.656Z');
INSERT INTO misconfigurations VALUES('66354f4b-4042-467b-975d-52c1065d588b',4,'mysql','have_ssl','NO','YES','N','N','L','P','N','N',5.0,5.0,'H','H','[]','','8.1','Disabling SSL/TLS allows plaintext traffic, exposing data to eavesdropping and man-in-the-middle attacks. Any remote attacker can intercept sensitive information.','Set ''have_ssl'' to ''YES'' and configure SSL/TLS as per the MySQL Reference Manual.','value','always','','{"description": "The ''have_ssl'' directive enables SSL/TLS encryption for MySQL connections. Disabling it (value NO) allows plaintext traffic, exposing sensitive data to interception and man-in-the-middle attacks.", "potential_impact": ["Expose database credentials and sensitive information in transit", "Allow attackers to intercept and modify data during transmission", "Enable eavesdropping on communication between the MySQL server and clients"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sniffs network traffic to capture unencrypted database credentials and queries.", "result": "The attacker can read or modify data in transit, leading to unauthorized access and potential data breaches."}, "metric_justifications": {"ac": "Why AC=L: Disabling SSL/TLS (have_ssl=NO) makes it trivial for any remote attacker to intercept plaintext traffic without needing additional privileges.", "c": "Why C=P: Confidentiality is partially compromised as sensitive data can be read by attackers who intercept network communications.", "i": "Why I=N: Integrity of the data in transit is not directly affected, but attackers can modify intercepted data leading to potential injection attacks or data corruption.", "a": "Why A=N: Availability is not directly impacted; however, denial-of-service scenarios could arise if attackers exploit vulnerabilities introduced by plaintext communication.", "gel": "Why GEL=H: Misconfigurations like disabling SSL/TLS are frequently exploited due to the ease of capturing sensitive information in plain text.", "grl": "Why GRL=H: Remediation steps for enabling SSL/TLS are well-documented and widely available, making it straightforward to correct this misconfiguration."}}','2026-06-22T00:17:23.807Z','2026-06-22T02:17:54.897Z');
INSERT INTO misconfigurations VALUES('a4c3d01e-4313-4ab1-a68c-c9d892066dad',4,'mysql','ssl_type','','ANY,X509,SPECIFIED','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','8.2','Not enforcing SSL/TLS allows eavesdropping and man-in-the-middle attacks, exposing sensitive data in transit. However, it does not provide full system access or immediate availability impact.','Use the GRANT statement to require SSL for users connecting over untrusted networks: GRANT USAGE ON *.* TO ''my_user''@''app1.example.com'' REQUIRE X509;','value','always','','{"description": "The ssl_type directive specifies the SSL/TLS requirements for MySQL connections. Not setting this to ANY, X509, or SPECIFIED allows unencrypted communication between clients and the server, exposing sensitive data in transit.", "potential_impact": ["Expose database traffic to eavesdropping", "Allow interception of authentication credentials", "Enable man-in-the-middle attacks"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can intercept network traffic between a MySQL client and server, capturing unencrypted data.", "result": "The attacker gains access to sensitive information such as database queries, credentials, and other confidential data."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily eavesdrop on or intercept unencrypted MySQL traffic without any special preconditions beyond being able to monitor the network.", "c": "Why C=P: The confidentiality of sensitive information such as database queries and credentials is compromised, allowing an attacker to read this data.", "i": "Why I=N: While SSL/TLS configuration affects security, it does not inherently provide mechanisms for modifying data or configurations directly through this misconfiguration alone.", "a": "Why A=N: The availability of the system is not directly impacted by the lack of SSL/TLS enforcement; however, sensitive data exposure can indirectly affect trust and operational integrity.", "gel": "Why GEL=M: This type of misconfiguration is commonly exploited due to its ease of detection and exploitation in environments where security practices are lax.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure SSL/TLS for MySQL, making remediation straightforward."}}','2026-06-22T00:20:32.368Z','2026-06-22T02:22:02.610Z');
INSERT INTO misconfigurations VALUES('9c171876-cf6f-4c2b-a409-64b0cb47eef7',4,'mysql','master_info_repository','FILE','TABLE','N','N','M','P','C','N',7.79999999999999982,7.29999999999999982,'L','H','[]','','9.3','Setting master_info_repository to ''FILE'' stores the password in a plaintext file, which can be accessed by an attacker with filesystem permissions. This allows modification of the slave''s connection information and potential unauthorized access.','Set ''master_info_repository = TABLE'' to store the password securely within the database tables.','value','always','','{"description": "The directive master_info_repository controls where MySQL replication master information is stored. Setting it to ''FILE'' stores this sensitive data in plaintext files on disk, which can be accessed by unauthorized users with filesystem permissions.", "potential_impact": ["Expose the replication password and other sensitive configuration details", "Allow an attacker to modify the slave''s connection information", "Enable unauthorized access to the master server through compromised credentials"], "exploitation_scenario": {"prerequisites": ["An attacker with filesystem permissions on the MySQL data directory"], "example": "An attacker reads the plaintext file containing replication details and modifies it to redirect traffic or steal credentials.", "result": "The attacker gains unauthorized access to the master server''s replication configuration, potentially leading to data theft or service disruption."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs filesystem permissions on the MySQL data directory, which is a moderate barrier compared to trivially exploitable configurations.", "c": "Why C=P: The replication password and other sensitive configuration details are readable in plaintext files.", "i": "Why I=C: The slave''s connection information can be modified, leading to potential unauthorized access or redirection of traffic.", "a": "Why A=N: Availability is not directly affected by this misconfiguration, but it may lead to service disruption if the attacker uses the compromised credentials.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to more common vulnerabilities like SQL injection or XSS.", "grl": "Why GRL=H: There are extensive remediation guidelines and documentation available for securing MySQL replication configurations."}}','2026-06-22T00:22:18.416Z','2026-06-22T02:26:02.620Z');
INSERT INTO misconfigurations VALUES('ada8999a-3fc2-4481-b1bd-8542bbc02eea',6,'docker','docker group membership','untrusted users','trusted users only','N','N','M','P','C','C',9.0,8.09999999999999964,'H','U','[]','','1.1.2','Untrusted users in the docker group can start containers with root access to the host file system, allowing them to modify sensitive files or gain elevated privileges. This is a direct full system compromise (CAT I).','Remove untrusted users from the docker group and ensure that sensitive directories are not mapped from the host to container volumes.','value','always','','{"description": "Docker group membership allows users to manage and run Docker containers. Setting the docker group to include untrusted users can lead to a full system compromise as these users can start containers with root access to the host file system, allowing them to modify sensitive files or gain elevated privileges.", "potential_impact": ["Unauthorized modification of sensitive files", "Elevation of privilege to root level", "Potential data exfiltration"], "exploitation_scenario": {"prerequisites": ["Membership in the docker group", "Knowledge of Docker commands"], "example": "Running the command: `docker run -it --privileged <image>` as an untrusted user grants them root access to the host.", "result": "The untrusted user gains root access to the host, allowing them to modify sensitive files or gain elevated privileges."}, "metric_justifications": {"ac": "Untrusted users in the docker group can start containers with root access to the host file system, allowing them to modify sensitive files or gain elevated privileges. This is a direct full system compromise (CAT I), but requires knowledge of Docker commands and membership in the docker group.", "c": "Untrusted users can read sensitive files on the host file system.", "i": "Untrusted users can modify sensitive files on the host file system.", "a": "Availability is affected as untrusted users can disrupt services running on the host.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires knowledge of Docker commands and membership in the docker group.", "grl": "Remediation documentation is widely available, such as CIS Benchmark section 1.1.2."}}','2026-06-24T22:34:41.604Z','2026-06-24T22:44:05.266Z');
INSERT INTO misconfigurations VALUES('a11bdbc7-5606-41a7-b169-4a16594a14c3',6,'docker','container host hardening status','insecure','hardened','N','N','M','N','N','N',0.0,0.0,'L','U','[]','','1.2.1','When the container host hardening status is ''insecure'', the host system is not following best practices for infrastructure security. This could potentially lead to security exposures and breaches, but no immediate impact is observed as the host is still running.','Hardening the container host OS is recommended according to infrastructure security best practices.','value','always','','{"description": "The container host hardening status being ''insecure'' indicates that the host system is not following best practices for infrastructure security, potentially leading to security exposures and breaches.", "potential_impact": ["Unauthorized access to the host system", "Data leakage or modification", "Disruption of service due to malicious activities"], "exploitation_scenario": {"prerequisites": ["Knowledge of the container host''s vulnerabilities", "Access to the container host network"], "example": "An attacker can exploit unpatched vulnerabilities in the container host OS to gain access.", "result": "The attacker gains control over the container host, potentially leading to data breaches or service disruptions."}, "metric_justifications": {"ac": "When the container host hardening status is ''insecure'', an attacker requires specific knowledge of the container host''s vulnerabilities and network access. This represents a moderate barrier (AC=M) to exploitation.", "c": "With an insecure container host, sensitive information may be disclosed or readable by unauthorized entities.", "i": "The insecure state allows for potential modification of data or configuration on the container host.", "a": "The availability of services running on the container host may be affected due to malicious activities.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it depends on the specific vulnerabilities present in the container host OS.", "grl": "Remediation documentation for securing the container host is widely available and well-documented."}}','2026-06-24T22:34:51.134Z','2026-06-24T22:44:25.418Z');
INSERT INTO misconfigurations VALUES('ed915124-fc83-4198-9f0a-93e6ec73907d',6,'docker','Docker daemon''s cgroup usage','non-default','default','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','2.11','Setting Docker daemon''s cgroup usage to ''non-default'' can lead to unintended resource sharing and utilization issues on the host, but it does not directly expose sensitive information or allow system compromise.','Leave the default cgroup usage as is by not specifying --cgroup-parent when starting Docker daemon.','value','always','','{"description": "Setting Docker daemon''s cgroup usage to ''non-default'' can lead to unintended resource sharing and utilization issues on the host, potentially causing performance degradation or denial of service. This misconfiguration may also complicate container isolation and management.", "potential_impact": ["Performance degradation due to improper resource allocation", "Potential Denial of Service by consuming excessive resources", "Complexity in managing containers due to altered cgroup hierarchy"], "exploitation_scenario": {"prerequisites": ["Access to the host where Docker daemon is running", "Knowledge of non-default cgroup usage configuration"], "example": "For example, starting Docker daemon with --cgroup-parent=systemd instead of the default: docker run --cgroup-parent=systemd image_name", "result": "The Docker containers will now share resources differently than intended, potentially causing the issues mentioned in potential_impact"}, "metric_justifications": {"ac": "Setting Docker daemon''s cgroup usage to ''non-default'' requires specific knowledge of the host''s resource management system and the ability to modify the Docker daemon''s startup parameters. This is a genuine but moderate barrier, as it involves more than just a standard HTTP request or simple command.", "c": "No sensitive information is directly disclosed by this misconfiguration.", "i": "The configuration can affect how resources are allocated among containers, but it does not allow direct modification of the host''s system files or data.", "a": "Availability is affected due to potential performance degradation and Denial of Service scenarios.", "gel": "Exploitation frequency for this type of misconfiguration may be low, as it requires specific knowledge and intent.", "grl": "Remediation documentation is widely available, but the implementation may require manual intervention."}}','2026-06-24T22:35:00.576Z','2026-06-24T22:44:45.855Z');
INSERT INTO misconfigurations VALUES('24d41bae-faf8-44bd-9273-c1013f17c71f',6,'docker','storage-opt dm.basesize','set','not set until needed','N','N','M','N','N','P',4.29999999999999982,3.60000000000000008,'L','U','[]','','2.12','Setting ''storage-opt dm.basesize'' expands the base device size, which may cause a denial of service condition if the allocated partition becomes full. However, shrinking is not permitted.','Do not set --storage-opt dm.basesize until needed to avoid potential denial of service.','value','always','','{"description": "Setting ''storage-opt dm.basesize'' expands the base device size of Docker volumes, which may cause a denial of service condition if the allocated partition becomes full and new data cannot be written. This setting should not be applied until it is needed to avoid potential data loss or system instability.", "potential_impact": ["Potential data loss due to insufficient storage space", "System instability leading to degraded performance", "Denial of service if the allocated partition becomes full"], "exploitation_scenario": {"prerequisites": ["Access to Docker configuration files", "Knowledge of ''storage-opt dm.basesize'' option"], "example": "Example config snippet: `docker run --storage-opt dm.basesize=<size> ...`", "result": "The base device size of Docker volumes is expanded, potentially causing a denial of service if the allocated partition becomes full."}, "metric_justifications": {"ac": "Setting ''storage-opt dm.basesize'' requires knowledge of the option and write access to Docker configuration files, making it a moderate barrier for an attacker (AC=M).", "c": "No sensitive information is disclosed or readable as a result of this misconfiguration.", "i": "The misconfiguration allows for modification of the base device size of Docker volumes, potentially causing data loss or system instability.", "a": "Availability is affected by the potential denial of service condition if the allocated partition becomes full.", "gel": "Exploitation frequency for this type of misconfiguration may be low as it requires specific knowledge and access to Docker configuration files.", "grl": "Remediation documentation for this misconfiguration is widely available, making it easier to address."}}','2026-06-24T22:35:09.040Z','2026-06-24T22:45:08.418Z');
INSERT INTO misconfigurations VALUES('60f42e3a-40d9-45e4-8289-08b9cb727b30',6,'docker','dockerd_log_driver','json','syslog','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','2.14','Dockerd_log_driver=''json'' stores logs locally as files, which may not be easily accessible or managed centrally. This can lead to difficulties in monitoring and responding to security incidents.','Configure a centralized logging solution by setting dockerd_log_driver according to your IT security policy (e.g., syslog, journald, etc.).','value','always','','{"description": "The ''dockerd_log_driver'' set to ''json'' stores logs locally as files, which may not be easily accessible or managed centrally. This can lead to difficulties in monitoring and responding to security incidents.", "potential_impact": ["Unauthorized access to sensitive log data", "Delayed detection of security incidents", "Inability to effectively audit and troubleshoot Docker containers"], "exploitation_scenario": {"prerequisites": ["Access to the host system where Docker is running"], "example": "Modifying the Docker daemon configuration file (/etc/docker/daemon.json) to set ''log-driver'' to ''json''", "result": "Logs are stored locally as files instead of being sent to a centralized logging solution"}, "metric_justifications": {"ac": "Requires write access to the Docker daemon configuration file, which can be challenging but not overly complex for an attacker with local system access.", "c": "Sensitive log data is disclosed if an attacker gains access to the host system where Docker logs are stored", "i": "An attacker cannot modify the logs directly, but they can potentially manipulate them before they are written or after they are read", "a": "Availability of Docker logs may be affected due to difficulties in monitoring and responding to security incidents", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires local system access", "grl": "Remediation documentation is widely available, but effective implementation depends on the specific IT security policies and centralized logging solutions in place"}}','2026-06-24T22:35:18.361Z','2026-06-24T22:45:29.948Z');
INSERT INTO misconfigurations VALUES('6dc70aea-cc0b-4d29-9680-f45d7acb364b',6,'docker','dockerd_no_new_privileges','not set','--no-new-privileges','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','2.15','When dockerd_no_new_privileges is not set, containers can acquire additional privileges via suid or sgid bits. This increases the risk of subverting privileged binaries and bypassing LSMs like SELinux.','Set ''dockerd --no-new-privileges'' to restrict containers from acquiring new privileges.','value','always','','{"description": "Dockerd_no_new_privileges is not set, allowing containers to acquire additional privileges via suid or sgid bits. This increases the risk of subverting privileged binaries and bypassing LSMs like SELinux.", "potential_impact": ["Container escalation of privilege", "Bypassing security measures such as SELinux", "Potential data exposure or manipulation due to increased container privileges"], "exploitation_scenario": {"prerequisites": ["Access to the host system where Docker is running", "Existence of a container with suid or sgid bits"], "example": "''docker run -it --privileged alpine sh'' command, which starts an Alpine container with full privileges on the host system", "result": "The container acquires additional privileges beyond its intended scope, increasing the risk of data breaches and system compromise"}, "metric_justifications": {"ac": "Requires write access to the web root or execution of a container with suid or sgid bits, an additional precondition", "c": "No specific information disclosure", "i": "Data and configuration can be modified due to increased container privileges", "a": "Availability may be affected if the container exploitation leads to a system crash or data loss", "gel": "Exploitation frequency for this type of misconfiguration is moderate, depending on the specific attack scenario", "grl": "Remediation documentation is widely available and easy to find"}}','2026-06-24T22:35:25.328Z','2026-06-24T22:45:46.224Z');
INSERT INTO misconfigurations VALUES('341a6036-153a-43a8-90f0-2e021104d91d',6,'docker','dockerd --live-restore','not present or not enabled','enabled','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','2.16','The --live-restore option in Docker ensures that containers continue running during daemon restarts, improving availability. However, it does not directly impact confidentiality or integrity as it only affects container management, not data handling.','Enable ''dockerd --live-restore'' to maintain container availability during daemon restarts.','value','always','','{"description": "The absence or non-enablement of ''dockerd --live-restore'' can lead to interruptions in container availability during daemon restarts, potentially causing service disruptions and increased downtime.", "potential_impact": ["Service interruptions", "Increased downtime", "Potential data loss due to container termination"], "exploitation_scenario": {"prerequisites": ["Unauthorized access to the Docker host"], "example": "''dockerd --live-restore=false'' in daemon configuration file (daemon.json)", "result": "Containers will be terminated during daemon restarts"}, "metric_justifications": {"ac": "Requires unauthorized access to the Docker host and modification of the daemon configuration, demonstrating a moderate barrier for exploitation.", "c": "No sensitive information is disclosed or readable due to this misconfiguration.", "i": "No data or configuration can be modified directly as a result of this misconfiguration.", "a": "Availability is affected as containers will terminate during daemon restarts, impacting service availability.", "gel": "Exploitation frequency for this type of misconfiguration may be low due to the need for unauthorized access and configuration modification.", "grl": "Remediation documentation is readily available in Docker official documentation and CIS Benchmark."}}','2026-06-24T22:35:33.387Z','2026-06-24T22:46:02.399Z');
INSERT INTO misconfigurations VALUES('c208e7b5-01c7-4cbe-8378-30c7b3e0d8d2',6,'docker','dockerd --userland-proxy','true','false','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','2.17','The userland proxy service increases the attack surface by adding another component to forward ports. While it''s not directly exploitable, it could potentially introduce new vulnerabilities that an attacker might leverage in certain circumstances.','Disable the userland proxy by setting ''dockerd --userland-proxy=false''.','value','always','','{"description": "The ''dockerd --userland-proxy'' directive enables a userland proxy service that increases the attack surface by adding another component to forward ports. This can potentially introduce new vulnerabilities that an attacker might leverage in certain circumstances.", "potential_impact": ["Unauthorized access to Docker containers", "Data exfiltration from Docker containers", "Disruption of Docker services"], "exploitation_scenario": {"prerequisites": ["Access to the host running Docker", "Knowledge of the forwarded ports"], "example": "An attacker can send a specially crafted HTTP request to the forwarded port to exploit potential vulnerabilities in the userland proxy.", "result": "The attacker gains unauthorized access to Docker containers, potentially leading to data exfiltration or disruption of Docker services."}, "metric_justifications": {"ac": "Enabling ''dockerd --userland-proxy=true'' creates an additional component that can be exploited if vulnerabilities are discovered. While it''s not trivial, it requires some knowledge and effort to find and exploit these vulnerabilities.", "c": "The userland proxy service may disclose information about the forwarded ports and Docker containers.", "i": "An attacker can potentially modify the configuration of the userland proxy service if vulnerabilities are discovered.", "a": "The availability of Docker services may be affected if the userland proxy is exploited.", "gel": "Exploitation frequency for this type of misconfiguration depends on the specific vulnerability and the attacker''s skill level.", "grl": "Remediation documentation for this issue is widely available, making it easier to address."}}','2026-06-24T22:35:42.450Z','2026-06-24T22:46:25.641Z');
INSERT INTO misconfigurations VALUES('355a0226-1df9-4f4c-8dc9-53d78a7226e1',6,'docker','runtime parameter to the Docker daemon','--experimental','','N','N','M','N','N','N',0.0,0.0,'ND','U','[]','','2.19','Enabling experimental features in Docker daemon may introduce unpredictable behavior or instability, but it does not directly expose sensitive information or provide attackers with additional privileges. However, since these features are not fully tested, they could potentially introduce vulnerabilities in the future.','Avoid using ''--experimental'' as a runtime parameter to the Docker daemon in production environments.','value','always','','{"description": "The runtime parameter ''--experimental'' to the Docker daemon enables experimental features that may introduce unpredictable behavior or instability in your system. These features are not fully tested and could potentially introduce vulnerabilities in the future.", "potential_impact": ["Potential introduction of unpredictable behavior or instability", "Potential exploitation of undiscovered vulnerabilities in experimental features", "Potential impact on application functionality due to unexpected behavior"], "exploitation_scenario": {"prerequisites": ["Access to the Docker daemon runtime parameters", "Knowledge of available experimental features"], "example": "Running ''docker run --experimental'' enables experimental features in the Docker daemon.", "result": "Experimental features may introduce unpredictable behavior or instability, potentially leading to application crashes or data loss."}, "metric_justifications": {"ac": "Enabling experimental features in Docker daemon may introduce unpredictable behavior or instability, but it does not directly expose sensitive information or provide attackers with additional privileges. However, since these features are not fully tested, they could potentially introduce vulnerabilities in the future.", "c": "No sensitive information is disclosed or readable as a result of this misconfiguration.", "i": "No data or configuration can be modified directly due to this misconfiguration.", "a": "Availability may be affected indirectly through potential application crashes or data loss caused by unpredictable behavior or instability introduced by experimental features.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires knowledge of available experimental features and access to the Docker daemon runtime parameters.", "grl": "Remediation documentation is readily available in resources such as the CIS Benchmark and CCSS."}}','2026-06-24T22:35:49.164Z','2026-06-24T22:46:46.417Z');
INSERT INTO misconfigurations VALUES('68ae3210-e4ca-495e-bf11-02b970be9c99',6,'docker','icc','true','false','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','2.2','With icc=''true'', all containers on the same host can potentially read packets across the container network, leading to unintended information disclosure. However, this misconfiguration does not directly allow arbitrary data modification or service disruption.','Set ''icc'': false in the Docker daemon configuration file or run dockerd with --icc=false as an argument.','value','always','','{"description": "Setting icc to true allows all containers on the same host to potentially read packets across the container network, leading to unintended information disclosure. This misconfiguration does not directly allow arbitrary data modification or service disruption.", "potential_impact": ["Unauthorized access to network traffic within the Docker host", "Potential for sensitive data exposure", "Compromised privacy of communication between containers"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host", "Understanding of Docker networking"], "example": "In a YAML Docker Compose file, setting ''icc: true'' under services section.", "result": "An attacker can potentially read network traffic between containers on the same host."}, "metric_justifications": {"ac": "With icc=''true'', an attacker requires write access to the Docker daemon configuration file or the ability to run dockerd with --icc=false as an argument, which presents a moderate barrier.", "c": "Setting icc to true allows containers on the same host to read packets across the container network, disclosing potentially sensitive information.", "i": "With icc=''true'', data can be read but not modified arbitrarily.", "a": "Availability is not directly affected by this misconfiguration.", "gel": "Exploitation frequency for this type of misconfiguration may vary depending on the security posture and access controls in place.", "grl": "Remediation documentation is readily available, as it involves setting icc to false."}}','2026-06-24T22:35:57.721Z','2026-06-24T22:47:04.873Z');
INSERT INTO misconfigurations VALUES('e80c41e4-c7c1-4f46-a855-141e38fb5533',6,'docker','log-level','insecure','info','N','N','L','N','N','N',0.0,0.0,'M','H','[]','','2.3','Setting log-level to ''insecure'' does not affect the security of the system directly, but it may lead to unnecessary logging noise that could potentially obscure important security events. However, in this case, since the default value is already ''info'', setting it to ''insecure'' has no impact.','Maintain the default log-level as ''info''.','value','always','','{"description": "Setting log-level to ''insecure'' in Docker may result in excessive logging noise that could potentially obscure important security events. The default value of ''info'' already provides a balance between verbosity and system performance.", "potential_impact": ["Obscuring important security events", "Increased system resource usage due to excessive logging"], "exploitation_scenario": {"prerequisites": ["Access to Docker configuration files"], "example": "Modifying the log-level in a Dockerfile or docker-compose.yml file to ''insecure''", "result": "Increased logging output, potentially obscuring important security events"}, "metric_justifications": {"ac": "Setting log-level to ''insecure'' is an easy exploit as it only requires modifying a configuration file.", "c": "No sensitive information is disclosed or readable due to the nature of log-level modification.", "i": "No data or configuration can be modified by changing the log-level.", "a": "Availability is not affected as system functionality remains unchanged.", "gel": "Exploitation of this misconfiguration is common due to its simplicity and potential impact on system performance and security visibility.", "grl": "Remediation documentation for this type of misconfiguration is widely available."}}','2026-06-24T22:36:06.440Z','2026-06-24T22:47:20.966Z');
INSERT INTO misconfigurations VALUES('0e88fae7-1892-4957-87bc-46a1715f9499',6,'docker','docker_insecure_registries','insecure','secure','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','2.5','Setting docker_insecure_registries=''insecure'' allows Docker to access unencrypted, insecure registries. This can lead to traffic interception and modification, potentially exposing sensitive data.','Set docker_insecure_registries=[] to only allow secure TLS-enabled registries.','value','always','','{"description": "The docker_insecure_registries directive is used to specify which registries Docker should access for pulling images. Setting it to ''insecure'' allows Docker to connect to unencrypted, insecure registries. This can lead to traffic interception and modification, potentially exposing sensitive data.", "potential_impact": ["Unauthorized access to Docker images", "Data exfiltration due to intercepted traffic", "Manipulation of pulled images leading to malware injection"], "exploitation_scenario": {"prerequisites": ["Access to the Docker configuration file", "Knowledge of the ''insecure'' value for docker_insecure_registries"], "example": "Example config snippet: docker_insecure_registries = [''insecure'']", "result": "An attacker can intercept and modify traffic between Docker and insecure registries, potentially gaining access to sensitive data or injecting malicious images."}, "metric_justifications": {"ac": "Setting docker_insecure_registries=''insecure'' allows Docker to access unencrypted, insecure registries. This can lead to traffic interception and modification, potentially exposing sensitive data. However, it requires write access to the Docker configuration file, making it a moderate barrier.", "c": "Insecure registries do not encrypt traffic, allowing an attacker to read all transmitted data.", "i": "An attacker can modify images pulled from insecure registries, potentially injecting malware or other malicious content.", "a": "The availability of Docker services is not directly affected by this misconfiguration.", "gel": "Exploitation frequency for this type of misconfiguration may be low as long as the configuration file is properly secured.", "grl": "Remediation documentation is widely available, but effective implementation requires understanding and proper configuration."}}','2026-06-24T22:36:15.443Z','2026-06-24T22:47:38.290Z');
INSERT INTO misconfigurations VALUES('5b9bf68e-44fa-4aac-a6bb-d2caf438d950',6,'docker','docker storage driver','aufs','','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','2.6','Using aufs as the Docker storage driver can lead to kernel crashes and is not a supported driver in many modern Linux distributions. While it does allow container sharing of executable and shared libraries, this should be reviewed according to your organization''s security policy.','Do not explicitly use aufs as the Docker storage driver. Use the recommended storage driver by your preferred vendor and ensure it aligns with your organization''s security policy.','value','always','','{"description": "Using aufs as the Docker storage driver can lead to kernel crashes and is not a supported driver in many modern Linux distributions. This misconfiguration may allow container sharing of executable and shared libraries, which could potentially impact the security posture of your system.", "potential_impact": ["Kernel crashes leading to system instability", "Potential data leakage due to shared libraries", "Container escape via shared libraries"], "exploitation_scenario": {"prerequisites": ["Access to the Docker configuration file", "Knowledge of aufs as a Docker storage driver"], "example": "Modifying the Docker daemon configuration file to set the storage driver to ''aufs''", "result": "Kernel crashes and potential container escape"}, "metric_justifications": {"ac": "Requires knowledge of aufs as a Docker storage driver and write access to the Docker daemon configuration file, which presents a moderate barrier for an unauthenticated attacker.", "c": "No sensitive information is disclosed or readable due to the use of aufs.", "i": "The system''s stability can be modified by setting the Docker storage driver to ''aufs''.", "a": "Availability is affected as kernel crashes may lead to system instability.", "gel": "Exploitation frequency for this type of misconfiguration is low due to aufs not being a commonly used or recommended Docker storage driver.", "grl": "Remediation documentation is readily available in the CIS Benchmark and other security resources."}}','2026-06-24T22:36:26.143Z','2026-06-24T22:47:55.408Z');
INSERT INTO misconfigurations VALUES('bf3bdcca-a4d5-4ebc-bddc-6d2519160448',6,'docker','docker_storage_driver','devicemapper','','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','2.7','Using devicemapper as the storage driver for Docker is deprecated and has been removed in Docker Engine v25.0. Continuing to use it may prevent upgrading to newer versions, causing potential security vulnerabilities or compatibility issues.','Do not explicitly set docker_storage_driver to ''devicemapper''. Use the storage driver recommended by your preferred vendor and in line with your policy.','value','always','','{"description": "The docker_storage_driver set to ''devicemapper'' is deprecated and may prevent upgrading to newer Docker Engine versions, potentially exposing security vulnerabilities or compatibility issues. It is recommended to use a different storage driver as per your preferred vendor''s recommendations.", "potential_impact": ["Potential exposure to known and unknown security vulnerabilities in older Docker Engine versions", "Compatibility issues with newer Docker Engine versions", "Inability to apply critical updates and patches"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host or container", "Knowledge of the current Docker storage driver configuration"], "example": "Example config snippet: ''storage-driver: devicemapper''.", "result": "Successful exploitation could lead to security vulnerabilities, compatibility issues, and inability to apply critical updates."}, "metric_justifications": {"ac": "Using devicemapper as the storage driver requires knowledge of the current Docker configuration and access to the Docker host or container. This represents a moderate barrier for an attacker.", "c": "No sensitive information is disclosed by using devicemapper as the storage driver.", "i": "Modifying the storage driver configuration could potentially affect the overall system''s security and compatibility.", "a": "The availability of the Docker host or container may be affected if the storage driver configuration is modified incorrectly.", "gel": "Exploitation frequency for this type of misconfiguration is low due to its deprecated nature and the need for specific knowledge and access.", "grl": "Remediation documentation is readily available in Docker''s official documentation."}}','2026-06-24T22:36:35.114Z','2026-06-24T22:48:15.571Z');
INSERT INTO misconfigurations VALUES('110b976c-0cd4-4e44-9361-783bf8cfcd6b',6,'docker','tls','insecure','secure','N','N','M','P','N','N',4.29999999999999982,3.89999999999999991,'H','U','[]','','2.8','Setting tls=''insecure'' disables TLS authentication for the Docker daemon, making it accessible to any remote attacker who can connect to the specified IP/port. This increases the risk of unauthorized access and potential system compromise.','Configure TLS authentication by following the Docker documentation or other references.','value','always','','{"description": "Setting tls to ''insecure'' disables TLS authentication for the Docker daemon, making it accessible to any remote attacker who can connect to the specified IP/port. This increases the risk of unauthorized access and potential system compromise.", "potential_impact": ["Unauthorized access to the Docker daemon", "Potential data exfiltration", "Potential system compromise leading to further attacks"], "exploitation_scenario": {"prerequisites": ["Knowledge of the IP/port where the Docker daemon is running", "Ability to connect to the specified IP/port"], "example": "Config snippet: `docker run -d --restart=unless-stopped -p 2375:2375 -e TLS=insecure docker`, HTTP request: `curl -v http://<IP>:2375/v1.24/containers/json`", "result": "Access to the Docker daemon without authentication, allowing an attacker to execute commands, manipulate containers, and potentially gain access to sensitive data"}, "metric_justifications": {"ac": "Requires knowledge of the IP/port where the Docker daemon is running and ability to connect to it. This represents a moderate barrier for an attacker.", "c": "Discloses information about the running containers, images, and other system details.", "i": "Allows modification of container configurations, execution of commands, and potential data manipulation.", "a": "Availability is affected as unauthorized access can lead to service disruption or denial-of-service attacks.", "gel": "Exploitation frequency for this type of misconfiguration is high due to the ease of discovering insecure TLS configurations.", "grl": "Remediation documentation is widely available, such as Docker''s official documentation on securing the daemon."}}','2026-06-24T22:36:44.029Z','2026-06-24T22:48:37.446Z');
INSERT INTO misconfigurations VALUES('a59d062c-d497-4350-93e2-8d5266dc49a5',6,'docker','dockerd --default-ulimit','','--default-ulimit nproc=1024:2048 --default-ulimit nofile=100:200','N','N','M','P','N','P',5.79999999999999982,4.90000000000000035,'L','U','[]','','2.9','Setting no default ulimit for Docker allows containers to consume unlimited system resources, potentially causing gradual degradation or even a denial of service condition. This is CAT II — resource exhaustion.','Set appropriate resource limits using ''dockerd --default-ulimit nproc=1024:2048 --default-ulimit nofile=100:200'' or similar, as per your security policy.','value','always','','{"description": "The ''dockerd --default-ulimit'' directive sets system resource limits for Docker containers by default. Using an unspecified value allows containers to consume unlimited resources, potentially causing gradual degradation or even a denial of service condition.", "potential_impact": ["Resource exhaustion leading to performance degradation", "Potential for container-based Denial of Service (DoS) attacks", "Long-term impact on system stability and availability"], "exploitation_scenario": {"prerequisites": ["Unspecified ''dockerd --default-ulimit'' value", "Running Docker containers with unlimited resource limits"], "example": "For example, a container running without specified resource limits can consume all available CPU or memory resources, causing other processes to slow down or fail.", "result": "The result is a gradual degradation of system performance and potential Denial of Service conditions."}, "metric_justifications": {"ac": "Setting no default ulimit for Docker allows containers to consume unlimited system resources, potentially causing gradual degradation or even a denial of service condition. This is CAT II — resource exhaustion.", "c": "No sensitive information is disclosed by this misconfiguration.", "i": "Containers can modify system resources such as CPU and memory without limits.", "a": "Availability is affected due to potential Denial of Service conditions caused by unlimited resource consumption.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, depending on the specific Docker environment and workload.", "grl": "Remediation documentation is widely available in resources such as CIS Benchmark section 2.9 and CCSS BaseScore 5.8."}}','2026-06-24T22:36:52.243Z','2026-06-24T22:48:54.419Z');
INSERT INTO misconfigurations VALUES('41c03d2d-8010-49c9-8f08-a3716c3c3c4e',6,'docker','secrets_storage_in_dockerfiles','stored','not_stored','N','N','L','P','P','N',6.40000000000000035,6.0,'L','H','[]','','4.10','Access control misconfiguration.','Apply deny-by-default.','value','always','','{"description": "The directive ''secrets_storage_in_dockerfiles'' specifies whether sensitive information such as API keys and passwords are stored in Dockerfiles. A value of ''stored'' indicates that these secrets are included directly within the Dockerfile, which is a security risk. This practice can lead to unintended exposure of sensitive data during image builds or when sharing images.", "potential_impact": ["Exposure of sensitive information", "Unauthorized access to resources protected by these secrets", "Compromised build environment due to leaked credentials"], "exploitation_scenario": {"prerequisites": ["Access to the Dockerfile or built image"], "example": "For example, a Dockerfile containing a hardcoded API key: `FROM alpine\nRUN echo ''API_KEY=mysecretkey'' >> /etc/environment`", "result": "An attacker can extract the sensitive information by inspecting the built image or analyzing the Dockerfile."}, "metric_justifications": {"ac": "Why AC=L: Storing secrets in Dockerfiles is an easy exploit as it only requires reading the Dockerfile or inspecting the built image. No special preconditions beyond access are needed.", "c": "Why C=P: Sensitive information such as API keys and passwords can be disclosed.", "i": "Why I=P: The configuration of the Dockerfile, including secrets, can be modified.", "a": "Why A=N: Availability is not affected as the system remains operational, but sensitive data may be compromised.", "gel": "Why GEL=L: This type of misconfiguration is common and easy to exploit by attackers.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available, but it requires careful attention during the development process."}}','2026-06-24T22:37:15.161Z','2026-06-24T22:49:15.245Z');
INSERT INTO misconfigurations VALUES('804e6e50-c72c-4db9-858b-28085183f90c',6,'docker','package_distribution_mechanism','insecure','secure','N','N','M','N','N','N',0.0,0.0,'H','U','[]','','4.11','Using ''insecure'' package distribution mechanism can lead to the installation of malicious or vulnerable packages, potentially compromising the system. A secure package manager should be used for authenticity verification.','Use a secure package manager like yum-utils''s ''yum-config-manager --enableplugin=protected_package'', apt-transport-https for Debian-based systems, or Homebrew''s --cask option for macOS.','value','always','','{"description": "The ''package_distribution_mechanism'' directive specifies how packages are distributed within Docker containers. Using an ''insecure'' mechanism can lead to the installation of malicious or vulnerable packages, potentially compromising the system.", "potential_impact": ["Unauthorized access to sensitive data", "Disruption of service due to malicious package execution", "Exposure to known vulnerabilities in installed packages"], "exploitation_scenario": {"prerequisites": ["Access to the Dockerfile or container configuration", "Knowledge of an unsecured package repository URL"], "example": "Example: Using ''docker pull from insecure-registry.example.com/myimage'' instead of ''docker pull myimage from a trusted registry''", "result": "Malicious or vulnerable packages are installed, potentially leading to system compromise"}, "metric_justifications": {"ac": "Using an insecure package distribution mechanism requires knowledge of an unsecured repository and the ability to modify the Dockerfile or container configuration. This presents a moderate barrier for an attacker.", "c": "No sensitive information is disclosed by using an insecure package distribution mechanism, but it does increase the risk of exposing such data through vulnerable packages.", "i": "The insecure package distribution mechanism allows for the installation of unauthorized and potentially malicious packages, which can modify container configuration or data.", "a": "Availability is not directly affected by using an insecure package distribution mechanism, but disruptions may occur due to malicious package execution or vulnerabilities.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as attackers can easily find unsecured package repositories and use them for malicious purposes.", "grl": "Remediation documentation is widely available, as using a secure package distribution mechanism is a common best practice in Docker security."}}','2026-06-24T22:37:27.410Z','2026-06-24T22:49:34.601Z');
INSERT INTO misconfigurations VALUES('15346c51-5146-4ab4-9f12-3c235e8512fd',6,'docker','artifact_validation','insecure','secure','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','4.12','Setting artifact_validation=''insecure'' disables signature validation, allowing unsigned or tampered artifacts to be uploaded. This weakens trust in the package registry and may lead to unintended execution of malicious code.','Set ''artifact_validation=secure'' to ensure all artifacts are signed and validated before uploading.','value','always','','{"description": "Setting artifact_validation to ''insecure'' disables signature validation for Docker images, allowing unsigned or tampered images to be uploaded. This weakens trust in the package registry and may lead to unintended execution of malicious code.", "potential_impact": ["Unauthorized image upload", "Execution of malicious code", "Compromised container security"], "exploitation_scenario": {"prerequisites": ["Access to the Docker registry with write permissions"], "example": "docker login (registry) && docker tag (image) (new-registry)/(image):insecure", "result": "The uploaded image bypasses signature validation and can be executed without verification."}, "metric_justifications": {"ac": "Requires write access to the Docker registry, an additional precondition. This makes exploitation possible but not trivial.", "c": "No sensitive information is disclosed or readable as a result of this misconfiguration.", "i": "Allows for unauthorized image upload and execution of malicious code.", "a": "Availability of the Docker registry and its services may be affected if the registry is compromised.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires write access to the registry.", "grl": "Remediation documentation is widely available, making it relatively easy to find solutions."}}','2026-06-24T22:37:38.474Z','2026-06-24T22:49:50.456Z');
INSERT INTO misconfigurations VALUES('3cd1e1fb-ad5e-4969-bfd1-64a5d33acb5f',6,'docker','unnecessary_packages','','minimal_base_image','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','4.3','Installing unnecessary packages increases the attack surface of a container, potentially exposing vulnerabilities that could be exploited. However, in this case, since no specific package is mentioned, the immediate impact is none.','To minimize the attack surface, only install necessary software packages. Consider using minimal base images like BusyBox or Alpine instead of standard Centos, Debian, or Red Hat images.','value','always','','{"description": "The unnecessary_packages directive refers to installing additional software packages beyond those required for the intended functionality of the container. This practice increases the attack surface and potentially exposes vulnerabilities that could be exploited.", "potential_impact": ["Unnecessary packages may contain known or unknown vulnerabilities, increasing the risk of unauthorized access or data breaches.", "Excessive package installations can lead to increased resource consumption, potentially impacting container performance and stability."], "exploitation_scenario": {"prerequisites": ["An attacker must have access to the container or host system where the unnecessary packages are installed."], "example": "For instance, an attacker could exploit a known vulnerability in an unused package to gain unauthorized access to the container.", "result": "The result of successful exploitation could be data theft, unauthorized modification of container configuration, or denial of service."}, "metric_justifications": {"ac": "Unnecessary packages increase the complexity and potential attack vectors for an attacker. While not trivial, it requires knowledge of the specific unnecessary packages installed and their associated vulnerabilities.", "c": "No sensitive information is disclosed or readable due to the absence of specific package details.", "i": "Data or configuration can be modified if the attacker exploits a vulnerability in an unnecessary package.", "a": "Availability may be affected if the unnecessary packages consume excessive resources, leading to performance degradation or instability.", "gel": "Exploitation frequency for this type of misconfiguration is moderate due to the need for specific knowledge about the unnecessary packages and their associated vulnerabilities.", "grl": "Remediation documentation availability is high as it involves removing unnecessary packages and using minimal base images."}}','2026-06-24T22:37:47.021Z','2026-06-24T22:50:10.849Z');
INSERT INTO misconfigurations VALUES('814e2eed-9d8b-427b-8736-b9d3163925e0',6,'docker','image_update','not updated automatically','updated','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','4.4','Not updating images automatically means that containers may run on outdated base images, which could contain known vulnerabilities. However, since no information disclosure or modification is possible without further exploitation, the confidentiality and integrity impacts are None.','Update images automatically to ensure they include the latest security patches.','value','always','','{"description": "The ''image_update'' directive specifies whether Docker images are updated automatically. Setting it to ''not updated automatically'' means that containers may run on outdated base images, which could contain known vulnerabilities.", "potential_impact": ["Containers may run with known vulnerabilities in their base images", "Exposure to potential security breaches", "Potential data leakage or unauthorized modifications if a container is compromised"], "exploitation_scenario": {"prerequisites": ["An attacker must have access to the Docker host or network where the containers are running", "Knowledge of the specific vulnerability in the outdated image"], "example": "For example, an attacker could exploit a known vulnerability in an outdated base image by crafting a malicious container that takes advantage of this vulnerability when run.", "result": "The result would be unauthorized access to the container or host, potentially leading to data theft or system compromise"}, "metric_justifications": {"ac": "Requires an attacker to have knowledge of a specific vulnerability in an outdated image and access to the Docker host or network where the containers are running. This represents a moderate barrier (write access needed, network position, etc).", "c": "No sensitive information is disclosed as a result of this misconfiguration.", "i": "Data or configuration can be modified if a container is compromised due to the use of an outdated image with known vulnerabilities.", "a": "Availability may be affected if a container or host is compromised and taken offline.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires knowledge of specific vulnerabilities in outdated images.", "grl": "Remediation documentation availability is high, as updating Docker images automatically is a common best practice."}}','2026-06-24T22:37:54.353Z','2026-06-24T22:50:27.061Z');
INSERT INTO misconfigurations VALUES('b9d9ec43-58de-4e71-86a5-cdf49753dda6',6,'docker','DOCKER_CONTENT_TRUST','0','1','N','N','M','N','N','N',0.0,0.0,'ND','H','[]','','4.5','With DOCKER_CONTENT_TRUST=''0'', content trust for Docker is disabled, which means images pulled from the public Docker Hub won''t be verified. This could potentially lead to using untrusted images, posing a risk of supply-chain attacks.','Set DOCKER_CONTENT_TRUST=1 to enable content trust for Docker and ensure that images are verified before use.','value','always','','{"description": "With DOCKER_CONTENT_TRUST=''0'', content trust for Docker is disabled, which means images pulled from the public Docker Hub won''t be verified. This could potentially lead to using untrusted images, posing a risk of supply-chain attacks.", "potential_impact": ["Unauthorized access to sensitive data", "Disruption of service due to malicious code execution", "Data exfiltration or manipulation"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host", "Knowledge of DOCKER_CONTENT_TRUST configuration"], "example": "Setting DOCKER_CONTENT_TRUST=0 in the Docker daemon configuration file (daemon.json)", "result": "Pulling and using unverified images from the public Docker Hub"}, "metric_justifications": {"ac": "With DOCKER_CONTENT_TRUST=0, an attacker with access to the Docker host can pull and use unverified images, posing a moderate risk of supply-chain attacks.", "c": "DOCKER_CONTENT_TRUST=0 discloses that content trust is disabled, making it easier for an attacker to identify vulnerable systems.", "i": "DOCKER_CONTENT_TRUST=0 allows the use of unverified images, which can be modified to include malicious code or data.", "a": "DOCKER_CONTENT_TRUST=0 does not directly affect the availability of the system, but using unverified images could lead to service disruptions.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires access to the Docker host and knowledge of the configuration.", "grl": "Remediation documentation for this issue is widely available, making it easy for security engineers to address."}}','2026-06-24T22:38:04.631Z','2026-06-24T22:50:49.544Z');
INSERT INTO misconfigurations VALUES('1a413230-4460-4914-a5e8-4dd06b98184a',6,'docker','Dockerfile ADD instruction','ADD','COPY','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','4.9','Using ADD in Dockerfiles can potentially download files from remote URLs without proper scanning, introducing security risks such as malware or vulnerabilities associated with decompression. However, the impact is limited to container content, not the host system.','Replace ''ADD'' with ''COPY'' in Dockerfiles.','value','always','','{"description": "The Dockerfile ADD instruction allows downloading files from remote URLs during container build, potentially introducing security risks such as malware or vulnerabilities associated with decompression. The use of ''ADD'' can bypass some security scanning steps, making it dangerous.", "potential_impact": ["Potential introduction of malicious code into the container", "Potential exposure of sensitive data during download", "Potential exploitation of vulnerabilities in downloaded files"], "exploitation_scenario": {"prerequisites": ["Access to a Dockerfile using ''ADD'' instruction", "Internet connection for remote file download"], "example": "Example: `ADD http://example.com/malware.tar.gz /app/`, which downloads malware.tar.gz from example.com and extracts it into /app/", "result": "The container will be infected with malware or vulnerable to exploitation, potentially compromising the entire application."}, "metric_justifications": {"ac": "Using ''ADD'' in Dockerfiles can potentially download files from remote URLs without proper scanning, introducing security risks. However, the impact is limited to container content, not the host system. This meets the criteria for AC=M as it requires write access to the web root, an additional precondition.", "c": "The ''ADD'' instruction can disclose sensitive data during download if the remote URL points to a malicious server or a repository containing sensitive files.", "i": "The ''ADD'' instruction allows modification of container content by downloading and extracting files from remote URLs.", "a": "The availability of the application running in the container may be affected if it is compromised due to the use of ''ADD''.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires an attacker to find a Dockerfile using ''ADD'' and a suitable remote URL.", "grl": "Remediation documentation for this issue is widely available, making it easier for developers to address."}}','2026-06-24T22:38:11.126Z','2026-06-24T22:51:12.225Z');
INSERT INTO misconfigurations VALUES('d7c4b0cd-7ff8-46ab-a283-781d11a4ded1',6,'docker','swarm mode','','disabled','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','5.1','Enabling swarm mode opens multiple network ports, increasing the attack surface. Without it, Docker engine instances only communicate over a Unix socket, reducing potential vulnerabilities.','If not needed, disable swarm mode by running ''docker swarm leave''.','value','always','','{"description": "Enabling Docker Swarm mode opens multiple network ports, increasing the attack surface and potential vulnerabilities. Without it, Docker engine instances only communicate over a Unix socket, reducing potential attacks.", "potential_impact": ["Unauthorized access to cluster management", "Data exfiltration through exposed services", "Disruption of service due to swarm-related attacks"], "exploitation_scenario": {"prerequisites": ["Knowledge of Docker Swarm commands", "Access to the Docker host or container"], "example": "''docker swarm init'' command initiates a swarm, opening network ports.", "result": "An attacker can manipulate the cluster, access sensitive data, or disrupt services."}, "metric_justifications": {"ac": "Enabling Swarm mode requires configuration changes and understanding of Docker Swarm functionality. This introduces a moderate barrier for an unauthorized user.", "c": "Swarm mode exposes network ports, potentially disclosing information about the cluster''s services and nodes.", "i": "With Swarm mode enabled, an attacker can manipulate the cluster configuration or access sensitive data.", "a": "Swarm mode does not directly affect the availability of individual containers but may disrupt the entire swarm if exploited.", "gel": "Exploitation of this misconfiguration is not common due to its specificity and requirement for knowledge about Docker Swarm.", "grl": "Remediation documentation for disabling Swarm mode is readily available."}}','2026-06-24T22:38:18.121Z','2026-06-24T22:51:27.548Z');
INSERT INTO misconfigurations VALUES('5ba5acf7-3c26-4216-99ca-6f1d6a743278',6,'docker','--net','host','','N','N','H','N','N','C',5.40000000000000035,4.90000000000000035,'ND','U','[]','','5.10','Setting --net=host allows the container to have full access to the host''s network interfaces and run as if it were a root process on the host. This can potentially lead to undesired actions such as shutting down the Docker host or opening reserved low numbered ports, posing a significant security risk.','Do not use --net=host when starting any container. Instead, let containers connect to the Docker bridge by default.','value','always','','{"description": "Setting --net=host allows the container to have full access to the host''s network interfaces and run as if it were a root process on the host. This can potentially lead to undesired actions such as shutting down the Docker host or opening reserved low numbered ports, posing a significant security risk.", "potential_impact": ["Unauthorized access to host''s network interfaces", "Potential for data exfiltration", "DDoS attacks from the container"], "exploitation_scenario": {"prerequisites": ["Container privileged mode is enabled", "The container has been started with --net=host"], "example": "Starting a container with: docker run --privileged --net=host myimage", "result": "The container gains full network access to the host and can perform actions such as shutting down the Docker host or opening reserved ports."}, "metric_justifications": {"ac": "Requires a complex multi-step chain of prerequisites, including enabling privileged mode and explicitly setting --net=host. This makes exploitation more difficult but still possible for an attacker with knowledge of Docker configuration.", "c": "No sensitive information is disclosed or readable by default due to the container''s isolation, but the potential for data exfiltration exists if the container is compromised.", "i": "The container can modify any file on the host that it has access to, including system files and configuration, posing a risk to the overall system integrity.", "a": "Availability is affected as the container can potentially shut down the Docker host or disrupt network services.", "gel": "Exploitation frequency for this type of misconfiguration is relatively low, but it can be exploited by an attacker with knowledge of Docker configuration and privileged access to the host.", "grl": "Remediation documentation is widely available in resources such as CIS Benchmark and CCSS."}}','2026-06-24T22:38:27.401Z','2026-06-24T22:51:48.608Z');
INSERT INTO misconfigurations VALUES('bc1abe77-15d2-499a-a5dc-8ab69a68c940',6,'docker','docker run --cpu-shares','not set or not specified','<appropriate value based on container priority>','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.12','By not setting CPU shares, containers share resources equally by default. This can lead to resource contention and potential performance issues for high-priority containers if they require more CPU time.','Set appropriate CPU shares using the ''--cpu-shares'' option when running Docker containers.','value','always','','{"description": "The Docker directive ''docker run --cpu-shares'' is used to allocate CPU resources among containers. Not setting this value results in equal resource sharing by default, which can lead to performance issues for high-priority containers due to potential resource contention.", "potential_impact": ["Performance degradation for high-priority containers", "Increased response times and delays", "Potential application instability or downtime"], "exploitation_scenario": {"prerequisites": ["Running multiple Docker containers with varying priorities", "Lack of explicit CPU share allocation"], "example": "For example, running a container without specifying CPU shares: `docker run my-image`", "result": "As a result, high-priority containers may experience performance issues due to resource contention with other containers."}, "metric_justifications": {"ac": "By not setting CPU shares, an attacker does not need any specific privileges or knowledge beyond running Docker containers. However, the impact is moderate as it requires a multi-container environment and proper understanding of container priorities.", "c": "No sensitive information is disclosed due to this misconfiguration.", "i": "No configuration can be directly modified as a result of this misconfiguration.", "a": "Container availability remains unaffected, but performance issues may cause temporary service interruptions.", "gel": "This type of misconfiguration is relatively common in multi-container Docker environments, making it exploitable with moderate frequency.", "grl": "Remediation documentation for this issue is widely available and easy to find."}}','2026-06-24T22:38:36.033Z','2026-06-24T22:52:06.876Z');
INSERT INTO misconfigurations VALUES('46ac7db6-98eb-4af3-929f-de4126d9b3f6',6,'docker','bind','0.0.0.0','specific host interface','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.14','Binding container traffic to ''0.0.0.0'' allows connections from any network interface on the host machine, potentially bypassing security measures such as firewalls and intrusion detection systems intended for specific interfaces.','Bind the container port to a specific host interface using --publish or --expose options in Docker commands.','value','always','','{"description": "Binding container traffic to ''0.0.0.0'' allows connections from any network interface on the host machine, potentially bypassing security measures such as firewalls and intrusion detection systems intended for specific interfaces.", "potential_impact": ["Unauthorized access to the container", "Data exfiltration", "Denial of Service attacks"], "exploitation_scenario": {"prerequisites": ["Access to the host machine", "Knowledge of Docker and its network configuration"], "example": "For example, a malicious user could exploit this misconfiguration by running a container with bind set to ''0.0.0.0'' and then connecting to it from an unauthorized IP address.", "result": "The result would be unauthorized access to the container, potentially leading to data exfiltration or Denial of Service attacks."}, "metric_justifications": {"ac": "Why AC=M: Binding to ''0.0.0.0'' allows connections from any network interface on the host machine, requiring a specific understanding of Docker networking and access to the host machine.", "c": "Why C=N: No sensitive information is disclosed or readable as a result of this misconfiguration.", "i": "Why I=N: No data or configuration can be modified directly due to this misconfiguration, but unauthorized access could lead to data manipulation.", "a": "Why A=N: The availability of the system is not affected by this misconfiguration, but unauthorized access could lead to Denial of Service attacks.", "gel": "Why GEL=L: This type of misconfiguration is relatively common due to its ease of occurrence and potential for exploitation.", "grl": "Why GRL=H: Remediation documentation is widely available, but effective implementation requires understanding of Docker networking."}}','2026-06-24T22:38:42.833Z','2026-06-24T22:52:26.259Z');
INSERT INTO misconfigurations VALUES('36f4884e-90d6-4333-9d68-2ab4cde802c1',6,'docker','restart_policy','not set or not ''on-failure:5''','''on-failure:5''','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','5.15','Setting the restart policy to ''on-failure:5'' limits the number of attempts to restart a container, preventing potential denial-of-service attacks and distributed denial-of-service attacks. Without this setting, containers may indefinitely attempt to restart, potentially leading to service disruptions.','Set ''--restart=on-failure:5'' when running the container.','value','always','','{"description": "The ''restart_policy'' directive determines how Docker handles container restarts in case of failure. Not setting it or using a value other than ''on-failure:5'' can lead to potential denial-of-service attacks and service disruptions due to unlimited attempts at container restart.", "potential_impact": ["Potential for prolonged service disruptions", "Increased resource consumption leading to system instability", "Possibility of a distributed denial-of-service attack if multiple containers are affected"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host or container", "Knowledge of the container''s name or ID"], "example": "Example Docker run command: `docker run -d --restart=on-failure:5 my_container` (with no restart policy, the command would be `docker run -d my_container`)", "result": "The container will attempt to restart up to 5 times upon failure, preventing potential service disruptions due to a single failure."}, "metric_justifications": {"ac": "Setting ''restart_policy'' to not set or not ''on-failure:5'' requires no additional prerequisites, making it moderately easy for an attacker to exploit.", "c": "No sensitive information is disclosed by this misconfiguration.", "i": "Data and configuration can be modified if the container is restarted indefinitely, potentially leading to service disruptions.", "a": "Availability is affected as containers may not recover from failures without a proper restart policy.", "gel": "Exploitation frequency for this type of misconfiguration is moderate due to its simplicity.", "grl": "Remediation documentation is widely available, making it relatively easy to address."}}','2026-06-24T22:38:52.023Z','2026-06-24T22:52:44.954Z');
INSERT INTO misconfigurations VALUES('5ae89a65-b1d3-4641-8f89-33d7bc9798ad',6,'docker','docker_run_pid_host','present','absent','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','5.16','Sharing the host''s process namespace with containers allows a malicious user in a container to see all processes on the host, potentially manipulate them or even shut down the host. This could be serious, particularly in multi-tenanted environments.','Do not start a container with --pid=host. Instead, use ''docker run'' without the --pid=host argument.','value','always','','{"description": "The ''docker run'' command with ''--pid=host'' directive set to ''present'' allows a container to share the host''s process namespace. This can expose all processes on the host, potentially enabling manipulation or even shutdown of the host.", "potential_impact": ["Unauthorized access to host processes", "Potential data breaches due to manipulated processes", "Host system instability or downtime due to process manipulation"], "exploitation_scenario": {"prerequisites": ["Access to a container on the host", "Knowledge of Docker and its command-line interface"], "example": "Running ''docker run --pid=host myimage'' exposes the host''s process namespace to the container.", "result": "The container can view, manipulate, or even terminate processes on the host."}, "metric_justifications": {"ac": "Sharing the host''s process namespace with containers allows a malicious user in a container to see all processes on the host, potentially manipulate them or even shut down the host. This could be serious, particularly in multi-tenanted environments.", "c": "The presence of ''--pid=host'' discloses all host processes to the container.", "i": "With access to host processes, a malicious user can modify system settings or data.", "a": "Availability is affected as a malicious user could potentially shut down the host.", "gel": "Exploitation frequency for this type of misconfiguration is moderate due to its potential impact.", "grl": "Remediation documentation is high as it involves understanding Docker''s process isolation features."}}','2026-06-24T22:39:01.052Z','2026-06-24T22:53:03.688Z');
INSERT INTO misconfigurations VALUES('0129ccf4-877a-483f-ae08-e120edd9632e',6,'docker','docker run command','/dev/tty0:/dev/tty0:rwm -- device=/dev/temp_sda:/dev','','N','N','M','P','C','C',9.0,8.09999999999999964,'H','U','[]','','5.18','Exposing host devices to containers with read-write-mknod permissions allows containers to directly access and manipulate these devices, potentially causing data loss or system instability. In this case, the misconfiguration exposes both a tty device and a block device, posing a significant threat.','Avoid exposing host devices to containers directly. If necessary, use granular permissions (read-only or read-write) as appropriate for your organization''s needs.','value','always','','{"description": "Exposing host devices to containers with read-write-mknod permissions allows containers to directly access and manipulate these devices, potentially causing data loss or system instability. In this case, the misconfiguration exposes both a tty device (/dev/tty0) and a block device (/dev/temp_sda), posing a significant threat.", "potential_impact": ["Data loss due to unauthorized modification of host devices", "System instability caused by container manipulation of host devices", "Potential for privilege escalation within the container"], "exploitation_scenario": {"prerequisites": ["Container execution with read-write-mknod permissions on host devices", "Knowledge of specific device names (/dev/tty0 and /dev/temp_sda)"], "example": "/docker run -it --device=/dev/tty0:/dev --device=/dev/temp_sda:/dev image-name", "result": "Container gains direct access to host devices, allowing for data manipulation and potential system instability"}, "metric_justifications": {"ac": "Exposing host devices with read-write-mknod permissions requires write access to the web root, an additional precondition. However, once achieved, it allows for significant container control, justifying a Medium (M) Access Complexity score.", "c": "The misconfiguration exposes sensitive host device information, such as tty and block device names, increasing the Confidentiality impact.", "i": "By exposing these devices with read-write-mknod permissions, containers can modify data on the host system, increasing the Integrity impact.", "a": "The misconfiguration does not directly affect availability, but potential data loss or system instability could indirectly impact it. Therefore, Availability impact is considered Low (L).", "gel": "Exploitation of this type of misconfiguration is relatively common among attackers with moderate knowledge, justifying a High (H) Exploitability Level.", "grl": "Remediation documentation for this issue is widely available and easy to find, justifying a Low (L) Reported Vulnerabilities Level."}}','2026-06-24T22:39:08.933Z','2026-06-24T22:53:27.706Z');
INSERT INTO misconfigurations VALUES('90c2587d-c009-48a4-9fb9-0394c6cd3590',6,'docker','ulimit','default (no override)','overridden as needed','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','5.19','Overriding the default ulimit settings can lead to resource exhaustion by individual containers, potentially causing system-wide degradation or unresponsiveness. However, in this case, not overriding the default ulimit (default ''no override'') means that the container will inherit the Docker daemon''s ulimit settings.','If specific resource limits are required for a container instance, override the default ulimit settings as needed. For example: `docker run -ti -d --ulimit nofile=1024:1024 centos sleep 1000`','value','always','','{"description": "The default ulimit setting in Docker allows containers to inherit the host''s resource limits, potentially leading to resource exhaustion and system-wide degradation or unresponsiveness. Overriding these settings is recommended for better control over container resource usage.", "potential_impact": ["Resource exhaustion causing system instability", "Container misbehavior due to insufficient resources", "Potential denial of service for other containers"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host", "Knowledge of default ulimit settings"], "example": "Running a container without overriding the default ulimit: `docker run -ti -d centos sleep 1000`", "result": "The container consumes resources according to the host''s default ulimit, potentially causing system-wide issues."}, "metric_justifications": {"ac": "Overriding the default ulimit settings can lead to resource exhaustion by individual containers, potentially causing system-wide degradation or unresponsiveness. However, in this case, not overriding the default ulimit (default ''no override'') means that the container will inherit the Docker daemon''s ulimit settings.", "c": "No sensitive information is disclosed by default ulimit.", "i": "No configuration can be modified directly through ulimit.", "a": "Availability is affected as resource exhaustion can lead to system instability.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, depending on the specific resources and container workload.", "grl": "Remediation documentation is widely available in Docker''s official documentation."}}','2026-06-24T22:39:20.987Z','2026-06-24T22:53:46.519Z');
INSERT INTO misconfigurations VALUES('9ee73375-b407-4340-9f68-773336ad2b1e',6,'docker','docker run argument','--uts=host','','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.21','Setting --uts=host allows containers to change the hostname, which is not in line with good security practice. While this doesn''t directly impact confidentiality or integrity, it can lead to potential confusion and misidentification of the host.','Avoid using ''--uts=host'' when starting a container. Instead, use the default behavior where containers have their own UTS namespace isolated from the host.','value','always','','{"description": "Setting --uts=host during Docker run allows containers to change the hostname, which can lead to potential confusion and misidentification of the host. This is not in line with good security practice.", "potential_impact": ["Potential for misidentification of the host", "Possible confusion in system logs and monitoring tools", "Increased difficulty in managing and securing multiple containers"], "exploitation_scenario": {"prerequisites": ["An attacker must have the ability to run Docker commands on the host"], "example": "Example command: `docker run --uts=host myimage`", "result": "The container''s UTS namespace is merged with the host, allowing the container to change the hostname"}, "metric_justifications": {"ac": "Requires an attacker to have Docker privileges on the host. While this is not a trivial requirement, it does present a moderate barrier.", "c": "No sensitive information is disclosed or readable", "i": "Allows modification of the hostname, which can lead to potential confusion and misidentification", "a": "Availability is not directly affected", "gel": "Exploitation frequency for this type of misconfiguration may be low due to the need for Docker privileges on the host", "grl": "Remediation documentation is readily available, as best practices advise against using --uts=host"}}','2026-06-24T22:39:30.585Z','2026-06-24T22:54:02.462Z');
INSERT INTO misconfigurations VALUES('3c608d7d-8f2d-4d7b-9385-0bab905dd852',6,'docker','seccomp profile','disabled','enabled','N','N','M','N','N','N',0.0,0.0,'L','U','[]','','5.22','Disabling the seccomp profile allows all system calls, potentially exposing the container to known exploits that are blocked by default. This can lead to security vulnerabilities.','Keep the seccomp profile enabled unless there is a specific need to modify it.','value','always','','{"description": "Disabling the seccomp profile allows all system calls, potentially exposing the container to known exploits that are blocked by default. This can lead to security vulnerabilities.", "potential_impact": ["Unauthorized access to sensitive data", "Container escape leading to host compromise", "Data exfiltration"], "exploitation_scenario": {"prerequisites": ["Access to the Docker container or host", "Knowledge of system calls that can be exploited"], "example": "For example, an attacker could disable the seccomp profile by modifying the JSON configuration file directly.", "result": "As a result, the attacker could execute arbitrary system calls, potentially leading to unauthorized access or container escape."}, "metric_justifications": {"ac": "Disabling the seccomp profile requires knowledge of the Docker configuration and the ability to modify it. This is a moderate barrier as it requires some level of expertise.", "c": "With seccomp profile disabled, all system calls are allowed, potentially disclosing sensitive information.", "i": "The seccomp profile can be modified to allow or deny specific system calls, so with it disabled, any configuration change is possible.", "a": "Disabling the seccomp profile does not directly affect availability, but it can lead to unavailability if the container is compromised.", "gel": "Exploitation of this misconfiguration is common due to its potential for significant security impact.", "grl": "Remediation documentation for this issue is widely available and easy to find."}}','2026-06-24T22:39:37.306Z','2026-06-24T22:54:23.361Z');
INSERT INTO misconfigurations VALUES('7312ff68-fd0e-4a79-bcd3-1a953cf48847',6,'docker','docker exec --privileged','true','false','N','N','M','N','N','N',0.0,0.0,'H','U','[]','','5.23','Using ''docker exec --privileged'' grants excessive Linux capabilities to the command, potentially compromising container security. If not necessary, it should be avoided.','Avoid using ''docker exec --privileged''. Instead, specify individual permissions for containers requiring enhanced capabilities.','value','always','','{"description": "Using ''docker exec --privileged'' grants excessive Linux capabilities to the command within the container, potentially compromising container security. This directive should be avoided unless absolutely necessary.", "potential_impact": ["Potential data breaches due to elevated privileges", "Container escape leading to host system compromise", "Unauthorized modification of container configurations"], "exploitation_scenario": {"prerequisites": ["Access to the Docker daemon with sufficient permissions", "Knowledge of the container ID or name"], "example": "''docker exec -it <container-id> --privileged /bin/bash''", "result": "The command is executed with root privileges within the container, allowing an attacker to perform actions that would normally be restricted"}, "metric_justifications": {"ac": "Using ''docker exec --privileged'' requires knowledge of the container and the ability to execute commands with elevated privileges, which is a moderate barrier for an attacker.", "c": "No sensitive information is disclosed or readable as a direct result of this misconfiguration.", "i": "Data and configuration can be modified within the container due to the elevated privileges granted by ''docker exec --privileged''.", "a": "Container availability may be affected if the attacker modifies critical system files or services.", "gel": "The exploitation frequency for this type of misconfiguration is moderate, as it requires knowledge of the container and the ability to execute commands with elevated privileges.", "grl": "Remediation documentation is widely available, advising against using ''docker exec --privileged'' unless absolutely necessary."}}','2026-06-24T22:39:45.580Z','2026-06-24T22:54:43.586Z');
INSERT INTO misconfigurations VALUES('0bd69d17-b5ab-4e01-a384-0adad99bb8f1',6,'docker','docker exec --user','root','','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.24','Using ''docker exec --user=root'' allows executing commands within the container as root, which can be dangerous when running containers with reduced capabilities or enhanced restrictions. This could potentially lead to privilege escalation if the container is not designed to run as root.','Avoid using ''docker exec --user=root''. Instead, use ''docker exec'' without the --user option or specify a non-root user as needed.','value','always','','{"description": "Using ''docker exec --user=root'' allows executing commands within the container as root, which can be dangerous when running containers with reduced capabilities or enhanced restrictions. This could potentially lead to privilege escalation if the container is not designed to run as root.", "potential_impact": ["Privilege escalation within the container", "Unauthorized access to sensitive data within the container", "Modification of critical system files within the container"], "exploitation_scenario": {"prerequisites": ["Access to the host running the Docker daemon", "Knowledge of the container ID or name"], "example": "docker exec --user=root <container-id> /bin/bash", "result": "Execution of commands with root privileges within the container"}, "metric_justifications": {"ac": "Using ''docker exec --user=root'' allows executing commands as root, which requires a moderate level of expertise and access to the Docker daemon. This could potentially lead to privilege escalation if the container is not designed to run as root.", "c": "The user can read all files within the container", "i": "The user can modify all files within the container", "a": "The user can affect the availability of the container by modifying critical system files", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires access to the Docker daemon", "grl": "Remediation documentation for this issue is widely available"}}','2026-06-24T22:39:55.602Z','2026-06-24T22:55:01.248Z');
INSERT INTO misconfigurations VALUES('dea71b67-f987-4b7c-a64d-44be39ef426f',6,'docker','docker run --cgroup-parent','present','absent','N','N','M','N','N','N',0.0,0.0,'ND','U','[]','','5.25','Using ''docker run --cgroup-parent'' allows containers to be attached to a different cgroup than intended, potentially granting excess permissions and resources. This can pose a security risk if not monitored.','Avoid using ''docker run --cgroup-parent'' unless strictly required for specific use cases.','value','always','','{"description": "The ''docker run --cgroup-parent'' directive allows containers to be attached to a different cgroup than intended, potentially granting excess permissions and resources. This can pose a security risk if not monitored.", "potential_impact": ["Container may gain unintended access to system resources", "Potential for privilege escalation within the host", "Unauthorized resource consumption leading to performance degradation"], "exploitation_scenario": {"prerequisites": ["An attacker with access to the Docker host", "Knowledge of the ''docker run --cgroup-parent'' directive"], "example": "Example command: docker run --cgroup-parent=/other-cgroup my-container", "result": "The container is attached to a different cgroup, potentially granting excess permissions and resources."}, "metric_justifications": {"ac": "Using ''docker run --cgroup-parent'' requires an attacker with access to the Docker host and knowledge of the directive. This represents a moderate barrier (AC=M).", "c": "No sensitive information is disclosed or readable as a result of this misconfiguration.", "i": "The container can gain unintended access to system resources, modifying its behavior and potentially causing harm.", "a": "Availability may be affected due to unauthorized resource consumption leading to performance degradation.", "gel": "Exploitation frequency for this type of misconfiguration is moderate (GEL=ND).", "grl": "Remediation documentation is readily available, and avoiding the use of ''docker run --cgroup-parent'' unless strictly required can mitigate this risk (GRL=U)."}}','2026-06-24T22:40:01.116Z','2026-06-24T22:55:27.542Z');
INSERT INTO misconfigurations VALUES('60355a12-a727-49a0-bac5-db3994042f7a',6,'docker','docker run options','insecure','--rm -it --security-opt=no-new-privileges','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.26','Setting ''insecure'' for docker run options allows containers to acquire additional privileges via suid or sgid bits, increasing the risk of subverting privileged binaries. This can lead to potential security vulnerabilities, but does not directly expose sensitive information or cause immediate service disruption.','Use ''docker run --rm -it --security-opt=no-new-privileges'' instead of ''insecure''.','value','always','','{"description": "Using ''insecure'' for docker run options allows containers to acquire additional privileges via suid or sgid bits, increasing the risk of subverting privileged binaries. This can lead to potential security vulnerabilities, but does not directly expose sensitive information or cause immediate service disruption.", "potential_impact": ["Potential escalation of container privileges", "Subversion of privileged binaries", "Creation of a security loophole for further attacks"], "exploitation_scenario": {"prerequisites": ["Container is run with ''insecure'' option", "Presence of suid or sgid binaries in the container"], "example": "''docker run -it --insecure image-name''", "result": "Container acquires additional privileges, potentially allowing for subversion of privileged binaries"}, "metric_justifications": {"ac": "Setting ''insecure'' for docker run options requires a moderate barrier: understanding the implications of using this option and intentionally choosing it over more secure alternatives.", "c": "No sensitive information is disclosed or readable due to the nature of the misconfiguration.", "i": "Data or configuration can be modified by exploiting the additional privileges acquired through ''insecure'' option.", "a": "Availability may be affected if the subversion of privileged binaries leads to service disruption or unauthorized access.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires intentional use of an insecure option.", "grl": "Remediation documentation availability is high, as using ''insecure'' option is discouraged and remediation involves switching to a more secure alternative."}}','2026-06-24T22:40:09.612Z','2026-06-24T22:55:46.069Z');
INSERT INTO misconfigurations VALUES('eeddf509-4ee7-4e92-bf39-2effd6a6c020',6,'docker','Docker version pinning mechanism','latest','customized version pinning rules','N','N','M','N','N','N',0.0,0.0,'L','W','[]','','5.28','Using ''latest'' for Docker version pinning can lead to using older images containing known vulnerabilities due to caching attacks. While no immediate impact is observed, it increases the risk of exploitation.','Use specific tag versions or digest-based pinning mechanisms to ensure you always pull the latest secure image.','value','always','','{"description": "Using ''latest'' for Docker version pinning can lead to pulling older images containing known vulnerabilities due to caching attacks. This increases the risk of exploitation without immediate impact.", "potential_impact": ["Exposure to known vulnerabilities", "Potential data breaches or system crashes", "Unplanned downtime for containerized applications"], "exploitation_scenario": {"prerequisites": ["An attacker needs access to the Docker host or registry where the image is pulled from", "Knowledge of caching mechanisms used by Docker Hub or other registries"], "example": "Attacker pulls an image with tag ''latest'' from a vulnerable Docker Hub repository, exploiting the caching mechanism to serve an older insecure version.", "result": "The attacker can execute arbitrary code within the container, potentially leading to data breaches or system crashes."}, "metric_justifications": {"ac": "Using ''latest'' for Docker version pinning requires no additional effort from an attacker, making it moderately easy to exploit.", "c": "No sensitive information is disclosed by using ''latest''.", "i": "Data or configuration can be modified if the attacker gains control of a container running with elevated privileges.", "a": "Availability may be affected if the attacked container is part of a critical service.", "gel": "Exploitation frequency for this type of misconfiguration is moderate due to its simplicity and potential impact.", "grl": "Remediation documentation is widely available, making it relatively easy to address."}}','2026-06-24T22:40:17.869Z','2026-06-24T22:56:05.314Z');
INSERT INTO misconfigurations VALUES('d77dc044-c3c8-4cf7-916d-f997278a35f0',6,'docker','--pids-limit','0','100 or greater','N','N','M','N','N','P',4.29999999999999982,4.29999999999999982,'H','H','[]','','5.29','Setting --pids-limit to ''0'' allows unlimited forks within a container, potentially leading to a fork bomb attack that could crash the system. This requires an attacker with container access but does not directly expose sensitive information or modify configuration.','Set an appropriate value for --pids-limit when launching the container to limit the number of concurrently running processes and prevent a fork bomb attack.','value','always','','{"description": "Setting --pids-limit to ''0'' allows unlimited forks within a Docker container, potentially leading to a fork bomb attack that could crash the system.", "potential_impact": ["Container crash", "Resource exhaustion", "Service interruption"], "exploitation_scenario": {"prerequisites": ["Container access"], "example": "Example Docker command: `docker run --pids-limit=0 myimage`", "result": "The container will be vulnerable to a fork bomb attack, which can cause it to consume excessive resources and eventually crash."}, "metric_justifications": {"ac": "Setting --pids-limit to ''0'' removes the limit on the number of concurrently running processes within a container, making it easier for an attacker to execute a fork bomb attack.", "c": "No sensitive information is directly disclosed or readable due to container access requirements.", "i": "No configuration or data can be modified as a result of this misconfiguration.", "a": "The availability of the container and associated services may be affected due to resource exhaustion and potential crash.", "gel": "Fork bomb attacks are relatively common in systems with weak process management controls, making them a frequent exploitation technique for this type of misconfiguration.", "grl": "Remediation documentation is widely available, as setting an appropriate value for --pids-limit when launching the container can prevent fork bomb attacks."}}','2026-06-24T22:40:27.306Z','2026-06-24T22:56:24.702Z');
INSERT INTO misconfigurations VALUES('86fc9e43-d263-4ddc-b794-6667b1d27a30',6,'docker','SELinux state','insecure','enabled','N','N','M','N','N','N',0.0,0.0,'ND','H','[]','','5.3','Setting SELinux state to ''insecure'' disables the Mandatory Access Control (MAC) system, weakening the security of your containers. This can potentially lead to unauthorized access or data leakage.','Set the SELinux state to ''enforcing'' or ''permissive''.','value','always','','{"description": "The SELinux state is set to ''insecure'', which disables the Mandatory Access Control (MAC) system in Docker containers. This configuration weakens the security of your containers, potentially leading to unauthorized access or data leakage.", "potential_impact": ["Unauthorized access to sensitive data", "Data leakage", "Potential privilege escalation"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host", "Knowledge of SELinux state configuration"], "example": "Modifying the SELinux state in the Docker daemon configuration file: ''sudo nano /etc/docker/daemon.json'' and setting ''selinux_enabled'': false", "result": "SELinux is disabled, allowing an attacker to potentially gain unauthorized access or manipulate data within containers"}, "metric_justifications": {"ac": "Setting SELinux state to ''insecure'' requires knowledge of the Docker configuration and the ability to modify it. This can be considered a moderate barrier (AC=M)", "c": "With SELinux disabled, sensitive data within containers may become readable or writable by unauthorized entities", "i": "SELinux controls access to resources in Docker containers. Disabling it allows modification of these resources without proper authorization", "a": "Availability is not directly affected by setting SELinux state to ''insecure''", "gel": "Exploitation frequency for this type of misconfiguration may be moderate, depending on the security awareness and practices of the Docker administrators", "grl": "Remediation documentation for this issue is widely available, making it easier for security engineers to address"}}','2026-06-24T22:40:32.869Z','2026-06-24T22:56:46.102Z');
INSERT INTO misconfigurations VALUES('b95302cc-5468-49e8-9786-f4b6abbae688',6,'docker','docker network create','docker0','<user-defined-network>','N','N','M','P','N','N',4.29999999999999982,3.89999999999999991,'H','U','[]','','5.30','Using Docker''s default bridge ''docker0'' is vulnerable to ARP spoofing and MAC flooding attacks due to lack of filtering. This can lead to potential network traffic interception or man-in-the-middle attacks.','Create a user-defined network according to Docker documentation and run all containers within this network instead of using ''docker0''.','value','always','','{"description": "Using ''docker0'' as the network for Docker containers can lead to potential ARP spoofing and MAC flooding attacks due to lack of filtering on this default bridge network. This could result in network traffic interception or man-in-the-middle attacks.", "potential_impact": ["Network traffic interception", "Man-in-the-middle attacks", "Potential data breaches"], "exploitation_scenario": {"prerequisites": ["An unauthenticated attacker within the Docker network", "Knowledge of ARP spoofing and MAC flooding techniques"], "example": "An attacker can flood ''docker0'' with malicious ARP replies to intercept traffic between containers.", "result": "The attacker can potentially read, modify, or eavesdrop on network traffic within the Docker network."}, "metric_justifications": {"ac": "Using ''docker0'' for Docker network creation requires an unauthenticated attacker to have knowledge of ARP spoofing and MAC flooding techniques, which can be considered a moderate barrier (Medium).", "c": "An attacker can potentially read sensitive data transmitted over the network.", "i": "An attacker can potentially modify or eavesdrop on network traffic within the Docker network.", "a": "The availability of network services may be affected during an attack.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires specific knowledge and tools.", "grl": "Remediation documentation for this issue is widely available in Docker security best practices."}}','2026-06-24T22:40:41.852Z','2026-06-24T22:57:05.837Z');
INSERT INTO misconfigurations VALUES('c13c4e3c-a23f-4b6b-bd65-6b79af1382ce',6,'docker','docker run command','''--userns=host''','','N','N','M','N','N','N',0.0,0.0,'L','U','[]','','5.31','Sharing the host''s user namespaces with containers allows a container''s root process to have the same UID as a process on the host, potentially enabling privilege escalation or other security breaches. However, in this case, no known exploitation has been documented.','Avoid using ''--userns=host'' when running Docker containers. Instead, use user namespaces to isolate users on the host from users in the containers.','value','always','','{"description": "The ''--userns=host'' flag for the Docker run command allows a container''s root process to have the same UID as a process on the host, potentially enabling privilege escalation or other security breaches. This can lead to unauthorized access to sensitive data or system resources.", "potential_impact": ["Unauthorized access to sensitive data", "Privilege escalation within the host", "Disruption of host services due to container misbehavior"], "exploitation_scenario": {"prerequisites": ["Container with root privileges", "Docker run command with ''--userns=host'' flag"], "example": "docker run --userns=host my-container", "result": "The container''s root process can now interact with the host as if it were a native process, potentially leading to security breaches."}, "metric_justifications": {"ac": "Sharing the host''s user namespaces with containers allows for potential privilege escalation or other security breaches. However, exploitation requires container root privileges and the ''--userns=host'' flag, making it a genuine but moderate barrier.", "c": "No specific information is disclosed or readable due to the nature of this misconfiguration.", "i": "Data and configuration can be modified if the attacker gains root access within the container and exploits the ''--userns=host'' flag.", "a": "Availability may be affected if the attacker is able to disrupt host services due to container misbehavior.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires both container root privileges and the ''--userns=host'' flag.", "grl": "Remediation documentation is widely available, advising against using ''--userns=host'' when running Docker containers."}}','2026-06-24T22:40:51.808Z','2026-06-24T22:57:25.885Z');
INSERT INTO misconfigurations VALUES('f8cbb812-6859-4781-a20e-ca8ef1c5129d',6,'docker','docker_run_privileged','--privileged','','N','N','L','N','N','C',7.79999999999999982,7.0,'H','U','[]','','5.5','Running a container with the --privileged flag grants it all Linux kernel capabilities and lifts device cgroup controller limitations, effectively giving the container most of the rights of the underlying host. This can lead to complete system compromise if exploited.','Avoid using the --privileged flag when running Docker containers.','value','always','','{"description": "Running Docker containers with the --privileged flag grants them all Linux kernel capabilities and lifts device cgroup controller limitations, effectively giving the container most of the rights of the underlying host. This can lead to complete system compromise if exploited.", "potential_impact": ["Unauthorized access to sensitive data", "Modification or deletion of critical system files", "Root-level control over the host system"], "exploitation_scenario": {"prerequisites": ["Access to the Docker daemon with sufficient privileges"], "example": "Running a container with `docker run --privileged myimage`", "result": "The container gains full control over the host system, potentially leading to data breaches or system takeover"}, "metric_justifications": {"ac": "An unauthenticated attacker can trigger this with a standard Docker command (--privileged), making it easy to exploit.", "c": "No specific information disclosure beyond what is already accessible by the container", "i": "The container can modify or delete any file on the host system", "a": "Availability is affected as the attacker can potentially disrupt or take over the host system", "gel": "Exploitation frequency for this type of misconfiguration is high due to its potential severity and ease of exploit", "grl": "Remediation documentation is widely available, but user education and policy enforcement are key to preventing such misconfigurations"}}','2026-06-24T22:40:59.782Z','2026-06-24T22:57:43.269Z');
INSERT INTO misconfigurations VALUES('d07a6a67-31f3-4230-bc1e-ff9128484ad6',6,'docker','SSH daemon in container','running inside the container','not running inside the container','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.7','Running SSH within the container complicates security management by making it difficult to manage access policies, keys, passwords, and security upgrades for the SSH server. It also increases the attack surface.','Uninstall the SSH daemon from the container and use docker exec to enter a container on the remote host.','value','always','','{"description": "The SSH daemon running inside the Docker container complicates security management by making it difficult to manage access policies, keys, passwords, and security upgrades for the SSH server. It also increases the attack surface.", "potential_impact": ["Unauthorized access to the container", "Data breaches due to weak or compromised SSH credentials", "Privilege escalation within the host system"], "exploitation_scenario": {"prerequisites": ["Access to the Docker container", "Knowledge of the running SSH daemon inside the container"], "example": "An attacker can connect to the SSH daemon running inside the container using a standard SSH client.", "result": "The attacker gains access to the container and potentially the host system, depending on the configuration."}, "metric_justifications": {"ac": "Running the SSH daemon within the container requires additional management efforts for securing the SSH server. This increases the complexity of managing security policies, keys, passwords, and upgrades.", "c": "The running SSH daemon does not disclose any sensitive information by default.", "i": "An attacker can potentially modify the SSH configuration or access files within the container if they gain access to the SSH daemon.", "a": "The availability of the service is not directly affected by the running SSH daemon inside the container, but unauthorized access could lead to downtime.", "gel": "Exploitation of this misconfiguration is relatively common due to the increased attack surface and potential for unauthorized access.", "grl": "Remediation documentation for securing the SSH server within a Docker container is widely available."}}','2026-06-24T22:41:08.232Z','2026-06-24T22:58:03.146Z');
INSERT INTO misconfigurations VALUES('ed65d787-d43e-4b45-a72f-45d470e06583',6,'docker','privileged_port_mapping','yes','no','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.8','Mapping container ports to privileged host ports (<1024) can expose sensitive data and services, bypassing security restrictions. This is not a direct exploit but could lead to potential attacks.','Do not map container ports to privileged host ports when starting a container. Ensure there are no such declarations in the Dockerfile.','value','always','','{"description": "Mapping container ports to privileged host ports (<1024) allows unauthorized access to sensitive data and services, bypassing security restrictions. This configuration can lead to potential attacks such as data exposure, service manipulation, or unauthorized access.", "potential_impact": ["Data exposure", "Service manipulation", "Unauthorized access"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host", "Knowledge of the container''s port mapping"], "example": "Example: docker run -p 80:80 --privileged myimage", "result": "An attacker can access sensitive data or manipulate services running on the privileged host ports."}, "metric_justifications": {"ac": "Mapping container ports to privileged host ports (<1024) requires write access to the Docker daemon configuration, which is a moderate barrier for an attacker.", "c": "Privileged port mapping can disclose sensitive data and services running on the host.", "i": "An attacker can modify the behavior of services running on privileged host ports.", "a": "Availability may be affected if an attacker manipulates or takes down services running on privileged host ports.", "gel": "Exploitation frequency for this type of misconfiguration is moderate due to its potential impact and ease of discovery.", "grl": "Remediation documentation for this issue is widely available, making it easier for security engineers to address."}}','2026-06-24T22:41:17.378Z','2026-06-24T22:58:22.465Z');
INSERT INTO misconfigurations VALUES('af2159e2-2458-4746-a7d9-f5935f7ff4bd',6,'docker','Dockerfile EXPOSE instruction usage','','-p or --publish (explicitly define ports)','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','5.9','Exposing all ports in the Dockerfile increases the attack surface of the container, potentially allowing unauthorized access or service disruption. However, since no information is disclosed and no modification is possible without further steps, the impact on confidentiality and integrity is minimal.','Only expose needed ports by modifying the Dockerfile''s EXPOSE instruction and using --publish or --publish-all flags judiciously when starting containers.','value','always','','{"description": "The Dockerfile EXPOSE instruction specifies network ports that the container listens on at runtime. Using this instruction without explicitly defining ports increases the attack surface of the container, potentially allowing unauthorized access or service disruption.", "potential_impact": ["Unauthorized access to services running in the container", "Service disruption due to port exposure", "Potential for denial-of-service attacks"], "exploitation_scenario": {"prerequisites": ["Knowledge of the exposed ports and corresponding services", "Access to network traffic between the host and the container"], "example": "Exposing all ports in a Dockerfile: FROM alpine EXPOSE 80 443", "result": "An attacker can potentially gain access to services running on exposed ports, disrupt service availability, or perform denial-of-service attacks."}, "metric_justifications": {"ac": "Exposing all ports in the Dockerfile increases the attack surface of the container, requiring an attacker to have knowledge of the exposed ports and corresponding services. However, since no information is disclosed and no modification is possible without further steps, the impact on confidentiality and integrity is minimal.", "c": "No sensitive information is disclosed by exposing all ports in the Dockerfile.", "i": "Exposing all ports does not allow an attacker to modify any data or configuration within the container.", "a": "Exposing all ports may affect availability by providing more opportunities for denial-of-service attacks.", "gel": "Exploitation of this misconfiguration is relatively common due to its simplicity and potential impact.", "grl": "Remediation documentation for this issue is widely available, making it easier for security engineers to address."}}','2026-06-24T22:41:24.056Z','2026-06-24T22:58:47.185Z');
INSERT INTO misconfigurations VALUES('ff1e0ba2-7168-428f-8208-5eb1f405a302',6,'docker','image_management','insecure_image_sprawl','controlled_image_management','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','6.1','Keeping a large number of container images on the same host increases the risk of using outdated or vulnerable images. This can lead to potential exploitation if an unused image is instantiated.','Implement a workflow for removing old or stale images from the host and use features such as pull-by-digest to get specific images from the registry.','value','always','','{"description": "Insecure image sprawl refers to the practice of maintaining an excessive number of container images on a single host without proper management. This can lead to potential exploitation due to the use of outdated or vulnerable images.", "potential_impact": ["Exposure to known vulnerabilities in unused images", "Potential for unauthorized access or data breaches", "Increased attack surface for malicious actors"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host"], "example": "An attacker can exploit an outdated image by instantiating it on the host and leveraging known vulnerabilities.", "result": "The attacker gains control over the container, potentially leading to data theft or unauthorized modifications."}, "metric_justifications": {"ac": "Insecure image sprawl requires an attacker to have access to the Docker host and knowledge of existing vulnerable images. While not overly complex, it does require some level of understanding and effort.", "c": "Information disclosed includes container image details such as version numbers and base images.", "i": "Data or configuration can be modified within the containers instantiated from vulnerable images.", "a": "Availability is not directly affected, but insecure images can lead to service interruptions due to exploitation.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it relies on an attacker having access to the Docker host and knowledge of vulnerable images.", "grl": "Remediation documentation availability is high, as there are numerous resources available online for implementing controlled image management."}}','2026-06-24T22:41:33.087Z','2026-06-24T22:59:08.831Z');
INSERT INTO misconfigurations VALUES('2a1edaf3-efaa-4767-87d2-c7e15d81ce87',6,'docker','docker container prune','','periodically','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','6.2','Not pruning unused Docker containers can lead to resource waste and potential security risks from outdated images. However, the misconfiguration itself does not directly expose sensitive information or allow immediate exploitation.','Run ''docker container prune'' periodically to remove unused containers.','value','always','','{"description": "Docker container prune misconfiguration leads to resource waste and potential security risks from outdated images. Unpruned containers may contain sensitive data or vulnerabilities that could be exploited.", "potential_impact": ["Resource waste due to unused containers", "Exposure of sensitive data within unpruned containers", "Potential exploitation of vulnerabilities in unpruned containers"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host or container", "Knowledge of the Docker command ''docker container prune''"], "example": "''docker container prune'' command executed on the Docker host", "result": "Removal of unused Docker containers, potentially exposing sensitive data or vulnerabilities"}, "metric_justifications": {"ac": "Requires access to the Docker host and knowledge of the ''docker container prune'' command. This represents a moderate barrier for an attacker.", "c": "Unpruned containers may contain sensitive data that could be exposed during removal.", "i": "No data or configuration can be modified by simply running ''docker container prune''.", "a": "Availability is not affected as the containers are being removed, not made available.", "gel": "Exploitation frequency for this type of misconfiguration is moderate due to the need for access and knowledge.", "grl": "Remediation documentation is readily available in Docker official documentation."}}','2026-06-24T22:41:40.817Z','2026-06-24T22:59:27.485Z');
INSERT INTO misconfigurations VALUES('c898843c-2139-480f-8888-279eebe0430b',6,'docker','number of manager nodes','excessive','only a single manager','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','7.1','Excessive manager nodes in a swarm can increase the risk of compromise due to potential misconfigurations or vulnerabilities. However, in this case, there is no direct information disclosure or system modification possible.','Demote excess manager nodes to workers using ''docker node demote <ID>'' command.','value','always','','{"description": "Excessive manager nodes in a Docker Swarm can lead to increased risk of compromise due to potential misconfigurations or vulnerabilities. Each additional manager node increases the complexity and attack surface of the system.", "potential_impact": ["Increased risk of unauthorized access", "Potential for data leakage through misconfigured services", "Service disruptions due to mismanagement of resources"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host or swarm", "Knowledge of Docker commands"], "example": "Demoting a worker node to manager using ''docker node promote <ID>'' command.", "result": "The promoted node becomes a manager, increasing the number of potential attack vectors."}, "metric_justifications": {"ac": "Excessive manager nodes require additional configuration and management, making it more difficult for an attacker to exploit the system. However, once exploited, the impact can be significant.", "c": "No specific information disclosure is directly associated with this misconfiguration.", "i": "An attacker can potentially modify swarm-related configurations or services on any manager node.", "a": "The availability of the Docker Swarm may be affected if too many nodes are managing the swarm, leading to resource contention.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires knowledge of Docker commands and access to the system.", "grl": "Remediation documentation is readily available in resources such as the CIS Docker Benchmark v1.5."}}','2026-06-24T22:41:48.670Z','2026-06-24T22:59:45.945Z');
INSERT INTO misconfigurations VALUES('148be8e4-1b8a-47a3-a158-8061b68579d9',6,'docker','--listen-addr','','<specific interface>','N','N','M','N','N','N',0.0,0.0,'L','U','[]','','7.2','When --listen-addr is empty, Docker swarm services listen on all available host interfaces. This could potentially expose swarm services to networks that are not intended for their operation, increasing the attack surface. However, in this case, no sensitive information is directly disclosed or modified.','Specify a specific interface for the --listen-addr parameter during Docker Swarm initialization to limit exposure.','value','always','','{"description": "The --listen-addr directive in Docker Swarm initialization specifies the network interface(s) on which to listen for incoming traffic. When left empty, services will listen on all available host interfaces, potentially exposing them to networks that are not intended for their operation, increasing the attack surface.", "potential_impact": ["Unauthorized access to Docker Swarm services", "Data leakage if services handle sensitive information", "Denial of Service attacks if services are critical infrastructure"], "exploitation_scenario": {"prerequisites": ["Knowledge of the host''s network interfaces", "Access to the host where Docker Swarm is initialized"], "example": "For example, an attacker could exploit this misconfiguration by initializing a Docker Swarm service on the host with --listen-addr left empty.", "result": "As a result, the service would be accessible from all networks the host is connected to, potentially allowing unauthorized access."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to know the host''s network interfaces and have access to the host where Docker Swarm is initialized. This requires some level of system knowledge and access, but it is not overly complex.", "c": "Why C=N: No sensitive information is directly disclosed or modified in this scenario.", "i": "Why I=N: While services could be accessed, no data or configuration can be directly modified as a result of this misconfiguration.", "a": "Why A=N: The availability of the services remains unaffected, but their security is compromised by being exposed to unintended networks.", "gel": "Why GEL=L: This type of misconfiguration is relatively common due to its oversight nature.", "grl": "Why GRL=U: Remediation documentation is widely available and easy to implement."}}','2026-06-24T22:41:57.398Z','2026-06-24T23:00:05.285Z');
INSERT INTO misconfigurations VALUES('ec08b0cd-9dc1-4c01-8b4c-179e4a072b9b',6,'docker','docker swarm overlay network flag','not --opt encrypted','--opt encrypted','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','7.3','Docker swarm overlay network without encryption allows unencrypted data exchange between containers, potentially exposing sensitive information. However, exploitation requires the attacker to be part of the Docker swarm network.','Use ''--opt encrypted'' flag when creating Docker swarm overlay networks.','value','always','','{"description": "Docker Swarm overlay network without encryption (--opt encrypted) allows unencrypted data exchange between containers, potentially exposing sensitive information such as application data or authentication credentials.", "potential_impact": ["Sensitive data exposure", "Compromised application functionality", "Potential for man-in-the-middle attacks"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host or swarm manager", "Membership in the Docker Swarm network"], "example": "Creating a Docker overlay network without encryption: `docker network create --driver overlay my-network`", "result": "Unencrypted data exchange between containers within the network"}, "metric_justifications": {"ac": "Exploitation requires the attacker to be part of the Docker swarm network, making it a moderate barrier. However, once inside, they can intercept and manipulate unencrypted data.", "c": "Sensitive information such as application data or authentication credentials may be disclosed.", "i": "Data cannot be modified directly due to the nature of the overlay network, but its integrity is compromised.", "a": "Availability is not affected as long as the attacker does not disrupt the network.", "gel": "Exploitation frequency for this type of misconfiguration may vary depending on the specific application and network configuration.", "grl": "Remediation documentation is readily available, such as the CIS Docker Benchmark v1.5"}}','2026-06-24T22:42:05.924Z','2026-06-24T23:00:23.038Z');
INSERT INTO misconfigurations VALUES('2b0d81c0-035d-44bc-80a5-b75e4a411f78',6,'docker','Docker secret management commands','','follow docker secret documentation','N','N','M','N','N','N',0.0,0.0,'L','U','[]','','7.4','When Docker secret management commands are not used, there is no official method for managing secrets in a swarm cluster. This could potentially lead to unsecured storage or handling of sensitive data.','Follow the Docker secret documentation and use it to manage secrets effectively.','value','always','','{"description": "Docker secret management commands are not used, leading to unsecured storage or handling of sensitive data in a swarm cluster. This could potentially result in data exposure or unauthorized access.", "potential_impact": ["Data exposure", "Unauthorized access", "Compromised secrets"], "exploitation_scenario": {"prerequisites": ["Access to the Docker swarm cluster", "Knowledge of the location of sensitive data"], "example": "An attacker gains access to the Docker swarm cluster and locates sensitive data that is not being managed by Docker secret management commands.", "result": "The attacker can read, modify or exfiltrate the sensitive data."}, "metric_justifications": {"ac": "When Docker secret management commands are not used, an attacker requires access to the Docker swarm cluster and knowledge of the location of sensitive data. This represents a moderate barrier (AC=M) as it requires some level of network access and understanding of the system''s configuration.", "c": "Sensitive data such as passwords, API keys, and certificates can be disclosed or readable when not managed by Docker secret management commands.", "i": "Data or configuration can be modified if an attacker gains access to the sensitive data that is not being managed by Docker secret management commands.", "a": "Availability is not directly affected as the system continues to function, but the unsecured storage of sensitive data could lead to long-term service disruptions or data loss.", "gel": "Exploitation frequency for this type of misconfiguration may vary depending on the security posture and configuration of the Docker swarm cluster, but it is considered a common vulnerability in improperly secured environments.", "grl": "Remediation documentation is readily available in the official Docker secret management documentation."}}','2026-06-24T22:42:12.708Z','2026-06-24T23:00:41.570Z');
INSERT INTO misconfigurations VALUES('1ba2bc2b-bd43-41c2-9813-d1f92413f0d0',6,'docker','swarm_manager_autolock','off','on','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','7.5','With swarm_manager_autolock=''off'', the Docker swarm manager does not encrypt communication and Raft logs at rest, potentially exposing sensitive data. However, this misconfiguration only impacts availability as the swarm will not recover from a restart without manual intervention.','Set ''swarm_manager_autolock=on'' to protect mutual TLS encryption key and Raft log keys at rest.','value','always','','{"description": "The ''swarm_manager_autolock'' directive controls encryption for Docker Swarm manager communication and Raft logs at rest. With the value set to ''off'', sensitive data may be exposed, potentially impacting confidentiality and integrity of the system.", "potential_impact": ["Exposure of mutual TLS encryption key", "Exposure of Raft log keys", "Potential unauthorized modification of Swarm manager configuration"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host or container running the Swarm manager", "Knowledge of the ''swarm_manager_autolock'' directive and its impact"], "example": "For example, a user with access to the Docker host could modify the swarm_manager_autolock setting in the daemon configuration file.", "result": "As a result, sensitive data such as mutual TLS encryption keys and Raft log keys would not be encrypted at rest, potentially allowing unauthorized access or modification."}, "metric_justifications": {"ac": "With swarm_manager_autolock=''off'', an attacker with access to the Docker host could potentially read sensitive data, requiring write access to the daemon configuration file. This meets the Medium (M) difficulty level.", "c": "When ''swarm_manager_autolock'' is set to ''off'', mutual TLS encryption keys and Raft log keys are not encrypted at rest, disclosing sensitive information.", "i": "With swarm_manager_autolock=''off'', an attacker with write access could potentially modify the Swarm manager configuration, impacting integrity of the system.", "a": "Although availability is impacted when ''swarm_manager_autolock'' is set to ''off'', the Swarm will not recover from a restart without manual intervention, indicating Partial (P) availability.", "gel": "Exploitation frequency for this misconfiguration may be low due to the need for access to the Docker host and knowledge of the directive.", "grl": "Remediation documentation is widely available, making it High (H) in terms of remediation effort."}}','2026-06-24T22:42:20.213Z','2026-06-24T23:01:02.573Z');
INSERT INTO misconfigurations VALUES('387cccbb-762a-4980-b56f-edbfc0c8a08c',6,'docker','docker swarm auto-lock key rotation','not rotated','rotated','N','N','M','N','N','N',0.0,0.0,'L','W','[]','','7.6','Not rotating the swarm manager auto-lock key does not directly impact confidentiality or integrity, but it weakens security best practices. Rotation helps prevent unauthorized access if a key is compromised.','Run ''docker swarm unlock-key --rotate'' to rotate the keys and establish a predefined frequency for key rotation.','value','always','','{"description": "Docker Swarm auto-lock key rotation is not implemented, which weakens security best practices by failing to rotate the keys and potentially exposing the swarm manager to unauthorized access if a key is compromised.", "potential_impact": ["Unauthorized access to the Docker Swarm manager", "Potential data breaches or service disruptions", "Compromised cluster security leading to further attacks"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host running the swarm manager", "Knowledge of the current auto-lock key"], "example": "''docker swarm unlock --key <current_key>'' command followed by ''docker swarm lock'' to gain control over the swarm manager", "result": "Unauthorized access and control over the Docker Swarm cluster"}, "metric_justifications": {"ac": "Requires knowledge of the current auto-lock key and access to the Docker host running the swarm manager, demonstrating a moderate barrier for exploitation.", "c": "No sensitive information is disclosed or readable due to the lack of rotation.", "i": "Data and configuration can be modified if an attacker gains unauthorized access to the swarm manager.", "a": "Availability may be affected if an attacker gains control over the swarm manager and disrupts services.", "gel": "Exploitation frequency is moderate, as key rotation should be performed regularly to maintain security.", "grl": "Remediation documentation is widely available, as it involves running ''docker swarm unlock-key --rotate'' to rotate the keys."}}','2026-06-24T22:42:28.563Z','2026-06-24T23:01:19.916Z');
INSERT INTO misconfigurations VALUES('e5c82d80-d40a-4b8f-b651-bbd4bae81604',6,'docker','docker swarm update --cert-expiry','not set or expiry time less than 48h','48h','N','N','M','N','N','N',0.0,0.0,'L','H','[]','','7.7','Not setting or using an expiry time less than 48 hours for Docker Swarm node certificates may lead to outdated certificates, potentially allowing man-in-the-middle attacks during clustering operations. However, the impact is minimal as the default rotation period is 90 days.','Set an appropriate expiry time (e.g., 48h) using ''docker swarm update --cert-expiry 48h''.','value','always','','{"description": "Docker Swarm node certificates are essential for secure clustering operations. Not setting or using an expiry time less than 48 hours may lead to outdated certificates, potentially allowing man-in-the-middle attacks during these operations. The default rotation period is 90 days, but a shorter expiry time increases the risk of using stale certificates.", "potential_impact": ["Allowing unauthorized access to cluster communication", "Data interception during secure communication", "Disruption of service due to certificate errors"], "exploitation_scenario": {"prerequisites": ["Access to the Docker host or swarm manager", "Knowledge of Docker commands"], "example": "Command: ''docker swarm update --cert-expiry <duration in hours>''. With a duration less than 48 hours, outdated certificates will be used.", "result": "Successful exploitation results in the use of stale certificates during clustering operations, potentially allowing man-in-the-middle attacks."}, "metric_justifications": {"ac": "Setting an expiry time less than 48 hours for Docker Swarm node certificates requires knowledge of the ''docker swarm update --cert-expiry'' command and the ability to modify the certificate expiry duration. However, this is a moderate barrier as it only requires access to the Docker host or swarm manager.", "c": "No sensitive information is disclosed by not setting or using an expiry time less than 48 hours for Docker Swarm node certificates.", "i": "Not setting or using an expiry time less than 48 hours allows the use of stale certificates, which can be exploited for man-in-the-middle attacks during clustering operations. This modifies the security of the Docker Swarm cluster.", "a": "Not setting or using an expiry time less than 48 hours does not directly affect the availability of the Docker Swarm cluster, but it increases the risk of service disruption due to certificate errors.", "gel": "The frequency of exploiting this misconfiguration depends on the certificate rotation period. With a shorter expiry time, the risk is higher as stale certificates will be used more frequently.", "grl": "Remediation documentation for this misconfiguration is readily available in Docker''s official documentation and CIS Benchmark."}}','2026-06-24T22:42:37.602Z','2026-06-24T23:01:43.275Z');
INSERT INTO misconfigurations VALUES('bd7f4b8a-76cc-4585-bdef-0f910c3efbc1',6,'docker','docker swarm ca rotation','not rotated','rotated','N','N','M','N','N','N',0.0,0.0,'L','U','[]','','7.8','Docker Swarm CA certificate rotation is not implemented, leaving the cluster vulnerable to a compromised node or key impersonation. Rotating certificates helps maintain security during such events.','Run ''docker swarm ca --rotate'' to rotate the root CA certificates.','value','always','','{"description": "Docker Swarm CA certificate rotation is not implemented, leaving the cluster vulnerable to a compromised node or key impersonation. Rotating certificates helps maintain security during such events.", "potential_impact": ["Unauthorized access to the Docker Swarm cluster", "Data breaches due to impersonated nodes", "Disruption of services in case of a compromised root CA"], "exploitation_scenario": {"prerequisites": ["Access to the Docker Swarm manager node", "Knowledge of the current root CA certificates"], "example": "''docker swarm ca --list'' command reveals the current root CA certificates", "result": "An attacker can impersonate a node or manipulate cluster operations"}, "metric_justifications": {"ac": "Requires access to the Docker Swarm manager node and knowledge of the current root CA certificates, which is a moderate barrier for an unauthorized user.", "c": "No sensitive information is disclosed or readable due to the misconfiguration.", "i": "Data and configuration can be modified by an attacker impersonating a node or manipulating cluster operations.", "a": "Availability of services may be affected if an attacker successfully impersonates a node or manipulates cluster operations.", "gel": "Exploitation frequency for this type of misconfiguration is moderate, as it requires access to the Docker Swarm manager node and knowledge of the current root CA certificates.", "grl": "Remediation documentation is widely available in resources such as the CIS Benchmark and official Docker documentation."}}','2026-06-24T22:42:45.264Z','2026-06-24T23:01:58.460Z');
INSERT INTO misconfigurations VALUES('583f4625-3d7e-45d1-8393-3638b17c5e3f',6,'docker','Docker Swarm Data Plane and Management Plane Separation','default','--advertise-addr=192.168.0.1 --data-path-addr=17.1.0.3','N','N','M','P','N','C',7.79999999999999982,6.5,'L','U','[]','','7.9','Separating management and data plane traffic is a best practice for network security. Without separation, an attacker who gains access to the data plane can potentially reach the management plane, leading to complete service disruption.','Initialize Docker Swarm with dedicated interfaces for management and data planes using ''docker swarm init --advertise-addr=192.168.0.1 --data-path-addr=17.1.0.3''.','value','always','','{"description": "The default configuration for Docker Swarm Data Plane and Management Plane Separation allows both planes to use the same IP address. This setup can lead to potential security risks as an attacker who gains access to the data plane may potentially reach the management plane, leading to complete service disruption.", "potential_impact": ["Potential unauthorized control over Docker Swarm services", "Service disruptions due to management plane compromise", "Unauthorized configuration changes"], "exploitation_scenario": {"prerequisites": ["Gaining access to the data plane", "Knowledge of Docker Swarm architecture"], "example": "''docker swarm init'' command with default settings", "result": "Access to both management and data planes, enabling an attacker to disrupt services or make unauthorized changes"}, "metric_justifications": {"ac": "Without separation, an attacker who gains access to the data plane can potentially reach the management plane, leading to complete service disruption. This requires a complex multi-step chain of prerequisites (see exploitation_scenario), making it a Medium difficulty.", "c": "No sensitive information is disclosed or readable in this specific misconfiguration", "i": "Data and configuration can be modified if an attacker gains access to both planes", "a": "Availability is affected as an attacker can disrupt services by gaining control over both planes", "gel": "Exploitation frequency for this type of misconfiguration is moderate due to the need for multi-step attacks", "grl": "Remediation documentation is widely available and easy to find"}}','2026-06-24T22:42:54.369Z','2026-06-24T23:02:16.958Z');
INSERT INTO misconfigurations VALUES('e85269a1-8bc9-4202-9430-9a46b47220e6',7,'redis','/etc/opt/redislabs/permissions','704','700','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251226r961041_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The /etc/opt/redislabs/permissions file sets permissions for RedisLabs'' additional modules. A value of 704 grants write access to the group, which can lead to unauthorized modifications or data exposure.", "potential_impact": ["Unauthorized modification of RedisLabs'' configurations", "Exposure of sensitive data through altered configurations", "Potential for denial-of-service attacks due to misconfigured modules"], "exploitation_scenario": {"prerequisites": ["Access to the system where /etc/opt/redislabs/permissions is located"], "example": "For instance, changing the permissions to 704: chmod 704 /etc/opt/redislabs/permissions", "result": "An attacker can modify RedisLabs'' configurations, potentially causing data exposure or denial-of-service."}, "metric_justifications": {"ac": "The value 704 grants write access to the group, making it easy for an unauthorized user to modify sensitive configurations.", "c": "With read permissions (4), the file content is disclosed to the group.", "i": "Write permissions (2) allow the group to modify the file''s content.", "a": "The permissions do not affect the availability of the system as a whole, but misconfigurations can lead to denial-of-service incidents.", "gel": "Misconfigurations like this one are common and easy to exploit.", "grl": "Remediation documentation is widely available in security best practices."}}','2026-06-25T05:11:11.562Z','2026-06-25T05:14:02.599Z');
INSERT INTO misconfigurations VALUES('35f5b971-fb32-47e9-9f97-93841b8470ea',7,'redis','--askpass','','None','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251228r961047_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The --askpass directive in Redis allows an attacker to bypass authentication when connecting via SSH. This can lead to unauthorized access and potential data breaches.", "potential_impact": ["Unauthorized access", "Data exposure", "Privilege escalation"], "exploitation_scenario": {"prerequisites": ["Knowledge of Redis configuration", "Access to the Redis server via SSH"], "example": "--askpass=/path/to/script", "result": "Allows an attacker to bypass authentication and gain unauthorized access to the Redis server"}, "metric_justifications": {"ac": "Why AC=L: The --askpass directive can be easily exploited by simply modifying the SSH configuration. No special preconditions beyond sending a request are required.", "c": "Why C=P: Redis server credentials and data stored in the server can be disclosed.", "i": "Why I=N: The attacker can modify any data or configuration on the Redis server.", "a": "Why A=N: The availability of the Redis server is affected as an unauthorized user gains access.", "gel": "Why GEL=M: This type of misconfiguration is commonly found in systems with weak security practices.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available and easy to find."}}','2026-06-25T05:11:11.568Z','2026-06-25T05:14:45.556Z');
INSERT INTO misconfigurations VALUES('8fe0f8e0-f6d1-444e-b333-dca1861a702f',7,'redis','min_data_TLS_version','1.0','1.2','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251229r961050_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The min_data_TLS_version directive specifies the minimum TLS version that Redis will accept for encrypted connections. A value of 1.0 is dangerously low as it allows connections using SSLv2 and SSLv3, which are known to be insecure due to various vulnerabilities such as POODLE and BEAST attacks. These attacks can lead to information disclosure or even man-in-the-middle attacks.", "potential_impact": ["Information disclosure", "Man-in-the-middle attacks", "Compromised data integrity"], "exploitation_scenario": {"prerequisites": ["An unauthenticated attacker on the network", "A Redis instance with min_data_TLS_version set to 1.0"], "example": "HTTPS request using SSLv2 or SSLv3: `curl -v -X GET https://redis-instance`", "result": "Successful connection to the Redis instance using an insecure TLS version, potentially leading to information disclosure or man-in-the-middle attacks"}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTPS request, requiring no special preconditions beyond sending a request.", "c": "Why C=P: The attacker can read sensitive data transmitted over the insecure connection.", "i": "Why I=N: The attacker cannot modify the Redis configuration or data directly through this vulnerability.", "a": "Why A=N: The availability of the Redis instance is not affected by this vulnerability.", "gel": "Why GEL=M: Insecure TLS versions are commonly used, making exploitation relatively frequent.", "grl": "Why GRL=H: Remediation documentation for setting min_data_TLS_version to a secure value is widely available."}}','2026-06-25T05:11:11.576Z','2026-06-25T05:15:40.320Z');
INSERT INTO misconfigurations VALUES('58db5a46-a9eb-42ac-b7a9-26b401b8885f',7,'redis','fips','insecure_value','on','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251233r961857_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''fips'' directive enables FIPS mode in Redis, which enforces compliance with the Federal Information Processing Standards (FIPS) for cryptographic modules. Setting ''fips'' to ''insecure_value'' disables FIPS mode, making the system vulnerable to attacks that exploit weak or unapproved encryption algorithms. This misconfiguration can lead to sensitive data being exposed or tampered with.", "potential_impact": ["Exposure of sensitive data", "Tampering with encrypted data", "Potential for unauthorized access"], "exploitation_scenario": {"prerequisites": ["Access to Redis configuration file"], "example": "''redis.conf'': fips no", "result": "Redis will not enforce FIPS mode, making it vulnerable to attacks using weak or unapproved encryption algorithms"}, "metric_justifications": {"ac": "Why AC=L: Exploiting this misconfiguration requires only modifying the Redis configuration file and restarting the service. No special expertise or reconnaissance is needed.", "c": "Why C=P: Sensitive data can be read if it is encrypted with weak or unapproved algorithms.", "i": "Why I=N: Encrypted data can be modified if it is encrypted with weak or unapproved algorithms.", "a": "Why A=N: The availability of the system remains unaffected, but data confidentiality and integrity are compromised.", "gel": "Why GEL=M: This type of misconfiguration is common due to its simplicity and potential for significant impact.", "grl": "Why GRL=H: Remediation documentation is widely available in resources such as the CIS Benchmark"}}','2026-06-25T05:11:11.583Z','2026-06-25T05:35:29.334Z');
INSERT INTO misconfigurations VALUES('2e14ca00-13b6-46f5-bf4b-ad16769e5644',7,'redis','encryption_method','insecure_value','LUKS','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251242r961128_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The encryption_method directive specifies the method used to encrypt Redis data. Setting it to insecure_value means Redis data is not encrypted, making it vulnerable to eavesdropping and unauthorized access. This misconfiguration can lead to sensitive data exposure.", "potential_impact": ["Exposure of sensitive data stored in Redis", "Unauthorized access to Redis data", "Potential for data manipulation due to lack of encryption"], "exploitation_scenario": {"prerequisites": ["Knowledge of the Redis configuration file", "Ability to modify the Redis configuration file"], "example": "Example config snippet: `encryption_method insecure_value`. An attacker can simply read the Redis data without encryption.", "result": "An attacker can read and manipulate unencrypted Redis data, potentially leading to data breaches."}, "metric_justifications": {"ac": "Why AC=L: Exploitation of this misconfiguration is easy as it only requires reading the Redis configuration file and accessing the unencrypted data.", "c": "Why C=P: Sensitive data such as passwords, session tokens, and user information can be disclosed.", "i": "Why I=N: Data can be read and manipulated without any restrictions.", "a": "Why A=N: The availability of Redis data is not affected as the data is still accessible, but its integrity and confidentiality are compromised.", "gel": "Why GEL=M: This type of misconfiguration is common due to lack of encryption by default in Redis.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available and easy to implement."}}','2026-06-25T05:11:11.589Z','2026-06-25T05:17:27.719Z');
INSERT INTO misconfigurations VALUES('278652e5-434e-4d97-9e6f-4ed7b4426208',7,'redis','encryption','insecure_value','LUKS','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251244r1018563_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The Redis server is configured to use an insecure encryption method (insecure_value), which leaves sensitive data vulnerable to interception and unauthorized access. This configuration should be updated to a secure encryption method such as LUKS for improved security.", "potential_impact": ["Unauthorized read access to Redis data", "Data leakage during transmission", "Potential for tampering with Redis data"], "exploitation_scenario": {"prerequisites": ["Access to the Redis server configuration", "Knowledge of insecure encryption method used"], "example": "Example configuration: `requirepass insecure_value`. An attacker can simply connect to the Redis server and provide the password to gain access.", "result": "The attacker gains read access to all Redis data, potentially leading to data leakage or tampering."}, "metric_justifications": {"ac": "Why AC=L: exploitation requires only sending a request with the correct password. No special preconditions beyond sending a request.", "c": "Why C=P: sensitive Redis data is disclosed to unauthorized parties.", "i": "Why I=N: Redis data can be read and potentially modified by an attacker.", "a": "Why A=N: the availability of Redis data is compromised if it falls into the wrong hands.", "gel": "Why GEL=M: many attackers are likely to target insecure encryption methods for easy access to sensitive data.", "grl": "Why GRL=H: remediation documentation is widely available, making it relatively straightforward to implement secure encryption."}}','2026-06-25T05:11:11.595Z','2026-06-25T05:19:11.778Z');
INSERT INTO misconfigurations VALUES('0bd175e5-a31c-451b-8116-70b52a863630',7,'redis','version','','supported_version_number','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-265880r999546_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The Redis version directive specifies the supported version number for the Redis server. Using an unsupported version can expose the server to potential security vulnerabilities and lack of updates. An outdated Redis version may not have the latest security patches, making it easier for attackers to exploit known vulnerabilities.", "potential_impact": ["Unauthorized access", "Data exposure", "Server downtime"], "exploitation_scenario": {"prerequisites": ["Knowledge of the Redis version being used"], "example": "For example, sending a GET request to the Redis server with the command ''INFO'' will return the server information including the Redis version.", "result": "An attacker can use this information to search for known vulnerabilities in the specific Redis version and potentially exploit them."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily determine the Redis version by sending a standard HTTP request, making it easy to identify potential vulnerabilities.", "c": "Why C=P: The Redis version number is disclosed but no sensitive data is directly readable.", "i": "Why I=N: No configuration or data can be modified through this misconfiguration alone.", "a": "Why A=N: The availability of the server remains unaffected as long as the attacker does not exploit any vulnerabilities found.", "gel": "Why GEL=M: There are many known Redis version vulnerabilities, making it a common target for attacks.", "grl": "Why GRL=H: Remediation documentation is widely available in resources such as the CIS Benchmark and Redis official documentation."}}','2026-06-25T05:11:11.610Z','2026-06-25T05:20:03.811Z');
INSERT INTO misconfigurations VALUES('6e4bb770-7741-449d-93fb-fd0ab03e54a6',7,'redis','log_level','insecure_value','<organizationally defined level>','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251190r960879_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The log_level directive determines the severity level of Redis logs. Setting it to insecure_value (which is not an officially defined value) may result in excessive logging that could reveal sensitive information about the system, such as commands executed, client IP addresses, and error messages.", "potential_impact": ["Exposure of sensitive data", "Unauthorized access attempts detection evasion", "Performance degradation due to excessive logging"], "exploitation_scenario": {"prerequisites": ["Access to Redis configuration file"], "example": "Setting log_level to insecure_value in the redis.conf file: log_level insecure_value", "result": "Detailed logs containing sensitive information will be generated"}, "metric_justifications": {"ac": "Why AC=L: Setting log_level to insecure_value requires only modifying the Redis configuration file, which is a simple action that can be performed by any user with write access.", "c": "Why C=P: Sensitive information such as commands executed, client IP addresses, and error messages are disclosed in the logs.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration.", "a": "Why A=N: The system''s availability is not affected by this misconfiguration.", "gel": "Why GEL=M: Misconfigurations related to log_level are common and easy to exploit.", "grl": "Why GRL=H: Remediation documentation for this type of misconfiguration is widely available"}}','2026-06-25T05:11:11.617Z','2026-06-25T05:20:49.609Z');
INSERT INTO misconfigurations VALUES('b363ea09-6d09-4293-aec6-615019d1d54e',7,'redis','alert_threshold_storage','less than 75%','75%','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251197r961398_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The alert_threshold_storage directive determines the percentage of storage usage that triggers an alert. Setting it less than 75% can lead to insufficient alerts about potential Redis data loss or performance issues.", "potential_impact": ["Potential data loss due to lack of timely alerts", "Performance degradation due to unmonitored storage usage", "Increased risk of downtime or service interruptions"], "exploitation_scenario": {"prerequisites": ["Access to Redis configuration file"], "example": "Example config snippet: alert_threshold_storage 50%, which sets the threshold below the recommended 75%", "result": "Result: Insufficient alerts about potential data loss or performance issues"}, "metric_justifications": {"ac": "Why AC=L: Setting alert_threshold_storage less than 75% makes it easy for an attacker to exploit the misconfiguration by simply modifying the Redis configuration file.", "c": "Why C=P: The configuration setting determines the threshold at which alerts are triggered, and a lower value means less information about potential data loss or performance issues is disclosed.", "i": "Why I=N: No sensitive data can be modified by changing this directive.", "a": "Why A=N: The availability of Redis services remains unaffected by modifying the alert_threshold_storage setting.", "gel": "Why GEL=M: Misconfigurations involving alert_threshold_storage are common and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation documentation for this misconfiguration is widely available in security best practices and Redis configuration guides."}}','2026-06-25T05:11:11.623Z','2026-06-25T05:21:41.552Z');
INSERT INTO misconfigurations VALUES('280131b0-1502-4d2d-8867-1cf53d5517e9',7,'redis','/etc/logrotate.conf','','secured_configuration','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251200r960915_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The /etc/logrotate.conf misconfiguration exposes sensitive Redis log rotation settings to unauthenticated attackers, potentially allowing them to manipulate log rotation parameters or gain insights into system operations.", "potential_impact": ["Unauthorized modification of log rotation settings", "Exposure of Redis operational details", "Potential for denial-of-service attacks through log manipulation"], "exploitation_scenario": {"prerequisites": ["Access to the system''s network"], "example": "/etc/logrotate.conf file is publicly accessible", "result": "An attacker can view or modify log rotation settings, potentially causing data loss, unauthorized access, or denial-of-service"}, "metric_justifications": {"ac": "Exploitation requires only network access and no additional preconditions beyond sending a request to the publicly accessible /etc/logrotate.conf file.", "c": "Sensitive Redis log rotation settings are disclosed.", "i": "Log rotation parameters can be modified.", "a": "Availability may be affected through manipulation of log rotation settings.", "gel": "This type of misconfiguration is common and easily exploited by attackers.", "grl": "Remediation documentation is widely available in security best practices."}}','2026-06-25T05:11:11.629Z','2026-06-25T05:22:23.889Z');
INSERT INTO misconfigurations VALUES('d65fe966-24a7-4c59-8216-34d67476076b',7,'redis','timezone','insecure_value','UTC','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251201r961443_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The Redis timezone directive sets the server''s timezone. Using an insecure value (insecure_value) can lead to incorrect timestamps and potential issues with data consistency and sorting. The default value should be set to UTC.", "potential_impact": ["Incorrect timestamps may cause data inconsistencies", "Potential issues with data sorting", "Misinterpretation of event sequences could lead to security vulnerabilities"], "exploitation_scenario": {"prerequisites": ["An unauthenticated attacker needs access to the Redis configuration file or command-line interface"], "example": "Setting timezone: insecure_value in redis.conf", "result": "The server''s timezone will be set to an insecure value, leading to potential issues as described."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily modify the Redis configuration file or command-line interface to change the timezone to an insecure value.", "c": "Why C=P: The server''s timezone is disclosed but no sensitive data is readable.", "i": "Why I=N: Only the timezone can be modified, and it does not affect the availability of other data or configuration.", "a": "Why A=N: The change in timezone does not affect the server''s availability.", "gel": "Why GEL=M: Timezone misconfigurations are common and easy to exploit.", "grl": "Why GRL=H: Remediation documentation is widely available, such as the CIS Redis Benchmark."}}','2026-06-25T05:11:11.636Z','2026-06-25T05:23:12.296Z');
INSERT INTO misconfigurations VALUES('9b046124-2cf8-414e-8c6e-3be330d15163',7,'redis','/var/opt/redislabs/log/* permissions','777','640 or 660','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251204r960936_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The /var/opt/redislabs/log/* permissions set to 777 grants read, write, and execute access to all users, including unauthorized ones. This exposes Redis logs to potential attackers, allowing them to view sensitive information such as passwords, commands, and error messages.", "potential_impact": ["Unauthorized access to Redis logs", "Potential exposure of sensitive data", "Privilege escalation if other vulnerable services are present"], "exploitation_scenario": {"prerequisites": ["Access to the system where Redis is installed"], "example": "An attacker can simply list the contents of /var/opt/redislabs/log/* with a ''ls'' command or download the logs using an HTTP GET request.", "result": "The attacker gains access to Redis logs, potentially exposing sensitive data and enabling further attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request or a simple command like ''ls''.", "c": "Why C=P: Sensitive information such as passwords, commands, and error messages are disclosed.", "i": "Why I=N: No data or configuration can be modified directly from the logs.", "a": "Why A=N: Availability is not affected as the logs are read-only for unauthorized users.", "gel": "Why GEL=M: Misconfigurations allowing world-readable logs are common and easily exploited.", "grl": "Why GRL=H: Remediation documentation is widely available, but human error can still lead to this misconfiguration."}}','2026-06-25T05:11:11.642Z','2026-06-25T05:25:55.134Z');
INSERT INTO misconfigurations VALUES('c5c6532f-6926-4418-9351-dd39a79db273',7,'redis','user owner','insecure_value','redislabs','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251206r960942_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The user owner directive specifies the Unix user under which Redis runs. Setting it to an insecure_value can lead to potential privilege escalation and unauthorized access to sensitive data. The default value is typically ''redis'', but in this case, it''s set to ''insecure_value''.", "potential_impact": ["Privilege escalation", "Unauthorized access to Redis data", "Potential for data manipulation or deletion"], "exploitation_scenario": {"prerequisites": ["Access to the Redis configuration file"], "example": "Modifying the Redis configuration file to set user owner to ''insecure_value'':\n\n`user = insecure_value`", "result": "The Redis process will run under the specified insecure user, potentially allowing an attacker to gain unauthorized access or manipulate data."}, "metric_justifications": {"ac": "Why AC=L: Setting user owner to ''insecure_value'' requires only modifying a configuration file, which is a simple action that can be performed by any user with write access.", "c": "Why C=P: The insecure user may have access to sensitive Redis data such as passwords or session tokens.", "i": "Why I=N: The insecure user can modify Redis configuration and potentially manipulate or delete data.", "a": "Why A=N: The insecure user does not affect the availability of the Redis service itself, but may lead to data loss or unavailability due to potential misconfiguration or data manipulation.", "gel": "Why GEL=M: Misconfigurations involving user owner are relatively common and can be easily discovered during security audits.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available, but the specifics may depend on the Redis version and deployment environment."}}','2026-06-25T05:11:11.660Z','2026-06-25T05:27:42.154Z');
INSERT INTO misconfigurations VALUES('e33411d9-aaab-46d4-af34-1a3fc2b5f86c',7,'redis','directory_permissions','701','700','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251207r960945_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The directory_permissions value of 701 for Redis allows unauthenticated attackers to read and write files within the specified directory, which can lead to data exposure or modification. The default value should be 700 for better security.", "potential_impact": ["Data exposure due to unauthorized reading of sensitive files", "Modification of configuration files leading to system misconfiguration", "Unauthorized execution of scripts if executable files are present"], "exploitation_scenario": {"prerequisites": ["Access to the Redis server", "Knowledge of the directory where Redis data is stored"], "example": "For example, an attacker can send a command like ''CONFIG GET *'' to read all configuration settings.", "result": "The attacker can view or modify sensitive information, potentially leading to system compromise."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily read and write files within the specified directory with a standard HTTP request.", "c": "Why C=P: Sensitive information such as configuration settings, passwords, or data files can be disclosed.", "i": "Why I=N: Configuration settings, passwords, or data files can be modified.", "a": "Why A=N: The availability of the system is not directly affected by this misconfiguration, but it can lead to further issues if sensitive information is exposed or configuration is modified.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to exploit for attackers.", "grl": "Why GRL=H: Remediation documentation is widely available, but manual intervention is required to correct the issue."}}','2026-06-25T05:11:11.672Z','2026-06-25T05:28:27.700Z');
INSERT INTO misconfigurations VALUES('2435ce28-95c9-45bc-9108-4bd086dfb2da',7,'redis','user_role','viewer','appropriate_for_function','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251209r961461_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The user_role directive determines the level of access for Redis clients. Setting it to viewer grants read-only access to all keys and values in the database. This configuration is dangerous because an unauthenticated attacker can easily obtain sensitive data by simply querying the Redis instance.", "potential_impact": ["Data exposure", "Unauthorized read access", "Potential for information leaks"], "exploitation_scenario": {"prerequisites": ["Internet connection", "Access to the Redis instance"], "example": "HTTP request: GET <redis-instance-url>", "result": "The attacker receives a response containing all readable data in the Redis database"}, "metric_justifications": {"ac": "Why AC=L: an unauthenticated attacker can easily obtain sensitive data by simply querying the Redis instance.", "c": "Why C=P: all readable data in the Redis database is disclosed.", "i": "Why I=N: no write access or modification of data is possible with this configuration.", "a": "Why A=N: the availability of the Redis instance remains unaffected.", "gel": "Why GEL=M: user_role=viewer misconfigurations are common and easily exploitable.", "grl": "Why GRL=H: remediation documentation is widely available in security best practices"}}','2026-06-25T05:11:11.678Z','2026-06-25T05:29:07.398Z');
INSERT INTO misconfigurations VALUES('17e6a6dd-54a3-49fa-a868-276da0427f4f',7,'redis','installation_user','insecure_value','appropriate_people','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251211r960960_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The installation_user directive specifies the user under which Redis is run. Setting it to an insecure value (insecure_value) can lead to potential security risks as the user may have excessive privileges. This could allow unauthorized access, data modification, or denial of service.", "potential_impact": ["Unauthorized access to sensitive data", "Modification of Redis configuration or data", "Denial of service through malicious actions"], "exploitation_scenario": {"prerequisites": ["Knowledge of the Redis installation user and its privileges", "Ability to modify Redis configuration"], "example": "Setting the installation_user to an insecure value in the Redis configuration file (redis.conf):\n\n    bind 127.0.0.1\n    port 6379\n    daemonize yes\n    logfile \"/var/log/redis/redis.log\"\n    timeout 0\n    save 900 1\n    save 300 10\n    save 60 10000\n    rdbcompression yes\n    dbfilename dump.rdb\n    dir /var/redis/dumps\n    user insecure_value", "result": "An attacker can potentially gain unauthorized access to Redis, modify data, or cause a denial of service."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by modifying the Redis configuration file and setting the installation_user to an insecure value. No special preconditions beyond sending a request are required.", "c": "Why C=P: The attacker can read sensitive data such as Redis configuration, data, or logs.", "i": "Why I=N: The attacker can modify Redis configuration or data, potentially leading to unauthorized access or denial of service.", "a": "Why A=N: The availability of the Redis service may be affected if an attacker causes a denial of service.", "gel": "Why GEL=M: Misconfigurations involving the installation_user are common and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation documentation for this type of misconfiguration is widely available."}}','2026-06-25T05:11:11.684Z','2026-06-25T05:30:15.164Z');
INSERT INTO misconfigurations VALUES('4d3b2b97-a1b4-4ce5-bfbe-52bcfa1fdd1d',7,'redis','/var/opt/redislabs','','/mnt/dedicated_redis_directory','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251212r960960_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The specified Redis data directory is located at /var/opt/redislabs, which is not recommended as it may lead to potential security risks and complications in managing multiple applications within the same directory. The ideal practice is to have a dedicated directory for Redis data, such as /mnt/dedicated_redis_directory.", "potential_impact": ["Unauthorized access to Redis data", "Data corruption or loss due to mismanagement of multiple applications", "Potential for increased attack surface"], "exploitation_scenario": {"prerequisites": ["Access to the system where Redis is installed"], "example": "For example, modifying the Redis configuration file (redis.conf) and changing the ''dir'' directive from /var/opt/redislabs to /mnt/dedicated_redis_directory", "result": "The result would be a change in the location where Redis stores its data, improving security and management."}, "metric_justifications": {"ac": "Why AC=L: Exploiting this misconfiguration is easy as it only requires modifying the Redis configuration file and restarting the service. No special preconditions beyond sending a request are required.", "c": "Why C=P: The data directory contains sensitive Redis data that, if exposed, could be read by unauthorized users.", "i": "Why I=N: While the data can be read, it is not directly modifiable through this misconfiguration.", "a": "Why A=N: The availability of the Redis service is not affected by this misconfiguration.", "gel": "Why GEL=M: Misconfigurations involving data directory placement are common and easily exploitable.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available in security best practices and Redis configuration guides."}}','2026-06-25T05:11:11.690Z','2026-06-25T05:31:04.680Z');
INSERT INTO misconfigurations VALUES('da2ab2dd-d34c-4157-b7de-85789a07fed7',7,'redis','default database access','enabled','disabled','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251222r960969_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "Enabling default database access allows any client to connect and interact with the Redis server without authentication, posing a significant security risk. This configuration setting should be disabled to prevent unauthorized access.", "potential_impact": ["Unauthenticated clients can read sensitive data stored in the Redis database", "Clients can modify or delete data in the Redis database", "An attacker could potentially take control of the Redis server if other vulnerabilities exist"], "exploitation_scenario": {"prerequisites": ["Knowledge of the Redis server''s IP address and port number", "Ability to send a simple Redis command over the network"], "example": "redis-cli -h <server_ip> -p <port>", "result": "Connection to the Redis server is established, allowing the client to read, modify, or delete data"}, "metric_justifications": {"ac": "Enabling default database access requires no additional preconditions beyond sending a simple Redis command over the network. This makes it easy for any attacker to exploit.", "c": "With default database access enabled, sensitive data stored in the Redis database becomes readable by unauthenticated clients.", "i": "Unauthenticated clients can modify or delete data in the Redis database when default database access is enabled.", "a": "Default database access does not directly affect the availability of the Redis server, but it can lead to more serious issues if other vulnerabilities are exploited.", "gel": "Default database access misconfigurations are common and easy to discover, making them a frequent target for attackers.", "grl": "Remediation documentation for this issue is widely available and easy to find."}}','2026-06-25T05:11:11.696Z','2026-06-25T05:31:50.275Z');
INSERT INTO misconfigurations VALUES('e8ad5085-034f-41be-8b89-daf112bc3362',7,'redis','password_hashing_method','insecure_value','one-way, salted hashing functions (e.g., SHA256)','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251223r1018619_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The password_hashing_method directive specifies the method used to hash Redis passwords for authentication. Setting it to an insecure_value bypasses the intended security mechanism, making passwords vulnerable to easy decryption.", "potential_impact": ["Unauthorized access to Redis instances", "Compromised user accounts", "Potential data breaches"], "exploitation_scenario": {"prerequisites": ["Knowledge of the insecure password hash value", "Access to the Redis instance"], "example": "config snippet: `requirepass insecure_value`, HTTP request: `AUTH insecure_value`", "result": "The Redis instance authenticates with the insecure password, allowing unauthorized access"}, "metric_justifications": {"ac": "Exploitation is easy as it only requires setting an insecure password hash value and providing it during authentication.", "c": "No sensitive information is disclosed beyond the hashed password itself.", "i": "The password can be easily decrypted, allowing unauthorized access to Redis instances and user accounts.", "a": "Availability is not directly affected as the exploit does not cause downtime or service interruption.", "gel": "Exploitation of this misconfiguration is common due to its simplicity.", "grl": "Remediation documentation is widely available, making it easier for attackers to find and exploit this vulnerability."}}','2026-06-25T05:11:11.702Z','2026-06-25T05:32:30.560Z');
INSERT INTO misconfigurations VALUES('4a0e6b5a-5f9c-419c-9678-87a0b0c399fa',7,'redis','cm_session_timeout_minutes','15','<organizationally_defined_value>','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251224r961521_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The cm_session_timeout_minutes directive sets the timeout for Redis client connections in minutes. A value of 15 minutes is too short and can lead to increased resource consumption and potential denial-of-service (DoS) attacks. Longer session timeouts allow for more efficient use of resources, reducing the risk of such attacks.", "potential_impact": ["Increased resource consumption leading to potential Denial-of-Service (DoS) attacks", "Unauthorized access to sensitive data during short-lived sessions", "Potential for session hijacking due to shorter timeout duration"], "exploitation_scenario": {"prerequisites": ["An unauthenticated attacker with network access to the Redis server", "Knowledge of the Redis configuration, including the cm_session_timeout_minutes directive"], "example": "Example config snippet: `timeout 15000`; HTTP request: `telnet redis-server 6379`", "result": "The attacker can repeatedly establish and terminate connections, consuming server resources and potentially causing a Denial-of-Service (DoS) condition"}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily exploit the short timeout by repeatedly establishing and terminating connections, consuming server resources.", "c": "Why C=P: The attacker can access Redis server resources but cannot read sensitive data without additional vulnerabilities.", "i": "Why I=N: The attacker can modify session-related data during the short timeout period.", "a": "Why A=N: The attacker can disrupt the availability of the Redis server by consuming its resources.", "gel": "Why GEL=M: Short timeout configurations are common and easily exploitable by script kiddies or automated tools.", "grl": "Why GRL=H: Remediation documentation is widely available, but manual configuration changes may require technical expertise."}}','2026-06-25T05:11:11.708Z','2026-06-25T05:33:25.433Z');
INSERT INTO misconfigurations VALUES('91679c3f-74b6-4a20-b687-f033d711adcf',7,'redis','default_database_access','checked','unchecked','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251230r961053_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''default_database_access'' directive determines whether an unauthenticated attacker can access Redis databases without authentication. Setting it to ''checked'' allows such access, making the system vulnerable to data exposure and manipulation.", "potential_impact": ["Unauthorized read/write access to Redis databases", "Data breaches due to unauthenticated actions", "Modification of sensitive configuration or data"], "exploitation_scenario": {"prerequisites": ["An unauthenticated connection to the Redis server"], "example": "HTTP request: GET /dbname without authentication", "result": "Access granted to the specified database"}, "metric_justifications": {"ac": "Setting ''default_database_access'' to ''checked'' allows any unauthenticated attacker to trigger this with a standard HTTP request, making it easy to exploit.", "c": "With ''default_database_access'' set to ''checked'', an attacker can read sensitive data from Redis databases.", "i": "An attacker can modify the content of Redis databases when ''default_database_access'' is set to ''checked''.", "a": "The availability of the system may be affected if an attacker modifies or deletes critical data.", "gel": "Exploitation of this misconfiguration is common due to its simplicity and widespread usage.", "grl": "Remediation documentation for this issue is readily available in security benchmarks like CIS."}}','2026-06-25T05:11:11.712Z','2026-06-25T05:34:02.161Z');
INSERT INTO misconfigurations VALUES('bd549578-2b54-4064-a81d-37833baf20cc',7,'redis','fips_mode','insecure_value','on','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251232r961857_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''fips_mode'' directive enables Federal Information Processing Standard (FIPS) mode in Redis, enhancing security by requiring cryptographic modules to meet FIPS standards. Setting ''fips_mode'' to ''insecure_value'' disables this feature, making the system vulnerable to attacks that exploit weak or unverified cryptography.", "potential_impact": ["Unauthorized data access", "Data integrity breaches", "Cryptographic key exposure"], "exploitation_scenario": {"prerequisites": ["Access to Redis configuration file"], "example": "''redis.conf'': fips_mode no", "result": "Weak or unverified cryptography is used, making the system vulnerable to attacks"}, "metric_justifications": {"ac": "Setting ''fips_mode'' to ''insecure_value'' allows for easy exploitation by an attacker with access to the Redis configuration file. They can disable FIPS mode and use weak or unverified cryptography.", "c": "With FIPS mode disabled, sensitive data may be vulnerable to unauthorized access due to weakened encryption.", "i": "Data integrity is affected as weak or unverified cryptography can lead to data tampering or manipulation.", "a": "Availability remains unaffected as the system continues to operate, but with reduced security.", "gel": "Exploitation of this misconfiguration is common due to its simplicity and potential impact.", "grl": "Remediation documentation is widely available in resources such as CIS Benchmarks and Redis official documentation."}}','2026-06-25T05:11:11.718Z','2026-06-25T05:34:44.558Z');
INSERT INTO misconfigurations VALUES('a89dcfc3-d6d2-4989-98c4-36ab5114e1b2',7,'redis','/proc/sys/crypto/fips_enabled','0','1','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251234r961857_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The directive /proc/sys/crypto/fips_enabled controls Federal Information Processing Standards (FIPS) mode for cryptographic operations in the Linux kernel. Setting it to 0 disables FIPS mode, which may allow use of non-FIPS compliant algorithms and weaken the security of sensitive data. This is dangerous because it can expose your system to potential attacks that exploit vulnerabilities in non-compliant algorithms.", "potential_impact": ["Exposure of sensitive data due to use of non-FIPS compliant algorithms", "Potential for cryptographic attacks on sensitive data", "Compromised security compliance with FIPS standards"], "exploitation_scenario": {"prerequisites": ["Access to the system''s configuration files"], "example": "/echo 0 > /proc/sys/crypto/fips_enabled", "result": "Disabling of FIPS mode, allowing use of non-FIPS compliant algorithms"}, "metric_justifications": {"ac": "Why AC=L: Setting /proc/sys/crypto/fips_enabled to 0 is a simple operation that requires only writing a value to a file. No special preconditions beyond sending a command are needed.", "c": "Why C=P: Information about the cryptographic algorithms in use can be disclosed.", "i": "Why I=N: The configuration of the system''s cryptographic operations can be modified.", "a": "Why A=N: System availability is not directly affected by this misconfiguration.", "gel": "Why GEL=M: Exploitation of this type of misconfiguration is common due to its simplicity and potential impact.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available in security best practices and CIS benchmarks."}}','2026-06-25T05:11:11.729Z','2026-06-25T05:36:14.631Z');
INSERT INTO misconfigurations VALUES('5e9095dc-ad63-49ad-b191-8d56c7e8e995',7,'redis','tls_version','< v1.2','>= 1.2','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251237r961116_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The tls_version directive specifies the minimum TLS version to use for Redis connections. Setting it to < v1.2 allows usage of outdated and insecure versions of TLS, making the connection vulnerable to various attacks such as man-in-the-middle (MITM) attacks, downgrade attacks, and weak encryption.", "potential_impact": ["Data in transit can be intercepted and modified", "Authentication credentials can be exposed", "Confidentiality and integrity of sensitive data can be compromised"], "exploitation_scenario": {"prerequisites": ["An attacker within the network or able to perform a man-in-the-middle attack", "Knowledge of the Redis server''s IP address and port"], "example": "Example configuration: tls_version < v1.2 in redis.conf", "result": "The attacker can intercept, modify, or decrypt data transmitted between the client and the Redis server"}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by connecting to the Redis server using an outdated TLS version. No special preconditions beyond sending a request are required.", "c": "Why C=P: The attacker can read data in transit, including sensitive information such as authentication credentials and application data.", "i": "Why I=N: The attacker cannot modify the configuration or write data to the Redis server without additional privileges.", "a": "Why A=N: The availability of the Redis server is not directly affected by this misconfiguration, but the confidentiality and integrity of the data are compromised.", "gel": "Why GEL=M: Outdated TLS versions are commonly used in various attacks, making this type of misconfiguration a popular target for attackers.", "grl": "Why GRL=H: Remediation documentation is widely available and easy to follow, but the consequences of not addressing this issue can lead to serious security breaches."}}','2026-06-25T05:11:11.735Z','2026-06-25T05:37:03.727Z');
INSERT INTO misconfigurations VALUES('02dc58fc-2bdb-47cf-97ec-6aa9665b197e',7,'redis','certificate','insecure_value','certificate issued by DoD PKI or DoD-approved PKI Certification Authorities (CAs)','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251239r961596_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The Redis server is configured with an insecure certificate (insecure_value), which can lead to man-in-the-middle attacks and data interception. This misconfiguration allows unauthenticated attackers to impersonate the server, potentially compromising sensitive data.", "potential_impact": ["Data interception", "Man-in-the-middle attacks", "Compromised secure communication"], "exploitation_scenario": {"prerequisites": ["Network access to the Redis server"], "example": "An attacker can simply connect to the Redis server and use the insecure certificate for man-in-the-middle attacks.", "result": "The attacker can intercept and modify data transmitted between the client and the Redis server."}, "metric_justifications": {"ac": "Why AC=L: exploiting this misconfiguration requires only network access to the Redis server, making it easy for an unauthenticated attacker.", "c": "Why C=P: the insecure certificate allows an attacker to read sensitive data transmitted between the client and the Redis server.", "i": "Why I=N: the insecure certificate does not allow an attacker to modify the configuration of the Redis server.", "a": "Why A=N: the insecure certificate does not directly affect the availability of the Redis server.", "gel": "Why GEL=M: man-in-the-middle attacks on insecure certificates are common and easy to execute.", "grl": "Why GRL=H: remediation documentation for this misconfiguration is widely available."}}','2026-06-25T05:11:11.742Z','2026-06-25T05:37:48.148Z');
INSERT INTO misconfigurations VALUES('e8795a59-86f6-41fb-8617-2a9bec85ad02',7,'redis','persistence','insecure_value','Append Only File (AOF) - fsync every write','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251240r961122_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''persistence'' directive determines how Redis saves its data when it shuts down or crashes. Setting it to ''insecure_value'' means Redis will save data without fsync, which can lead to data loss or inconsistency in case of a sudden interruption. This configuration is dangerous as it exposes the system to potential data corruption and loss.", "potential_impact": ["Data integrity issues", "Potential data loss", "System instability"], "exploitation_scenario": {"prerequisites": ["An attacker with access to Redis server"], "example": "Example config: persistence insecure\nHTTP request: None (the misconfiguration is in the configuration file itself)", "result": "Data loss or corruption during a sudden interruption"}, "metric_justifications": {"ac": "Exploitation of this misconfiguration is easy as it only requires an attacker to access the Redis server and modify its configuration. No special skills or tools are needed beyond basic system administration.", "c": "Sensitive data stored in Redis can be disclosed if not saved correctly due to the lack of fsync.", "i": "The configuration can be modified, potentially leading to data loss or inconsistency issues.", "a": "Availability is affected as the system may become unstable or lose data during a sudden interruption.", "gel": "This type of misconfiguration is common and easy to exploit, making it a frequent target for attackers.", "grl": "Remediation documentation is widely available, making it relatively straightforward to correct this issue."}}','2026-06-25T05:11:11.748Z','2026-06-25T05:38:24.278Z');
INSERT INTO misconfigurations VALUES('4c38bc3c-5378-4cda-aa83-a1e0fb84b54c',7,'redis','UMASK','022','077','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251247r961149_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The UMASK directive sets the default file permissions for new files and directories created by Redis. A value of 022 allows group write access, which can lead to unintended data modification or exposure. The recommended value is 077, restricting all write access to the owner.", "potential_impact": ["Unauthorized group members may modify data", "Sensitive data may be exposed to group members", "Data integrity may be compromised"], "exploitation_scenario": {"prerequisites": ["Access to Redis configuration file", "Ability to modify the UMASK value"], "example": "In redis.conf: ''umask 022''. An attacker can change this to gain group write access.", "result": "Group members can now modify or view files created by Redis"}, "metric_justifications": {"ac": "Exploitation is easy as it only requires modifying the UMASK value in the redis.conf file", "c": "File permissions allow group read access, disclosing sensitive data", "i": "File permissions allow group write access, enabling data modification", "a": "Data availability remains unaffected as this is a configuration issue", "gel": "Misconfigurations like this are common and can be easily exploited by attackers", "grl": "Remediation documentation is widely available in security best practices"}}','2026-06-25T05:11:11.754Z','2026-06-25T05:39:02.733Z');
INSERT INTO misconfigurations VALUES('3f4a4ef0-d8b1-422d-bbbd-845f6079af6e',7,'redis','lua_scripts_enabled','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251251r961158_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The lua_scripts_enabled directive, when set to true, allows Redis to execute Lua scripts as part of its operations. This can lead to unintended code execution and potential data manipulation or exposure if insecure scripts are used.", "potential_impact": ["Data manipulation", "Unauthorized script execution", "Potential data exposure"], "exploitation_scenario": {"prerequisites": ["Access to Redis server", "Knowledge of Lua scripting"], "example": "Setting lua_scripts_enabled to true in the Redis configuration file: ''redis.conf''.", "result": "Arbitrary code execution within the Redis environment."}, "metric_justifications": {"ac": "Why AC=L: Enabling Lua scripts requires only setting a configuration option, making it easy for an attacker to exploit if the scripts are insecure.", "c": "Why C=P: No sensitive information is disclosed by default when lua_scripts_enabled is set to true.", "i": "Why I=N: Lua scripts can modify Redis data structures and potentially manipulate or expose sensitive data.", "a": "Why A=N: The availability of the Redis server may be affected if insecure scripts cause errors or crashes.", "gel": "Why GEL=M: Misconfigurations involving lua_scripts_enabled are relatively common, making exploitation frequent.", "grl": "Why GRL=H: Remediation documentation is widely available and easy to follow."}}','2026-06-25T05:11:11.760Z','2026-06-25T05:40:26.274Z');
INSERT INTO misconfigurations VALUES('a2e3b1a7-e123-454c-a48a-fc5aa2b6bdb4',7,'redis','max_connections','10k','<number_of_connections>','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-251183r960735_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The max_connections directive in Redis limits the number of client connections that can be established simultaneously. Setting it to a high value like 10k can lead to exhaustion of system resources, causing denial of service or unstable server behavior.", "potential_impact": ["Resource exhaustion leading to denial of service", "Unstable server behavior affecting other services", "Potential for increased network traffic"], "exploitation_scenario": {"prerequisites": ["An attacker with network access to the Redis instance", "Knowledge of Redis configuration and command structure"], "example": "Example: Redis config snippet: maxconnections 10000. An attacker can send multiple concurrent requests to exhaust available connections.", "result": "Server becomes unresponsive or crashes due to resource exhaustion."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit max_connections=10k by sending multiple concurrent requests, overwhelming the server''s resources.", "c": "Why C=P: No sensitive data is disclosed or readable due to this misconfiguration.", "i": "Why I=N: No configuration or data can be modified directly through this misconfiguration.", "a": "Why A=N: The availability of other services may be affected indirectly due to resource exhaustion, but the Redis instance itself is not directly affected.", "gel": "Why GEL=M: This type of misconfiguration allows for frequent exploitation by an attacker with knowledge of Redis configuration.", "grl": "Why GRL=H: Remediation documentation is widely available, but the impact of this misconfiguration may require system reboot or resource management adjustments."}}','2026-06-25T05:11:11.772Z','2026-06-25T05:41:09.327Z');
INSERT INTO misconfigurations VALUES('615cf980-61c4-4a49-9a94-24745a25851a',8,'tomcat','keystore password','changeit','secure_password','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222931r1137578_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The keystore password ''changeit'' is a dangerous default value as it provides unauthorized access to the Tomcat server''s SSL configuration. This can lead to man-in-the-middle attacks, data interception, and certificate misuse.", "potential_impact": ["Unauthorized access to SSL configuration", "Data interception during communication", "Man-in-the-middle attacks"], "exploitation_scenario": {"prerequisites": ["Knowledge of the default password ''changeit''", "Network access to the Tomcat server"], "example": "HTTP request: GET /manager/html HTTP/1.1\nHost: tomcat-server\nAccept: text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8\nAuthorization: Basic base64(base64(''changeit''))", "result": "Successful access to the Tomcat server''s SSL configuration"}, "metric_justifications": {"ac": "Why AC=L: Exploitation is easy as an unauthenticated attacker can trigger this with a standard HTTP request using the default password ''changeit''.", "c": "Why C=P: The server''s SSL configuration is disclosed, including private keys and certificates.", "i": "Why I=N: No data or configuration can be modified directly due to the read-only nature of the SSL configuration.", "a": "Why A=N: Availability remains unaffected as unauthorized access does not cause service disruption.", "gel": "Why GEL=M: This type of misconfiguration is common, making it a frequent target for attackers.", "grl": "Why GRL=H: Remediation documentation is widely available, but the success of remediation depends on the timely change of the keystore password."}}','2026-06-25T05:52:04.055Z','2026-06-25T05:54:49.093Z');
INSERT INTO misconfigurations VALUES('59417c4d-834e-4c36-a8c8-9937a79a975c',8,'tomcat','com.sun.management.jmxremote.ssl','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222964r1016511_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The com.sun.management.jmxremote.ssl directive is used to enable SSL for JMX connections in Tomcat. Setting it to false disables SSL, making JMX connections vulnerable to eavesdropping and man-in-the-middle attacks. This misconfiguration exposes sensitive data such as usernames, passwords, and server configurations to unauthorized parties.", "potential_impact": ["Exposure of sensitive data", "Unauthorized access to server configuration", "Potential for server compromise"], "exploitation_scenario": {"prerequisites": ["Network access to the Tomcat server", "Knowledge of JMX port (default: 1099)"], "example": "HTTP request: `telnet localhost 1099` followed by a JMX connection using a tool like JConsole or jmxterm", "result": "Unencrypted communication between the client and server, allowing an attacker to intercept and manipulate data"}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, exploiting the lack of SSL protection.", "c": "Why C=P: Sensitive information such as usernames, passwords, and server configurations are disclosed.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration.", "a": "Why A=N: Server availability is not affected by this misconfiguration.", "gel": "Why GEL=M: This type of misconfiguration is common due to its simplicity and the potential for sensitive data exposure.", "grl": "Why GRL=H: Remediation documentation is widely available in security best practices, such as the CIS Tomcat Benchmark."}}','2026-06-25T05:52:04.060Z','2026-06-25T05:55:35.179Z');
INSERT INTO misconfigurations VALUES('6fb9ff4c-e97d-4580-ae5f-9914657bd1f8',8,'tomcat','connectionURL','ldap://localhost:389','ldaps://localhost:636','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222965r961029_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The connectionURL directive specifies the LDAP server to use for authentication and authorization. The provided value ldap://localhost:389 uses an unencrypted LDAP connection, which is insecure as it transmits sensitive data in plain text. This can lead to interception of credentials by unauthorized parties.", "potential_impact": ["Exposure of user credentials", "Unauthorized access to Tomcat resources", "Potential for privilege escalation"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server configuration"], "example": "In the provided configuration, the connectionURL is set to ldap://localhost:389. This can be exploited by an attacker intercepting network traffic or by configuring a man-in-the-middle (MITM) attack.", "result": "The attacker gains access to user credentials transmitted over the insecure LDAP connection."}, "metric_justifications": {"ac": "Why AC=L: An unencrypted LDAP connection can be exploited by simply intercepting network traffic, making it easy for any attacker with basic network monitoring skills.", "c": "Why C=P: Sensitive user credentials are disclosed in plain text over the network.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration.", "a": "Why A=N: The availability of Tomcat resources is not affected by this misconfiguration, but the security of those resources is compromised.", "gel": "Why GEL=M: Misconfigurations involving unencrypted LDAP connections are common and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation documentation for securing LDAP connections is widely available, but the specific configuration may require manual adjustment."}}','2026-06-25T05:52:04.066Z','2026-06-25T05:56:19.689Z');
INSERT INTO misconfigurations VALUES('4aa97367-678e-4d47-8cf3-96b15c0be9f7',8,'tomcat','FIPSMode','off','on','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222968r961050_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The FIPSMode directive is used to enable or disable Federal Information Processing Standards (FIPS) mode in Tomcat. Setting FIPSMode to ''off'' disables FIPS mode, which may expose the application to potential security vulnerabilities as it allows the use of non-FIPS compliant cryptographic algorithms. This can lead to weakened encryption and increased risk of data interception.", "potential_impact": ["Data interception", "Unauthorized access", "Altered or forged digital signatures"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat configuration files"], "example": "Setting FIPSMode to ''off'' in the server.xml file: `<Manager className=\"org.apache.catalina.manager.ManagerServlet\" \n   accessClassName=\"org.apache.catalina.manager.ManagerServlet\" \n   pathname=\"manager\" \n   auth=\"container\" \n   debug=\"0\" \n   FIPSMode=\"off\"/>''", "result": "Use of non-FIPS compliant cryptographic algorithms, potentially leading to weakened encryption and increased risk of data interception"}, "metric_justifications": {"ac": "Setting FIPSMode to ''off'' is easy as it only requires modifying a configuration file. No special preconditions beyond sending a request are required.", "c": "FIPS mode off allows the use of non-FIPS compliant cryptographic algorithms, potentially exposing sensitive data.", "i": "With FIPSMode set to ''off'', it is possible to modify the configuration to use non-FIPS compliant cryptographic algorithms.", "a": "Availability is not affected as setting FIPSMode to ''off'' does not directly impact the availability of the application.", "gel": "Exploitation of this misconfiguration is common due to its ease and potential impact.", "grl": "Remediation documentation for this issue is widely available in security resources."}}','2026-06-25T05:52:04.072Z','2026-06-25T05:57:21.388Z');
INSERT INTO misconfigurations VALUES('bef1d1e8-2156-405f-923a-72c33ebd0202',8,'tomcat','secure','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222932r1137578_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''secure'' directive is set to ''false'', which allows unauthenticated attackers to access Tomcat manager and host manager applications. This configuration exposes sensitive information and provides an attack vector for further exploitation.", "potential_impact": ["Unauthorized access to Tomcat manager and host manager applications", "Exposure of server configuration details", "Potential for data manipulation or server misconfiguration"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat web application"], "example": "HTTP request: GET http://target.com/manager/html", "result": "Access granted to Tomcat manager application"}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it easy to exploit.", "c": "Why C=P: Server configuration details are disclosed when the ''secure'' directive is set to ''false''.", "i": "Why I=N: No data or configuration can be modified directly due to the lack of write access in this scenario.", "a": "Why A=N: The availability of the server remains unaffected as long as no denial-of-service attack is launched after gaining unauthorized access.", "gel": "Why GEL=M: Misconfigurations of this nature are common and can be easily discovered by automated tools or script kiddies.", "grl": "Why GRL=H: Remediation documentation for securing the ''secure'' directive is widely available in resources such as CIS Benchmarks."}}','2026-06-25T05:52:04.077Z','2026-06-25T05:58:06.693Z');
INSERT INTO misconfigurations VALUES('175c5b84-ecfb-4d73-8dcf-ebeb00d49275',8,'tomcat','http-only','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222933r1137578_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The http-only directive is used to prevent client-side scripts (e.g., JavaScript) from accessing session cookies over insecure channels. Setting http-only to false allows cross-site scripting (XSS) attacks to steal session cookies, potentially leading to unauthorized account takeover.", "potential_impact": ["Account takeover", "Unauthorized access to sensitive data", "Privacy breaches"], "exploitation_scenario": {"prerequisites": ["Successful XSS attack on the target web application"], "example": "In a vulnerable Tomcat configuration, an attacker could inject malicious JavaScript into a page viewed by the victim. The script would read the session cookie and send it to the attacker''s server.", "result": "The attacker gains access to the victim''s session, allowing them to impersonate the user and perform actions on their behalf."}, "metric_justifications": {"ac": "Setting http-only to false makes it easy for an attacker to steal session cookies via XSS attacks, as they can be accessed by client-side scripts.", "c": "Session cookies are disclosed to the attacker when http-only is set to false.", "i": "The attacker can modify the victim''s session by impersonating them after stealing the session cookie.", "a": "Availability is not directly affected, but unauthorized actions performed by the attacker could impact system resources or data integrity.", "gel": "XSS attacks are common and easy to execute, making it likely that this misconfiguration will be exploited.", "grl": "Remediation documentation for setting http-only to true is widely available."}}','2026-06-25T05:52:04.082Z','2026-06-25T05:59:30.699Z');
INSERT INTO misconfigurations VALUES('50c927de-47d2-414e-b7ec-b16bbd6ecbeb',8,'tomcat','readonly','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222934r1137578_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''readonly'' directive is set to false, allowing unauthenticated attackers to modify Tomcat configuration files. This can lead to server misconfiguration, data corruption, or even a complete compromise of the system.", "potential_impact": ["Configuration changes leading to server instability", "Data corruption or loss", "Unauthorized access to sensitive information"], "exploitation_scenario": {"prerequisites": ["Network access to the Tomcat server"], "example": "For example, an attacker can modify the ''server.xml'' file by sending a PUT request to ''/manager/textarea?path=conf/server.xml&text=<Context docBase=\"myapp\" path=\"/myapp\"/>''.", "result": "The server configuration is modified, potentially causing it to behave unpredictably or allowing the attacker to deploy their own web application."}, "metric_justifications": {"ac": "Why AC=L: With readonly set to false, an attacker can modify Tomcat configuration files with a standard HTTP request, making this exploit easy.", "c": "Why C=P: Sensitive information such as usernames, passwords, and server settings are disclosed or readable.", "i": "Why I=N: The web root directory and its contents can be modified.", "a": "Why A=N: Server availability is affected if the attacker''s modifications cause the server to malfunction or crash.", "gel": "Why GEL=M: This type of misconfiguration is common, making it a frequent target for attackers.", "grl": "Why GRL=H: Remediation documentation is widely available and easy to follow."}}','2026-06-25T05:52:04.087Z','2026-06-25T06:00:14.338Z');
INSERT INTO misconfigurations VALUES('4928b4bb-7ff5-4451-84b5-01cfc72fe08c',8,'tomcat','scheme','http','https','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222935r1137578_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''scheme'' directive specifies the protocol used for Tomcat connections. Using ''http'' instead of the recommended ''https'' exposes the application to unencrypted data transmission, making it vulnerable to eavesdropping and man-in-the-middle attacks. This misconfiguration can lead to sensitive data exposure and unauthorized access.", "potential_impact": ["Data theft", "Unauthorized access", "Man-in-the-middle attacks"], "exploitation_scenario": {"prerequisites": ["Knowledge of the vulnerable Tomcat instance''s IP address or domain name"], "example": "HTTP request: GET http://<vulnerable_tomcat_instance>", "result": "Unencrypted data transmission and potential access to sensitive information"}, "metric_justifications": {"ac": "An unauthenticated attacker can trigger this with a standard HTTP request, making it easy to exploit.", "c": "Sensitive application data is disclosed during unencrypted transmission.", "i": "No write access is required as the attacker only intercepts and reads data, not modifying it.", "a": "Availability is affected indirectly as unencrypted data can be intercepted and potentially used for further attacks.", "gel": "This type of misconfiguration is common due to its simplicity and ease of exploitation.", "grl": "Remediation documentation is widely available, making it straightforward to address."}}','2026-06-25T05:52:04.091Z','2026-06-25T06:00:54.590Z');
INSERT INTO misconfigurations VALUES('8d1d1a97-5df4-41c3-818f-4ec2911a1839',8,'tomcat','pattern','','%h %l %t %u "%r" %s %b','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222985r961362_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "pattern= is a security misconfiguration. Fallback: LLM unavailable.", "potential_impact": ["Fallback: LLM unavailable."], "exploitation_scenario": {"prerequisites": [], "example": "# Configuration\npattern ", "result": "Security risk introduced by this configuration."}, "metric_justifications": {"ac": "AC=L (Low complexity): pattern= can be exploited directly via a standard HTTP request, with no additional preconditions beyond network reachability.", "c": "Partial: limited impact within the scope of the web application.", "i": "None: this metric is not impacted by this misconfiguration.", "a": "None: this metric is not impacted by this misconfiguration.", "gel": "Medium exploitation rate -- exploit code exists and is occasionally used.", "grl": "CIS Benchmark section SV-222985r961362_rule documents the official remediation."}}','2026-06-25T05:52:04.096Z','2026-06-25T06:34:18.462Z');
INSERT INTO misconfigurations VALUES('26fe4f7f-0f75-41c4-93a4-aeee0c07b56b',8,'tomcat','$CATALINA_BASE/logs permissions','740','750','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222943r960930_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/logs permissions set to 740 grants write access to the group, allowing unauthenticated attackers to modify log files and potentially hide their activities or inject malicious commands. This could lead to data tampering, privacy breaches, and unauthorized system changes.", "potential_impact": ["Data tampering", "Privacy breach", "Unauthorized system changes"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server"], "example": "An attacker can modify log files by sending a simple HTTP PUT request with the desired content.", "result": "Modified log files may hide malicious activities or contain false information, compromising system integrity and security."}, "metric_justifications": {"ac": "Why AC=L: The specific conditions for $CATALINA_BASE/logs permissions=740 allow an unauthenticated attacker to modify log files with a standard HTTP request, making the exploitation easy.", "c": "Why C=P: Log files contain sensitive information such as user requests, application errors, and system events that can be disclosed or read by the group.", "i": "Why I=N: The group has write access to log files, but no data or configuration can be modified directly due to the nature of log files.", "a": "Why A=N: Modifying log files does not affect system availability as they are intended for monitoring and debugging purposes.", "gel": "Why GEL=M: Misconfigurations allowing write access to log files are common, making exploitation frequent for this type of misconfiguration.", "grl": "Why GRL=H: Remediation documentation is widely available in security best practices and Tomcat configuration guides."}}','2026-06-25T05:52:04.110Z','2026-06-25T06:05:25.087Z');
INSERT INTO misconfigurations VALUES('262c030d-1a39-418a-90dd-9c0ddd76d2a1',8,'tomcat','$CATALINA_BASE/logs/* permissions','insecure_value (not 640)','640','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222944r960930_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/logs/* permissions being set to insecure_value (not 640) allows unauthenticated attackers to read Tomcat server logs, potentially exposing sensitive information such as application errors, user credentials, and internal system details. This can aid an attacker in understanding the application structure, identifying vulnerabilities, or even executing further attacks.", "potential_impact": ["Exposure of sensitive application data", "Identification of potential vulnerabilities", "Possible execution of further attacks"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server over the network"], "example": "HTTP GET request to $CATALINA_BASE/logs/catalina.out", "result": "Reading of server logs containing sensitive information"}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily read the Tomcat server logs by sending a standard HTTP request to the log files, without requiring any special preconditions.", "c": "Why C=P: The server logs contain sensitive information such as application errors, user credentials, and internal system details that are disclosed when permissions are not set correctly.", "i": "Why I=N: There is no write access to the log files when permissions are incorrectly set, so data or configuration cannot be modified.", "a": "Why A=N: The availability of the Tomcat server remains unaffected as an attacker can only read the logs, not disrupt their functionality.", "gel": "Why GEL=M: Misconfigurations in log file permissions are common and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation documentation for setting correct log file permissions is widely available."}}','2026-06-25T05:52:04.116Z','2026-06-25T06:06:12.375Z');
INSERT INTO misconfigurations VALUES('3a028a0f-f357-48de-9261-1af0c1fec43b',8,'tomcat','$CATALINA_BASE/conf/* file permissions','permissions other than 640','640','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222945r960933_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/conf/* file permissions should be set to 640 for security reasons. Any other permissions allow unauthorized users (including attackers) to read or modify Tomcat configuration files, potentially leading to server misconfiguration, data exposure, or denial of service.", "potential_impact": ["Unauthorized reading of sensitive configuration data", "Modification of server settings", "Denial of service due to incorrect configurations"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server", "Knowledge of file system permissions"], "example": "For instance, a configuration file with permissions 755 can be read by any user in the group that owns the file.", "result": "An attacker can modify or read sensitive data, causing unintended behavior or data exposure."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily change permissions of Tomcat configuration files to gain read or write access if they are not set to 640 (read-write for owner, no access for group or others).", "c": "Why C=P: Configuration files contain sensitive information such as server settings and database credentials that should be protected from unauthorized reading.", "i": "Why I=N: Modifying configuration files can lead to server misconfiguration, data exposure, or denial of service.", "a": "Why A=N: Server availability is not directly affected by incorrect file permissions, but improper configurations may cause downtime indirectly.", "gel": "Why GEL=M: Misconfigured file permissions are a common issue in Tomcat deployments and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available, making it easy to correct the misconfiguration."}}','2026-06-25T05:52:04.119Z','2026-06-25T06:06:58.530Z');
INSERT INTO misconfigurations VALUES('2d0b960e-b674-466b-ac0a-ba94a5a45ebd',8,'tomcat','$CATALINA_BASE/conf folder permissions','insecure_value (not 750)','750','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222946r960933_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/conf folder contains Tomcat''s configuration files which, if not properly protected, can lead to unauthorized modification or disclosure of sensitive settings. The insecure_value (not 750) for the folder permissions allows any user with access to the server to read and modify these files, potentially leading to server misconfiguration, data exposure, or denial of service.", "potential_impact": ["Unauthorized modification of Tomcat configuration settings", "Exposure of sensitive information such as passwords or database credentials", "Denial of service due to incorrect configuration"], "exploitation_scenario": {"prerequisites": ["Access to the server where Tomcat is installed", "Knowledge of the insecure folder permissions"], "example": "$ chmod -R insecure_value $CATALINA_BASE/conf", "result": "An attacker can read and modify sensitive configuration files, leading to potential data exposure or server misconfiguration"}, "metric_justifications": {"ac": "Why AC=L: The insecure folder permissions (not 750) allow any user with access to the server to read and modify Tomcat''s configuration files, making it easy for an attacker to exploit this misconfiguration.", "c": "Why C=P: With insecure permissions, sensitive configuration files can be read by unauthorized users.", "i": "Why I=N: The insecure permissions allow unauthorized modification of Tomcat''s configuration files.", "a": "Why A=N: The insecure permissions do not directly affect the server''s availability, but incorrect configurations could lead to denial of service.", "gel": "Why GEL=M: Misconfigurations of this type are common and can be easily discovered by attackers.", "grl": "Why GRL=H: Remediation documentation for securing Tomcat''s configuration files is widely available."}}','2026-06-25T05:52:04.124Z','2026-06-25T06:07:47.391Z');
INSERT INTO misconfigurations VALUES('c51cbf59-2032-411d-b255-981614e1fbb5',8,'tomcat','$CATALINA_HOME/bin/*jar permissions','not set to 640','640','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222947r960936_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_HOME/bin/*jar permissions not set to 640 allows unauthenticated attackers to read and modify Tomcat JAR files, potentially leading to code injection or information disclosure.", "potential_impact": ["Code injection allowing arbitrary command execution", "Information disclosure of sensitive configuration data", "Denial of Service by replacing or deleting critical Tomcat components"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server over the network"], "example": "An attacker can download a malicious JAR file and replace an existing one in $CATALINA_HOME/bin, modifying or replacing critical Tomcat components.", "result": "The modified Tomcat component will be executed with the privileges of the Tomcat user, potentially leading to code injection or information disclosure."}, "metric_justifications": {"ac": "An attacker can easily replace JAR files in $CATALINA_HOME/bin without authentication when permissions are not set to 640.", "c": "Sensitive configuration data and Tomcat components can be read by an unauthenticated attacker.", "i": "An unauthenticated attacker can modify or replace critical Tomcat components.", "a": "Availability is affected as the modified Tomcat component may cause a Denial of Service.", "gel": "This type of misconfiguration is common and easily exploitable by script kiddies.", "grl": "Remediation documentation for setting $CATALINA_HOME/bin/*jar permissions to 640 is widely available."}}','2026-06-25T05:52:04.128Z','2026-06-25T06:08:31.345Z');
INSERT INTO misconfigurations VALUES('6809c156-ddb4-4295-a6e3-72d8e9486784',8,'tomcat','$CATALINA_HOME/bin permissions','not 750','750','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222948r960939_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_HOME/bin permissions should be set to 750 for proper Tomcat operation and security. A value not equal to 750 can lead to unauthorized access or modification of Tomcat binaries, potentially allowing an attacker to execute arbitrary commands or disrupt the service.", "potential_impact": ["Unauthorized command execution", "Service disruption", "Potential data leakage"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat server", "Knowledge of Tomcat directory structure"], "example": "For instance, an attacker can change the permissions of a binary file by sending a request like: `HTTP PUT /bin/catalina.sh 0644`", "result": "This could result in unauthorized command execution or service disruption."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily change the permissions of Tomcat binaries by sending a simple HTTP request, without requiring any special preconditions beyond sending a request.", "c": "Why C=P: The attacker can read sensitive information about the Tomcat configuration and environment.", "i": "Why I=N: The attacker can modify Tomcat binaries, potentially causing unauthorized command execution or service disruption.", "a": "Why A=N: The attacker can disrupt the availability of the Tomcat service by modifying or deleting essential binaries.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to exploit, making it a frequent target for attackers.", "grl": "Why GRL=H: Remediation documentation is widely available in security best practices and Tomcat configuration guides."}}','2026-06-25T05:52:04.133Z','2026-06-25T06:09:14.902Z');
INSERT INTO misconfigurations VALUES('cbb9d923-26f8-4be6-bb36-2ddc9ce914b8',8,'tomcat','UMask','insecure_value','0027','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222949r960960_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The UMask directive sets the file creation mask for Tomcat processes. An insecure value of ''insecure_value'' allows unintended permissions to be set on newly created files and directories, potentially exposing sensitive data or allowing unauthorized modifications.", "potential_impact": ["Unauthorized read access to sensitive files", "Unauthorized write access to web content", "Potential for privilege escalation"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat''s configuration files"], "example": "Setting UMask=0000 in the tomcat-users.conf file", "result": "Newly created files and directories will have no permissions set, allowing any user with access to the system to read, write, or modify them."}, "metric_justifications": {"ac": "Why AC=L: Setting UMask to an insecure value allows any unauthenticated attacker to create files with overly permissive permissions by simply creating a new file within the Tomcat webapps directory.", "c": "Why C=P: With insecure UMask settings, sensitive files such as logs or configuration files may be readable by unauthorized users.", "i": "Why I=N: An attacker with insecure UMask settings can modify web content, potentially leading to data tampering or defacement.", "a": "Why A=N: Insecure UMask settings do not directly affect the availability of the system.", "gel": "Why GEL=M: Misconfigurations involving UMask are common and easy to exploit.", "grl": "Why GRL=H: Remediation for this issue is well-documented in resources such as the CIS Tomcat Benchmark."}}','2026-06-25T05:52:04.138Z','2026-06-25T06:10:01.761Z');
INSERT INTO misconfigurations VALUES('cb81df7f-3a0b-4518-8b66-23182420ad7e',8,'tomcat','allowTrace','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222950r960963_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''allowTrace'' directive is set to true, which enables HTTP trace method (HTTP VERB TRACE). This allows an unauthenticated attacker to capture internal server communications, potentially exposing sensitive data such as session IDs, application logic, and server responses. It can also be used for Denial of Service attacks by flooding the server with TRACE requests.", "potential_impact": ["Exposure of sensitive data", "Denial of Service"], "exploitation_scenario": {"prerequisites": ["Internet access and ability to send HTTP requests"], "example": "HTTP request: GET /trace HTTP/1.1 Host: example.com", "result": "Internal server communications are captured and potentially exposed"}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it easy to exploit.", "c": "Why C=P: Internal server communications are disclosed.", "i": "Why I=N: No data or configuration can be modified directly.", "a": "Why A=N: Server availability is not affected significantly.", "gel": "Why GEL=M: This type of misconfiguration is commonly found in Tomcat servers, making it a frequent target for attackers.", "grl": "Why GRL=H: Remediation documentation is widely available and easy to implement."}}','2026-06-25T05:52:04.143Z','2026-06-25T06:10:36.358Z');
INSERT INTO misconfigurations VALUES('1e2e4b69-583e-458a-a267-00bf49e82e05',8,'tomcat','port','any_value_other_than_-1','-1','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222951r960963_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The Tomcat server should listen on a specific port (-1) as defined in the server.xml configuration file. Using any other value for the port directive can expose the server to potential attacks and unauthorized access.", "potential_impact": ["An attacker can potentially gain unauthorized access to the Tomcat server", "Confidential data may be exposed or leaked", "The availability of the server can be compromised"], "exploitation_scenario": {"prerequisites": ["Knowledge of the Tomcat server''s misconfigured port"], "example": "For instance, if the port is set to 8081 in the server.xml file instead of -1, an attacker can attempt to access the server by sending a request to http://target_server:8081", "result": "The attacker gains unauthorized access to the Tomcat server and potentially sensitive data"}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily discover the misconfigured port by sending a standard HTTP request to the server, making it easy to exploit.", "c": "Why C=P: The attacker can potentially read sensitive data from the Tomcat server.", "i": "Why I=N: The attacker can potentially modify the server''s configuration or data.", "a": "Why A=N: The availability of the server can be compromised if an attacker gains unauthorized access.", "gel": "Why GEL=M: Misconfigurations of this type are common, making exploitation frequent.", "grl": "Why GRL=H: Remediation documentation is widely available and easy to follow."}}','2026-06-25T05:52:04.148Z','2026-06-25T06:11:24.972Z');
INSERT INTO misconfigurations VALUES('aa00e89f-2044-4bb9-a6b0-122342c6d546',8,'tomcat','deployXML','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222955r960963_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The deployXML directive set to true allows an attacker to deploy web applications without authentication, posing a significant security risk. This configuration enables unauthenticated users to manipulate the Tomcat server by uploading malicious web applications.", "potential_impact": ["Unauthorized deployment of malicious web applications", "Potential for server takeover and data breaches", "Disruption of service due to malicious activity"], "exploitation_scenario": {"prerequisites": ["Network access to the Tomcat server", "Knowledge of the Tomcat manager/host-manager web application URL"], "example": "HTTP PUT request to http://tomcat_server:8080/manager/textdb with a malicious WAR file as the body", "result": "Successful deployment of the malicious web application on the Tomcat server"}, "metric_justifications": {"ac": "Why AC=L: exploitation involves sending a simple HTTP PUT request, making it easy for any unauthenticated attacker to trigger this with a standard request.", "c": "Why C=P: no sensitive data is disclosed or readable due to the nature of the deployXML directive.", "i": "Why I=N: only web application deployment configuration can be modified, but not other server settings or data.", "a": "Why A=N: the availability of the Tomcat server remains unaffected as long as the malicious web application does not cause a denial-of-service.", "gel": "Why GEL=M: this type of misconfiguration is common and can be easily discovered by automated security scanners.", "grl": "Why GRL=H: remediation documentation is widely available, such as the CIS Tomcat Benchmark."}}','2026-06-25T05:52:04.153Z','2026-06-25T06:12:13.960Z');
INSERT INTO misconfigurations VALUES('29de1ec8-bd26-4eb4-b2b4-e372634d10b4',8,'tomcat','privileged','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222961r1043177_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''privileged'' directive set to true allows an unauthenticated attacker to execute commands with root privileges on the Tomcat server. This misconfiguration poses a significant security risk as it bypasses the intended access controls.", "potential_impact": ["Unauthorized command execution", "Potential data theft or modification", "Server downtime due to malicious actions"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server", "Knowledge of the ''privileged'' directive"], "example": "For example, in the server.xml file: <Host appBase=\"webapps\" privileged=\"true\">. An attacker can then send a request to execute commands such as ''whoami'' or ''ls -la''.", "result": "The server executes the command with root privileges, providing the attacker with sensitive information or allowing them to modify the system."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it easy to exploit.", "c": "Why C=P: Sensitive server information and files are disclosed or readable.", "i": "Why I=N: The system configuration can be modified, potentially causing long-term damage.", "a": "Why A=N: Server availability is affected as the attacker can cause downtime or modify critical services.", "gel": "Why GEL=M: This type of misconfiguration is common and easily exploited by script kiddies.", "grl": "Why GRL=H: Remediation documentation is widely available, but proper configuration management is crucial to prevent such issues."}}','2026-06-25T05:52:04.156Z','2026-06-25T06:13:44.050Z');
INSERT INTO misconfigurations VALUES('acb50758-d360-4c01-96ff-0d894d2a505e',8,'tomcat','com.sun.management.jmxremote.authenticate','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222963r960972_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The com.sun.management.jmxremote.authenticate directive determines whether remote JMX connections require authentication. Setting it to false allows unauthenticated access to JMX interfaces, potentially leading to server compromise.", "potential_impact": ["Unauthorized read/write access to JMX interfaces", "Manipulation of Tomcat configuration", "Exploitation of other vulnerabilities via JMX"], "exploitation_scenario": {"prerequisites": ["Knowledge of the server''s Tomcat configuration", "Ability to send an HTTP request"], "example": "HTTP POST request to modify the Tomcat server''s JMX settings: `POST http://target-server:8080/manager/text/jmx?q=com.sun.management.jmxremote.authenticate=false&t=set`", "result": "Unauthenticated attacker gains access to JMX interfaces"}, "metric_justifications": {"ac": "Setting com.sun.management.jmxremote.authenticate to false (false) makes it easy for any unauthenticated attacker to trigger this with a standard HTTP request", "c": "With authenticated access disabled, sensitive configuration data can be read", "i": "Unauthenticated attackers can modify Tomcat''s JMX settings", "a": "Availability is not directly affected by this misconfiguration", "gel": "This type of misconfiguration is common due to its simplicity", "grl": "Remediation documentation for this issue is widely available"}}','2026-06-25T05:52:04.162Z','2026-06-25T06:14:32.357Z');
INSERT INTO misconfigurations VALUES('54d1d958-8e59-42f6-8803-c0d6d9b3660a',8,'tomcat','keystore_location','','/opt/tomcat/conf/<filename.jks>','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222967r985893_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The keystore_location directive specifies the path to the Java KeyStore file containing Tomcat''s SSL certificates. A misconfiguration of this directive can expose sensitive data or allow an attacker to impersonate Tomcat, leading to man-in-the-middle attacks and data breaches. In this case, the provided bad value does not specify a secure location for the KeyStore file.", "potential_impact": ["Exposure of SSL certificates", "Man-in-the-middle attacks", "Data breaches"], "exploitation_scenario": {"prerequisites": ["Network access to Tomcat server"], "example": "HTTP request: GET http://<tomcat_server>/conf/ (without a specific filename.jks)", "result": "Access to SSL certificates or ability to impersonate Tomcat"}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily access the KeyStore file if it is not properly secured by specifying an insecure location. No special preconditions beyond sending a request are required.", "c": "Why C=P: SSL certificates are disclosed, potentially allowing for man-in-the-middle attacks.", "i": "Why I=N: The KeyStore file can be read but not modified without additional privileges.", "a": "Why A=N: Availability is not directly affected as the service remains operational.", "gel": "Why GEL=M: Misconfigurations of keystore_location are common and can easily lead to exploitation.", "grl": "Why GRL=H: Remediation documentation for securing the KeyStore file is widely available."}}','2026-06-25T05:52:04.167Z','2026-06-25T06:15:22.903Z');
INSERT INTO misconfigurations VALUES('7c5aece1-6502-4b31-8669-1473bce451aa',8,'tomcat','certificationVerification','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222971r1136930_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''certificationVerification'' directive is set to false, which disables SSL certificate verification for incoming connections. This misconfiguration allows man-in-the-middle attacks, where an attacker can intercept and modify data, impersonate servers, or perform other malicious activities undetected.", "potential_impact": ["Data integrity compromise", "Confidentiality breach", "Unauthorized access"], "exploitation_scenario": {"prerequisites": ["Network-level access to the Tomcat server"], "example": "An attacker can send a request to the Tomcat server with a forged SSL certificate. If ''certificationVerification'' is set to false, the server will accept the fake certificate and establish an encrypted connection.", "result": "The attacker can intercept, modify, or inject data as it passes between the client and the server."}, "metric_justifications": {"ac": "Why AC=L: setting ''certificationVerification'' to false allows an unauthenticated attacker to trigger this with a standard HTTPS request.", "c": "Why C=P: the attacker can read all data transmitted over the connection, including sensitive information such as usernames, passwords, and credit card numbers.", "i": "Why I=N: the attacker cannot directly modify server configuration or data through this vulnerability, but can manipulate the data being transmitted.", "a": "Why A=N: the attacker can disrupt availability indirectly by modifying or blocking data transmission, but the primary impact is on integrity and confidentiality.", "gel": "Why GEL=M: man-in-the-middle attacks are common and this misconfiguration makes Tomcat servers more susceptible to them.", "grl": "Why GRL=H: remediation documentation for this issue is widely available, but proper configuration requires careful attention."}}','2026-06-25T05:52:04.172Z','2026-06-25T06:16:18.468Z');
INSERT INTO misconfigurations VALUES('98869937-8282-477c-be80-d4560136ca2a',8,'tomcat','showServerInfo','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222975r961167_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The showServerInfo directive set to true allows unauthenticated attackers to retrieve sensitive server information such as Tomcat version, installed JVM version, and system properties. This can aid an attacker in identifying potential vulnerabilities.", "potential_impact": ["Disclosure of sensitive server information", "Identification of potential vulnerabilities", "Possible escalation of privileges"], "exploitation_scenario": {"prerequisites": ["None, an attacker only needs to send a request to the Tomcat server"], "example": "HTTP GET request: http://target-tomcat-server/manager/status", "result": "Server information is returned in the response"}, "metric_justifications": {"ac": "Why AC=L: An attacker can trigger this with a standard HTTP request, requiring no special preconditions or expertise.", "c": "Why C=P: Sensitive server information is disclosed.", "i": "Why I=N: No data or configuration can be modified.", "a": "Why A=N: Server availability remains unaffected.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to exploit.", "grl": "Why GRL=H: Remediation documentation is widely available"}}','2026-06-25T05:52:04.177Z','2026-06-25T06:16:55.847Z');
INSERT INTO misconfigurations VALUES('bb431d9e-249b-453f-a628-8dd55e5093bb',8,'tomcat','showReport','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222977r961170_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''showReport'' directive, when set to true, allows unauthenticated attackers to trigger the generation of a detailed Tomcat server report. This report may contain sensitive information such as server version, installed modules, and system configuration details.", "potential_impact": ["Exposure of internal server details", "Possible identification of vulnerabilities", "Unauthorized access to system configuration"], "exploitation_scenario": {"prerequisites": ["No authentication is required"], "example": "HTTP GET request to http://target-tomcat-server/manager/text-report?showReport=true", "result": "Generation and download of a detailed Tomcat server report"}, "metric_justifications": {"ac": "Why AC=L: setting ''showReport'' to true requires no special preconditions beyond sending an HTTP request, making it easy for any unauthenticated attacker to trigger.", "c": "Why C=P: the report discloses sensitive information about the Tomcat server and its configuration.", "i": "Why I=N: the report does not allow modification of data or configuration.", "a": "Why A=N: the availability of the server is not affected by this misconfiguration.", "gel": "Why GEL=M: exploitation of this type of misconfiguration is common due to its simplicity and potential for information leakage.", "grl": "Why GRL=H: remediation documentation for this issue is widely available in security benchmarks and best practices."}}','2026-06-25T05:52:04.183Z','2026-06-25T06:17:37.135Z');
INSERT INTO misconfigurations VALUES('41a40050-6e97-43c3-bbe0-7e0f234af127',8,'tomcat','session-timeout','insecure_value','600','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222979r1043182_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The session-timeout directive determines how long an idle user session remains active before being terminated. Setting it to an insecure value (insecure_value) can lead to prolonged sessions, potentially allowing unauthorized access or data manipulation.", "potential_impact": ["Unauthorized access due to prolonged sessions", "Data manipulation during extended session periods", "Privilege escalation if combined with other vulnerabilities"], "exploitation_scenario": {"prerequisites": ["An unauthenticated attacker needs to establish a session", "Knowledge of the insecure session-timeout value"], "example": "For instance, with session-timeout=insecure_value, an attacker can keep a session alive for an extended period by simply sending HTTP requests without user interaction.", "result": "The attacker can perform actions such as data manipulation or privilege escalation during the prolonged session."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it easy to exploit.", "c": "Why C=P: No sensitive information is disclosed or readable due to the nature of the misconfiguration.", "i": "Why I=N: Data and configuration can be modified during the prolonged session, but not directly through this misconfiguration.", "a": "Why A=N: The availability of the system may not be affected as such, but the security of user sessions is compromised.", "gel": "Why GEL=M: Exploitation of this type of misconfiguration is common due to its simplicity and widespread use of insecure session-timeout values.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available, making it easier for administrators to address."}}','2026-06-25T05:52:04.187Z','2026-06-25T06:18:25.250Z');
INSERT INTO misconfigurations VALUES('113c013c-1b50-4b1d-8427-7661faa93e4c',8,'tomcat','failureCount','insecure_value','5','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222981r961281_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The failureCount directive is responsible for limiting the number of failed login attempts before locking an account. An insecure_value indicates that the limit is set too low or not set at all, potentially allowing brute force attacks to succeed. This can lead to unauthorized access and subsequent data breaches.", "potential_impact": ["Unauthorized account access", "Potential data breach", "Compromised system integrity"], "exploitation_scenario": {"prerequisites": ["Knowledge of the Tomcat server", "Basic network connectivity"], "example": "For instance, a configuration with failureCount=1 would allow an attacker to attempt 1 incorrect password within 30 seconds before locking the account.", "result": "Successful brute force attacks can lead to unauthorized access and potential data breaches."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit a low failureCount by attempting multiple passwords within the allowed timeframe, potentially gaining unauthorized access.", "c": "Why C=P: No sensitive data is disclosed or readable due to this misconfiguration.", "i": "Why I=N: The configuration does not allow for modification of sensitive data directly as a result of this misconfiguration.", "a": "Why A=N: System availability remains unaffected due to this misconfiguration, but unauthorized access can lead to potential downtime or data loss in subsequent attacks.", "gel": "Why GEL=M: Brute force attacks are common and frequent when the failureCount is set too low or not set at all.", "grl": "Why GRL=H: Remediation documentation for this type of misconfiguration is widely available, making it easier to address."}}','2026-06-25T05:52:04.192Z','2026-06-25T06:19:12.427Z');
INSERT INTO misconfigurations VALUES('3e1b7a05-e5eb-42e8-83e9-6c6eeb6447f6',8,'tomcat','shell','/bin/bash','/usr/sbin/nologin','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222983r961353_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''shell'' directive specifies the default shell for Tomcat users. Setting it to ''/bin/bash'' grants potentially malicious users a powerful and interactive command-line interface, which can lead to unauthorized system access, data manipulation, or denial of service. The recommended value is ''/usr/sbin/nologin'', which denies shell access.", "potential_impact": ["Unauthorized system access", "Data manipulation", "Denial of Service"], "exploitation_scenario": {"prerequisites": ["Authentication as a Tomcat user"], "example": "Tomcat user initiates a shell session: `http://server/manager/text`", "result": "Granted interactive shell access if ''shell'' is set to ''/bin/bash'', otherwise denied."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, given authentication as a Tomcat user.", "c": "Why C=P: No sensitive information is disclosed or readable beyond what the user already has access to.", "i": "Why I=N: The user''s level of access remains unchanged, but they gain an interactive shell which can be used to manipulate data and configuration.", "a": "Why A=N: Availability is not affected as long as the attacker does not exploit the shell for denial-of-service purposes.", "gel": "Why GEL=M: Exploitation of this misconfiguration is common due to its potential for system access and data manipulation.", "grl": "Why GRL=H: Remediation documentation is widely available, such as in the CIS Tomcat Benchmark."}}','2026-06-25T05:52:04.197Z','2026-06-25T06:19:59.148Z');
INSERT INTO misconfigurations VALUES('1a1df03f-e571-4cee-9a3f-24e38d189fc2',8,'tomcat','USER','root','tomcat','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222984r961353_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The USER directive specifies the Tomcat system user account. Setting it to ''root'' grants excessive privileges, as the root user has access to all files and resources on the system. This misconfiguration can lead to unauthorized data access, modification, or deletion.", "potential_impact": ["Unauthorized data access", "Modification of Tomcat configuration files", "Potential system compromise"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server''s configuration files"], "example": "In the server.xml file, changing the USER attribute from ''tomcat'' to ''root'': `<User username=''root'' password=''...'' />`", "result": "The Tomcat system user is changed to the root account, granting excessive privileges."}, "metric_justifications": {"ac": "Exploitation of this misconfiguration is easy as it only requires modifying a configuration file and restarting the server. No special skills or tools are needed beyond basic system administration.", "c": "The root user has access to all files on the system, potentially disclosing sensitive data.", "i": "The root user can modify any file on the system, including Tomcat configuration files and application data.", "a": "The availability of the Tomcat server may be affected if the root user inadvertently modifies critical files or configurations.", "gel": "Misconfigurations allowing a user to set their account to ''root'' are common and can be easily discovered by attackers.", "grl": "Remediation documentation for this misconfiguration is widely available, making it straightforward to address."}}','2026-06-25T05:52:04.202Z','2026-06-25T06:20:41.455Z');
INSERT INTO misconfigurations VALUES('e6891e32-9799-473f-b64f-cbc7ebf7c2a9',8,'tomcat','group','','tomcat','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222987r961461_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''group'' directive specifies the Tomcat user group that the server runs under. Setting it to an unspecified value (e.g., group=) can lead to potential privilege escalation and security vulnerabilities. This misconfiguration allows any attacker with access to the Tomcat server to modify the group membership, potentially gaining higher privileges.", "potential_impact": ["Privilege escalation", "Unauthorized access to system resources", "Altered system behavior due to modified group permissions"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat server configuration files"], "example": "Modifying the ''group'' directive in the Tomcat server.xml file: <User name=\"tomcat\" group=\"\" />", "result": "The Tomcat server will run under an unspecified group, potentially allowing privilege escalation."}, "metric_justifications": {"ac": "Why AC=L: Setting the ''group'' directive to an unspecified value (e.g., group=) is a simple configuration change that can be made by any attacker with access to the Tomcat server, making it easy to exploit.", "c": "Why C=P: The disclosed information includes the group membership of the Tomcat user, which may reveal sensitive system details.", "i": "Why I=N: No data or configuration can be directly modified by changing the ''group'' directive alone, but it can indirectly impact system behavior and security.", "a": "Why A=N: The availability of the Tomcat server is not affected by this misconfiguration, as long as proper access controls are in place.", "gel": "Why GEL=M: Misconfigurations involving group settings can be commonly found and exploited in Tomcat servers.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available in security best practices and CIS Benchmarks."}}','2026-06-25T05:52:04.208Z','2026-06-25T06:21:31.749Z');
INSERT INTO misconfigurations VALUES('10b68e80-9b71-4c6e-9c9d-870bf4183c4a',8,'tomcat','$CATALINA_BASE/logs ownership','not owned by tomcat user','owned by tomcat user','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222988r961461_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/logs directory not being owned by the Tomcat user can lead to potential unauthorized access and manipulation of log files, which may contain sensitive information such as application errors, user activity, and authentication data.", "potential_impact": ["Unauthorized access to sensitive log data", "Manipulation or deletion of log files", "Potential for privacy breaches"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server", "Knowledge of the Tomcat user account"], "example": "For example, an attacker can check the ownership of the logs directory using a simple ''ls -l'' command in a terminal.", "result": "If the logs directory is not owned by the Tomcat user, the attacker can potentially read, modify, or delete log files."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard file system command, making it easy to exploit.", "c": "Why C=P: Log files may contain sensitive information such as application errors, user activity, and authentication data.", "i": "Why I=N: The attacker can modify or delete log files, but cannot typically modify the Tomcat configuration or application code.", "a": "Why A=N: The attacker cannot directly affect the availability of the Tomcat server by manipulating log files.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to discover.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available."}}','2026-06-25T05:52:04.213Z','2026-06-25T06:22:16.908Z');
INSERT INTO misconfigurations VALUES('b30c209e-257a-4c96-b08c-2b4cea40d87a',8,'tomcat','$CATALINA_BASE/work ownership','','tomcat:tomcat','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222991r961461_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/work directory ownership should be set to tomcat:tomcat for proper Tomcat operation and security. Any other ownership configuration may lead to unauthorized access or modification of files within the work directory.", "potential_impact": ["Unauthorized read access to sensitive files", "Unauthorized write access leading to file manipulation", "Potential for privilege escalation"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat server", "Ability to modify Tomcat configuration"], "example": "$CATALINA_BASE/work ownership: user1:user1 instead of tomcat:tomcat", "result": "An attacker can read, write or manipulate files within the work directory, potentially leading to data breaches or server instability"}, "metric_justifications": {"ac": "Why AC=L: Changing the ownership of $CATALINA_BASE/work directory is a simple operation that can be done by any user with write access to Tomcat configuration files.", "c": "Why C=P: The work directory contains temporary files generated during Tomcat operation, some of which may contain sensitive information.", "i": "Why I=N: Modifying the ownership of $CATALINA_BASE/work directory allows an attacker to read, write or manipulate files within the directory.", "a": "Why A=N: Changing the ownership does not directly affect the availability of the Tomcat server.", "gel": "Why GEL=M: Misconfigurations in file permissions are common and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation for this misconfiguration is well-documented in the CIS Benchmark section SV-222991r961461_rule"}}','2026-06-25T05:52:04.217Z','2026-06-25T06:23:08.008Z');
INSERT INTO misconfigurations VALUES('5263f2b0-34d6-427a-909a-d963ba6e9b41',8,'tomcat','auth-method','insecure_value','CLIENT-CERT','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222993r985888_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''auth-method'' directive specifies the authentication method used by Tomcat. Setting it to ''insecure_value'' disables authentication altogether, allowing any unauthenticated attacker to access protected resources with a standard HTTP request.", "potential_impact": ["Unauthorized access to sensitive data", "Modification of server configuration", "Disruption of service availability"], "exploitation_scenario": {"prerequisites": ["Knowledge of the Tomcat server''s IP address or domain name", "Basic understanding of HTTP requests"], "example": "HTTP request: GET /protectedResource HTTP/1.1, where /protectedResource is a protected resource on the Tomcat server", "result": "Access granted to the protected resource without authentication"}, "metric_justifications": {"ac": "Why AC=L: exploitation requires only sending an HTTP request to a protected resource, no special preconditions beyond standard web attacks.", "c": "Why C=P: no sensitive information is disclosed or readable in this specific case as authentication is bypassed.", "i": "Why I=N: attackers can modify server configuration if they gain access to protected resources.", "a": "Why A=N: unauthenticated access can disrupt service availability depending on the protected resource and its functionality.", "gel": "Why GEL=M: this type of misconfiguration is common in Tomcat servers, making it a frequent target for attackers.", "grl": "Why GRL=H: remediation documentation is widely available, but proper configuration may require understanding of SSL certificates and client authentication."}}','2026-06-25T05:52:04.223Z','2026-06-25T06:23:52.886Z');
INSERT INTO misconfigurations VALUES('3ecde6b3-bf6b-4180-8e60-b6bb76232c25',8,'tomcat','javax.net.ssl.trustStore','insecure_value','/path/to/truststore','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222994r961596_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''javax.net.ssl.trustStore'' directive specifies the location of the trust store used by Tomcat to verify SSL certificates. Setting it to an insecure value (''insecure_value'') compromises the security of SSL communications, as it allows connections from untrusted sources.", "potential_impact": ["Allows man-in-the-middle attacks", "Enables data interception", "Potentially exposes sensitive information"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat configuration files"], "example": "Insecure value: ''insecure_value''. This configures Tomcat to trust all SSL certificates, effectively disabling SSL security.", "result": "An attacker can intercept and modify data transmitted over SSL, potentially exposing sensitive information."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request to change the trust store location.", "c": "Why C=P: The trust store contains certificates used for SSL verification, disclosing these could aid an attacker in impersonating trusted sources.", "i": "Why I=N: Changing the trust store location allows an attacker to bypass SSL security checks and potentially intercept data.", "a": "Why A=N: The availability of services is not directly affected, but the integrity and confidentiality of data transmitted over SSL are compromised.", "gel": "Why GEL=M: Misconfigurations of trust stores are common and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation documentation is widely available, but the specific configuration file may require a system administrator to locate and modify."}}','2026-06-25T05:52:04.226Z','2026-06-25T06:24:44.704Z');
INSERT INTO misconfigurations VALUES('968b6f69-962b-435c-b6f0-2e2b806b086f',8,'tomcat','org.apache.catalina.connector.CoyoteAdapter.ALLOW_BACKSLASH','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-223004r1135506_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The org.apache.catalina.connector.CoyoteAdapter.ALLOW_BACKSLASH directive, when set to true, allows an attacker to bypass certain security restrictions in Tomcat. This can lead to directory traversal attacks and unauthorized access to sensitive files.", "potential_impact": ["Unauthorized file read/write", "Disclosure of sensitive information", "Potential for remote code execution"], "exploitation_scenario": {"prerequisites": ["Network access to the Tomcat server"], "example": "HTTP request: /../webapps/ - navigates up one directory from the webapps directory", "result": "Access to parent directories and sensitive files"}, "metric_justifications": {"ac": "Allowing backslashes can make Tomcat vulnerable to directory traversal attacks, which are easy for an attacker to exploit with a standard HTTP request.", "c": "Sensitive files such as server configuration and application data may be readable.", "i": "An attacker can potentially modify or delete sensitive files.", "a": "The availability of the Tomcat server can be compromised if sensitive files are modified or deleted.", "gel": "Directory traversal attacks are common and easy to automate, making this misconfiguration exploitable frequently.", "grl": "Remediation documentation is widely available, making it relatively straightforward for an attacker to find and exploit this vulnerability."}}','2026-06-25T05:52:04.231Z','2026-06-25T06:25:24.503Z');
INSERT INTO misconfigurations VALUES('27dc4013-4b66-4bcc-befa-34fff7ca3253',8,'tomcat','org.apache.catalina.connector.Response.ENFORCE_ENCODING_IN_GET_WRITER','insecure_value','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-223005r1135509_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The directive org.apache.catalina.connector.Response.ENFORCE_ENCODING_IN_GET_WRITER controls whether Tomcat enforces encoding in GET requests. Setting it to insecure_value disables this enforcement, allowing an attacker to send maliciously crafted requests with special characters that could lead to unintended server behavior or data exposure.", "potential_impact": ["Unauthorized data access", "Server misconfiguration", "Potential for remote code execution"], "exploitation_scenario": {"prerequisites": ["An attacker can send a specially crafted GET request to the Tomcat server"], "example": "For example, an attacker could send a GET request with a URL like ''http://tomcat-server?param=<script>'', which would bypass the encoding enforcement and potentially execute malicious code on the server", "result": "The result of this exploitation could be unauthorized data access, server misconfiguration, or even remote code execution, depending on the specific vulnerabilities present in the Tomcat installation"}, "metric_justifications": {"ac": "Why AC=L: Setting org.apache.catalina.connector.Response.ENFORCE_ENCODING_IN_GET_WRITER to insecure_value allows an attacker to send specially crafted GET requests with minimal effort, making it easy for them to potentially exploit the server", "c": "Why C=P: With insecure encoding, an attacker could potentially access sensitive data or configuration information on the Tomcat server", "i": "Why I=N: An attacker could modify server behavior by sending maliciously crafted GET requests with special characters when encoding enforcement is disabled", "a": "Why A=N: The availability of the Tomcat server could be affected if an attacker successfully exploits a vulnerability due to insecure encoding", "gel": "Why GEL=M: Misconfigurations related to this directive are relatively common, making it a frequent target for attackers", "grl": "Why GRL=H: Remediation documentation is widely available and easy to find, but the success of the remediation depends on the specific configuration and vulnerabilities present in the Tomcat installation"}}','2026-06-25T05:52:04.237Z','2026-06-25T06:26:27.901Z');
INSERT INTO misconfigurations VALUES('f1048370-e053-4f29-bd41-5882937ef390',8,'tomcat','action_mail_acct','root','<email_address>','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-223010r985887_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The action_mail_acct directive specifies the email account used for Tomcat''s internal notifications. Setting it to ''root'' exposes these notifications to potential attackers. This could lead to unauthorized access to sensitive system information.", "potential_impact": ["Unauthorized access to system notifications", "Potential exposure of internal system details", "Possible escalation of privileges for an attacker"], "exploitation_scenario": {"prerequisites": ["Basic network access to the Tomcat server"], "example": "HTTP request: GET /manager/text HTTP/1.1\nHost: example.com", "result": "Access to system notifications sent to the action_mail_acct email address"}, "metric_justifications": {"ac": "Why AC=L: Exploiting this misconfiguration requires only sending a standard HTTP request, making it easy for any unauthenticated attacker.", "c": "Why C=P: The disclosed information includes internal system notifications which may contain sensitive details.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration.", "a": "Why A=N: System availability is not affected by this misconfiguration.", "gel": "Why GEL=M: Misconfigurations involving action_mail_acct are common, making exploitation frequent.", "grl": "Why GRL=H: Remediation documentation for this type of misconfiguration is widely available"}}','2026-06-25T05:52:04.242Z','2026-06-25T06:27:11.518Z');
INSERT INTO misconfigurations VALUES('bd21452a-8979-4e88-ac21-e3db5ed16167',8,'tomcat','hstsEnabled','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222928r960762_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The hstsEnabled directive is set to false, which disables HTTP Strict Transport Security (HSTS). This configuration allows an attacker to force non-secure connections, potentially leading to man-in-the-middle attacks and data interception. HSTS is crucial for enforcing secure connections and protecting against protocol downgrade attacks.", "potential_impact": ["Data interception", "Man-in-the-middle attacks", "Protocol downgrade attacks"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat configuration file"], "example": "Setting hstsEnabled=false in server.xml", "result": "Allows an attacker to force non-secure connections"}, "metric_justifications": {"ac": "With hstsEnabled=false, an unauthenticated attacker can trigger this with a standard HTTP request, making it easy to exploit.", "c": "No sensitive information is disclosed or readable due to the lack of HSTS.", "i": "No data or configuration can be modified directly as a result of hstsEnabled=false.", "a": "Availability is not affected by this misconfiguration, but the security of connections is compromised.", "gel": "HSTS misconfigurations are common and easy to exploit, making them a frequent target for attackers.", "grl": "Remediation documentation is widely available in resources such as the CIS Benchmark."}}','2026-06-25T05:52:04.248Z','2026-06-25T06:27:49.657Z');
INSERT INTO misconfigurations VALUES('cb315012-39b6-442a-9ef5-d1dade6b55b1',8,'tomcat','debug','insecure_value','0','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222953r960963_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''debug'' directive in Tomcat is used to enable debugging output. When set to ''insecure_value'', it allows unauthenticated attackers to view sensitive information such as stack traces, application source code, and internal server details. This can lead to data exposure and potential exploitation.", "potential_impact": ["Data exposure", "Potential application compromise", "Unauthorized access to internal server details"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server via HTTP"], "example": "HTTP GET request: `http://tomcat-server/debug`, which returns debugging information if ''debug'' is set to ''insecure_value''", "result": "Disclosure of sensitive information"}, "metric_justifications": {"ac": "Why AC=L: Exploitation requires only sending an HTTP request to the server, making it easy for any unauthenticated attacker.", "c": "Why C=P: Sensitive information such as stack traces, application source code, and internal server details are disclosed.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration.", "a": "Why A=N: Availability is not affected as the server remains operational.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to exploit.", "grl": "Why GRL=H: Remediation documentation is widely available in security resources."}}','2026-06-25T05:52:04.257Z','2026-06-25T06:29:22.710Z');
INSERT INTO misconfigurations VALUES('1165e4c2-509f-4022-8984-e3be7a509f52',8,'tomcat','listings','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222954r960963_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''listings'' directive set to true allows unauthenticated attackers to view directory listings of the web application''s files. This can reveal sensitive information such as file names and potentially expose vulnerable or sensitive files.", "potential_impact": ["Exposure of sensitive file names", "Reveal of vulnerable files", "Potential for unauthorized access to sensitive data"], "exploitation_scenario": {"prerequisites": ["Access to the web application''s URL"], "example": "HTTP GET request to a directory: http://example.com/directory/", "result": "Directory listings are displayed, revealing file names and potentially sensitive information"}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it easy to exploit.", "c": "Why C=P: Information disclosed includes file names and potentially sensitive information.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration.", "a": "Why A=N: The availability of the web application is not affected by this misconfiguration.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to exploit.", "grl": "Why GRL=H: Remediation documentation is widely available in security best practices."}}','2026-06-25T05:52:04.266Z','2026-06-25T06:30:00.456Z');
INSERT INTO misconfigurations VALUES('72fca197-98a8-4efd-a125-cb76d865e5d7',8,'tomcat','xpoweredBy','true','false','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222957r960963_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The xpoweredBy directive, when set to true, reveals Tomcat''s version information in the HTTP response header. This can aid attackers in identifying potential vulnerabilities and crafting targeted attacks against your server.", "potential_impact": ["Disclosure of server version information", "Facilitation of targeted attacks", "Potential for exploiting known vulnerabilities"], "exploitation_scenario": {"prerequisites": ["Sending a standard HTTP request to the server"], "example": "HTTP response header: X-Powered-By: Apache Tomcat/9.0.x", "result": "Attacker gains knowledge of the server''s version, which can be used for exploiting known vulnerabilities."}, "metric_justifications": {"ac": "Setting xpoweredBy to true makes it easy for any unauthenticated attacker to trigger this with a standard HTTP request.", "c": "The server version information is disclosed, providing valuable information about potential vulnerabilities.", "i": "No data or configuration can be modified directly through the xpoweredBy directive.", "a": "Server availability remains unaffected as long as the xpoweredBy directive does not cause any unintended issues.", "gel": "Exploitation of this misconfiguration is common due to its simplicity and widespread use of Tomcat servers.", "grl": "Remediation documentation for setting xpoweredBy to false is readily available in various security resources."}}','2026-06-25T05:52:04.271Z','2026-06-25T06:30:39.207Z');
INSERT INTO misconfigurations VALUES('144c3cfe-7a14-4e10-a4cc-b8a5792cc566',8,'tomcat','org.apache.catalina.connector. RECYCLE_FACADES','insecure_value','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222973r1043180_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The org.apache.catalina.connector. RECYCLE_FACADES directive determines whether Tomcat recycles Connector instances when they are idle. Setting it to insecure_value (false) can lead to memory leaks and increased resource usage, potentially causing performance issues or denial of service. The default value is true.", "potential_impact": ["Performance degradation due to memory leaks", "Increased resource consumption", "Potential Denial of Service"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat configuration files"], "example": "Setting org.apache.catalina.connector.RECYCLE_FACADES=false in the server.xml file", "result": "Memory leaks and increased resource usage"}, "metric_justifications": {"ac": "Why AC=L: Setting org.apache.catalina.connector.RECYCLE_FACADES to false is easy, requiring only modification of the server.xml file.", "c": "Why C=P: No sensitive information is disclosed or readable due to this misconfiguration.", "i": "Why I=N: The configuration can be modified, but no data or configuration can be directly altered as a result.", "a": "Why A=N: Availability is not affected by this misconfiguration.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to discover in Tomcat configurations.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available."}}','2026-06-25T05:52:04.276Z','2026-06-25T06:31:21.357Z');
INSERT INTO misconfigurations VALUES('07372acb-153d-4e74-a2b8-e2c5e63b6bdb',8,'tomcat','401.jsp content','insecure_value (sample passwords and user accounts)','secure_value (generic error information that assists users but does not provide sample data to users)','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222976r961170_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The 401.jsp content set to insecure_value (sample passwords and user accounts) exposes sensitive information, potentially allowing unauthenticated attackers to gain access to user credentials. This can lead to account takeover, data breaches, and further system compromises.", "potential_impact": ["Account takeover", "Data breach", "Further system compromise"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server over HTTP"], "example": "HTTP GET request to http://tomcat-server/error.jsp?exception=401", "result": "Disclosure of sample passwords and user accounts"}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, requiring no special preconditions beyond sending a request.", "c": "Why C=P: Sensitive information (sample passwords and user accounts) is disclosed.", "i": "Why I=N: No data or configuration can be modified through this vulnerability.", "a": "Why A=N: The availability of the system remains unaffected.", "gel": "Why GEL=M: This type of misconfiguration is common and easily exploitable by script kiddies and automated tools.", "grl": "Why GRL=H: Remediation documentation is widely available, such as in the CIS Benchmark section SV-222976r961170_rule"}}','2026-06-25T05:52:04.280Z','2026-06-25T06:32:01.941Z');
INSERT INTO misconfigurations VALUES('5fb21c4a-e4f4-44d0-a6b4-90878b0a54fc',8,'tomcat','lockOutTime','insecure_value','600','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222982r961281_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The lockOutTime directive sets the duration (in seconds) that an account is locked after a certain number of failed login attempts. An insecure value for this directive allows attackers to rapidly attempt multiple login combinations, potentially leading to account lockouts and denial-of-service conditions. The recommended value is 600 seconds.", "potential_impact": ["Account lockout leading to denial of service", "Potential brute force attacks on user accounts", "Unauthorized access if lockout duration is too short"], "exploitation_scenario": {"prerequisites": ["Knowledge of Tomcat configuration", "Access to the Tomcat server"], "example": "Insecure configuration: <LoginConfig> <Authentication> <Realm className=\"org.apache.catalina.realm.LockOutRealm\" lockOnFailure=\"true\" lockoutTime=\"insecure_value\"/> </Authentication></LoginConfig>", "result": "Account is locked out for an indefinite period, potentially leading to denial of service"}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit lockOutTime=insecure_value by rapidly attempting multiple login combinations. No special preconditions beyond sending a request are required.", "c": "Why C=P: No sensitive information is disclosed or readable due to the nature of this misconfiguration.", "i": "Why I=N: The configuration can be modified to set an insecure lockout duration, allowing for potential unauthorized access if the lockout duration is too short.", "a": "Why A=N: The availability of the Tomcat server may be affected due to account lockouts leading to denial of service.", "gel": "Why GEL=M: This type of misconfiguration allows for frequent exploitation attempts by attackers.", "grl": "Why GRL=H: Remediation documentation is widely available, but the impact of this misconfiguration may not be immediately apparent, making it harder to prioritize remediation."}}','2026-06-25T05:52:04.284Z','2026-06-25T06:32:53.343Z');
INSERT INTO misconfigurations VALUES('391deb9f-f7a8-4ece-b036-376be03ba719',8,'tomcat','$CATALINA_BASE/temp/ owner','insecure_user','tomcat','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222989r961461_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/temp/ owner directive specifies the user that owns the files in the Tomcat temporary directory. Setting it to an insecure user (insecure_user) can lead to unauthorized file manipulation and potential privilege escalation. This misconfiguration allows any attacker with network access to modify Tomcat''s temporary files, which could result in data corruption or unauthorized access.", "potential_impact": ["Data corruption", "Privilege escalation", "Unauthorized access"], "exploitation_scenario": {"prerequisites": ["Network access to the Tomcat server"], "example": "For example, an attacker can modify a file by sending a request to change the ownership of a file in $CATALINA_BASE/temp/: `sudo chown insecure_user /path/to/tomcat/temp/file.txt`", "result": "The attacker gains write access to Tomcat''s temporary files, potentially causing data corruption or unauthorized access."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily modify the ownership of files in $CATALINA_BASE/temp/ by sending a simple network request. No special preconditions are required beyond network access.", "c": "Why C=P: The attacker can read and write to Tomcat''s temporary files, potentially disclosing sensitive information or modifying configuration files.", "i": "Why I=N: The attacker can modify the contents of Tomcat''s temporary files, which could lead to data corruption or unauthorized access.", "a": "Why A=N: The availability of Tomcat services may be affected if the attacker modifies critical configuration files or causes data corruption.", "gel": "Why GEL=M: Misconfigurations involving file ownership and permissions are common, making this type of exploit relatively frequent.", "grl": "Why GRL=H: Remediation documentation for securing Tomcat''s file system is widely available in resources such as the CIS Benchmark."}}','2026-06-25T05:52:04.295Z','2026-06-25T06:35:12.844Z');
INSERT INTO misconfigurations VALUES('3fa48411-d8b4-4be2-a678-ec4e461f5074',8,'tomcat','$CATALINA_BASE/temp permissions','less than 750','750','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-222990r961461_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The $CATALINA_BASE/temp directory should have permissions set to 750 or higher to prevent unauthorized users from reading, modifying, or executing files within this directory. A permission of less than 750 allows read access for all users and write access for the owner and group, making it easy for an attacker to view sensitive files or inject malicious code.", "potential_impact": ["Unauthorized file reading", "Code injection leading to arbitrary command execution", "Data leakage"], "exploitation_scenario": {"prerequisites": ["Access to the Tomcat server", "Knowledge of the $CATALINA_BASE directory location"], "example": "$ chmod 640 /path/to/$CATALINA_BASE/temp", "result": "An attacker can read sensitive files or inject malicious code into Tomcat."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily access the $CATALINA_BASE/temp directory with less than 750 permissions by simply changing the file permissions using a command like chmod.", "c": "Why C=P: Sensitive files within the $CATALINA_BASE/temp directory can be read by unauthorized users.", "i": "Why I=N: The attacker cannot modify the files or configuration within the $CATALINA_BASE/temp directory with less than 750 permissions.", "a": "Why A=N: The attacker cannot affect the availability of the Tomcat server by modifying files in the $CATALINA_BASE/temp directory with less than 750 permissions.", "gel": "Why GEL=M: Misconfigurations like this are common and easy to exploit, making it a frequent target for attackers.", "grl": "Why GRL=H: Remediation documentation is widely available in security benchmarks such as the CIS Tomcat Benchmark."}}','2026-06-25T05:52:04.301Z','2026-06-25T06:36:05.244Z');
INSERT INTO misconfigurations VALUES('277d9ca0-1aa1-418a-874a-55b27ec7bd75',8,'tomcat','javax.net.ssl.trustStore','','/path/to/truststore','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-223001r1137585_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The ''javax.net.ssl.trustStore'' directive specifies the location of the trust store file used by Tomcat for SSL connections. Setting it to an empty string or omitting it entirely allows an attacker to use a self-signed certificate, potentially leading to man-in-the-middle attacks and data interception.", "potential_impact": ["Data interception", "Man-in-the-middle attacks", "Trust store compromise"], "exploitation_scenario": {"prerequisites": ["Network access to the Tomcat server"], "example": "An attacker can send a request with a self-signed certificate to the Tomcat server.", "result": "The Tomcat server may accept the self-signed certificate, allowing the attacker to intercept and modify data."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTPS request using a self-signed certificate.", "c": "Why C=P: No sensitive information is disclosed or readable, but data integrity and confidentiality are compromised.", "i": "Why I=N: No data or configuration can be modified directly as a result of this misconfiguration.", "a": "Why A=N: The availability of the service remains unaffected.", "gel": "Why GEL=M: This type of misconfiguration is common and easy to exploit.", "grl": "Why GRL=H: Remediation documentation is widely available, but proper configuration may require understanding SSL certificates."}}','2026-06-25T05:52:04.307Z','2026-06-25T06:36:45.095Z');
INSERT INTO misconfigurations VALUES('028ac2a7-28fe-42e6-935f-52f2b2ec58b7',8,'tomcat','org.apache.catalina.STRICT_SERVLET_COMPLIANCE','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-223002r961863_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The org.apache.catalina.STRICT_SERVLET_COMPLIANCE directive is set to false, which disables strict servlet compliance checks. This configuration allows for potential security vulnerabilities as it may lead to deserialization attacks and other code injection techniques. These attacks can result in unauthorized access, data theft, or server compromise.", "potential_impact": ["Unauthorized access", "Data theft", "Server compromise"], "exploitation_scenario": {"prerequisites": ["An attacker needs to send a specially crafted request to the Tomcat server"], "example": "For example, an attacker can send a malicious serialized Java object as a request parameter: `http://tomcat-server?obj=MaliciousObject`", "result": "Upon receiving the malicious request, the Tomcat server may deserialize and execute the attacker''s code, leading to unauthorized access or data theft."}, "metric_justifications": {"ac": "Why AC=L: With org.apache.catalina.STRICT_SERVLET_COMPLIANCE set to false, an attacker can easily send a specially crafted request to exploit deserialization vulnerabilities.", "c": "Why C=P: Sensitive data or configuration may be readable by an attacker during the exploitation.", "i": "Why I=N: No data or configuration can be modified directly due to the nature of deserialization attacks.", "a": "Why A=N: The availability of the Tomcat server is not affected in this specific misconfiguration, but the server''s security and integrity are compromised.", "gel": "Why GEL=M: Deserialization vulnerabilities are common and can be easily exploited by attackers.", "grl": "Why GRL=H: Remediation documentation for deserialization attacks is widely available online."}}','2026-06-25T05:52:04.312Z','2026-06-25T06:37:33.533Z');
INSERT INTO misconfigurations VALUES('bc70fd47-2326-43e9-9789-67e195d8a427',8,'tomcat','org.apache.catalina.connector.RECYCLE_FACADES','false','true','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','SV-223003r1135503_rule','Fallback: LLM unavailable.','Follow CIS recommendation.','value','always','','{"description": "The org.apache.catalina.connector.RECYCLE_FACADES directive controls whether Tomcat recycles connector facades on each request. Setting it to false can lead to memory leaks and increased resource consumption, potentially causing performance issues or denial of service.", "potential_impact": ["Performance degradation due to memory leaks", "Increased resource consumption leading to potential denial of service"], "exploitation_scenario": {"prerequisites": ["Access to Tomcat server configuration"], "example": "Setting org.apache.catalina.connector.RECYCLE_FACADES to false in the server.xml file.", "result": "Memory leaks and increased resource consumption over time"}, "metric_justifications": {"ac": "Why AC=L: Setting org.apache.catalina.connector.RECYCLE_FACADES to false makes it easy for an attacker to trigger memory leaks and increase resource consumption, leading to performance issues or denial of service.", "c": "Why C=P: No sensitive information is disclosed by this misconfiguration.", "i": "Why I=N: The configuration itself can be modified, but no data or user-specific information can be altered.", "a": "Why A=N: The availability of the Tomcat server is not directly affected by this misconfiguration, but performance issues may occur over time.", "gel": "Why GEL=M: This type of misconfiguration is relatively common and easy to identify during security audits.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available in Tomcat security best practices."}}','2026-06-25T05:52:04.316Z','2026-06-25T06:38:19.263Z');
INSERT INTO attack_chains VALUES(1,1,'apache-httpd','directory-traversal-chain','["Options", "AllowOverride"]',1.5,'Options FollowSymLinks or Indexes combined with AllowOverride All allows user-controlled .htaccess to escalate privileges and enable directory traversal or execution of arbitrary scripts.',0,'2026-06-20T01:42:43.048Z');
INSERT INTO attack_chains VALUES(2,1,'apache-httpd','dos-amplification','["Timeout", "KeepAliveTimeout", "MaxKeepAliveRequests"]',1.39999999999999991,'Permissive Timeout + KeepAliveTimeout + unbounded MaxKeepAliveRequests create compounding resource exhaustion vectors. An attacker can hold connections open and multiply the DoS impact.',0,'2026-06-20T01:42:43.050Z');
INSERT INTO attack_chains VALUES(3,1,'apache-httpd','info-disclosure-chain','["ServerTokens", "ServerSignature"]',1.30000000000000004,'Both ServerTokens and ServerSignature leaking version details compound the information disclosure risk, giving attackers precise version targeting.',0,'2026-06-20T01:42:43.053Z');
INSERT INTO attack_chains VALUES(4,1,'apache-httpd','load-module-status-on','["LoadModule", "ServerTokens"]',1.39999999999999991,'Enabling the status module with LoadModule and setting ServerTokens to Full reveals detailed server information, aiding attackers in reconnaissance and targeted exploitation.',0,'2026-06-20T01:42:43.055Z');
INSERT INTO attack_chains VALUES(5,1,'apache-httpd','load-module-status-userdir','["LoadModule", "User"]',1.60000000000000008,'Loading the status_module and setting User to root allows an attacker to access detailed server statistics via /server-status, which can be exploited for further reconnaissance or privilege escalation.',0,'2026-06-20T01:42:43.057Z');
INSERT INTO attack_chains VALUES(6,1,'apache-httpd','options-all-status-module','["Options", "LoadModule"]',1.39999999999999991,'Enabling Options All and loading the status_module allows an attacker to access detailed server statistics via /server-status, which can be used for further reconnaissance or denial of service attacks.',0,'2026-06-20T01:42:43.059Z');
INSERT INTO attack_chains VALUES(7,1,'apache-httpd','options-indexes-autoindex-module','["Options", "LoadModule"]',1.39999999999999991,'Enabling Options Indexes and loading the autoindex_module allows directory listings to be displayed, which can expose sensitive file structures and facilitate further reconnaissance or exploitation.',0,'2026-06-20T01:42:43.061Z');
INSERT INTO attack_chains VALUES(8,1,'apache-httpd','privilege-escalation','["User", "Group"]',1.60000000000000008,'Setting User and Group to root grants the Apache server full administrative privileges, allowing an attacker who gains access through any vulnerability to escalate their privileges immediately.',0,'2026-06-20T01:42:43.068Z');
INSERT INTO attack_chains VALUES(9,1,'apache-httpd','request-smuggling-chain','["LimitRequestLine", "LimitRequestFields", "LimitRequestFieldSize"]',1.39999999999999991,'Overly permissive request size limits across line, fields, and field size create compounding HTTP request smuggling and buffer overflow risk when multiple limits are misconfigured together.',0,'2026-06-20T01:42:43.071Z');
INSERT INTO attack_chains VALUES(10,1,'apache-httpd','server-tokens-full-sslprotocol-all','["ServerTokens", "SSLProtocol"]',1.39999999999999991,'Setting ServerTokens to Full and SSLProtocol to All provides detailed information about the server''s software version, which can be used by an attacker for targeted exploitation or reconnaissance.',0,'2026-06-20T01:42:43.074Z');
INSERT INTO attack_chains VALUES(11,1,'apache-httpd','webdav-rce-chain','["LoadModule", "AllowOverride"]',1.69999999999999995,'WebDAV modules (dav_module, dav_fs_module) loaded with permissive AllowOverride enables remote file upload and execution. This chain has the highest amplification — remote code execution in one step.',0,'2026-06-20T01:42:43.076Z');
INSERT INTO attack_chains VALUES(12,2,'nginx','server-info-to-tls-downgrade','["server_tokens", "ssl_protocols"]',1.39999999999999991,'Step 1 (server_tokens on) discloses the exact Nginx version in every HTTP response header, allowing an attacker to identify the specific OpenSSL version in use. Step 2 (ssl_protocols with SSLv3 or TLSv1/TLSv1.1) enables deprecated protocol versions with known cryptographic weaknesses. Together, version disclosure enables the attacker to precisely target the exposed TLS implementation with protocol-specific exploits (POODLE, BEAST), converting a passive information leak into an active MitM downgrade attack. Full path: reconnaissance via Server header → identify vulnerable TLS version → protocol downgrade attack.',0,'2026-06-20T01:49:46.694Z');
INSERT INTO attack_chains VALUES(13,2,'nginx','dos-resource-exhaustion','["send_timeout", "client_max_body_size", "keepalive_timeout"]',1.5,'Step 1 (send_timeout 0) removes the upper bound on how long Nginx waits for a client to receive a response, keeping worker connections open indefinitely for slow clients. Step 2 (client_max_body_size 0) removes request body size limits, allowing arbitrarily large uploads that consume memory and I/O. Step 3 (keepalive_timeout 0 or 65) compounds the attack surface: a value of 0 disables keepalive entirely, forcing a new connection per request and exhausting connection slots, while an excessive value holds connections open beyond reasonable use. Together, these three directives remove all throttling mechanisms and allow a low-bandwidth attacker to exhaust Nginx worker connections with minimal resources. Full path: initiate many slow connections → hold workers open indefinitely → exhaust server capacity.',0,'2026-06-20T01:49:46.695Z');
INSERT INTO attack_chains VALUES(14,2,'nginx','unencrypted-proxy-with-weak-tls','["proxy_pass", "ssl_protocols"]',1.39999999999999991,'Step 1 (proxy_pass to http://) routes backend traffic over unencrypted HTTP within the internal network, exposing credentials, session tokens, and API responses to any attacker with network access to the internal segment. Step 2 (ssl_protocols with weak protocols) means the client-facing connection is also potentially weak, enabling a MitM attacker to simultaneously intercept both the external TLS session (via downgrade) and the cleartext internal hop. Together, these directives create an end-to-end exposure path: attacker downgrades the external TLS session, then reads the cleartext proxy-to-backend channel. Full path: TLS downgrade on client connection → intercept cleartext proxy_pass channel → capture sensitive data.',0,'2026-06-20T01:49:46.697Z');
INSERT INTO attack_chains VALUES(18,4,'mysql','skip-grant-tables-log-raw','["skip-grant-tables", "log-raw"]',1.60000000000000008,'The ''skip-grant-tables'' directive allows anyone to bypass authentication and access the database without any restrictions, while ''log-raw'' logs detailed information about all SQL queries in a raw format. Together, these misconfigurations enable an attacker to gain full administrative control over the MySQL server by logging into it without credentials and viewing sensitive data through logged queries.',0,'2026-06-22T09:28:32.927Z');
INSERT INTO attack_chains VALUES(19,4,'mysql','allow-suspicious-udfs-log-raw','["allow-suspicious-udfs", "log-raw"]',1.60000000000000008,'''Allow-suspicious-udfs'' enables the use of potentially dangerous user-defined functions, which can be exploited to execute arbitrary code on the server. Combined with ''log-raw'', an attacker can gain detailed insights into SQL queries and system operations, facilitating further exploitation through UDFs.',0,'2026-06-22T09:28:32.936Z');
INSERT INTO attack_chains VALUES(20,4,'mysql','master-info-repository-file-log-raw','["master_info_repository", "log-raw"]',1.60000000000000008,'''Master_info_repository=FILE'' stores replication master information in a file, which can be read to obtain sensitive data such as passwords and server addresses. When combined with ''log-raw'', an attacker gains detailed logs of all SQL queries, including those related to replication, making it easier to exploit the stored replication information.',0,'2026-06-22T09:28:32.939Z');
INSERT INTO attack_chains VALUES(21,6,'docker','docker-privilege-escalation-pids','["--net", "--pids-limit"]',1.39999999999999991,'The combination of running commands with root privileges on the host system (step 1) and no limit on the number of processes (step 2) allows an attacker to escalate their privileges further by creating multiple processes.',0,'2026-06-24T22:43:43.412Z');
INSERT INTO attack_chains VALUES(22,7,'redis','file-permissions-escalation','["/etc/opt/redislabs/permissions", "directory_permissions"]',1.19999999999999995,'The misconfiguration of file permissions (704) for the RedisLabs directory allows an attacker to read sensitive files. Combined with the misconfiguration of directory permissions (701), an attacker can escalate privileges and potentially gain access to other protected directories.',0,'2026-06-25T05:13:14.751Z');
INSERT INTO attack_chains VALUES(23,7,'redis','tls-version-exploit','["tls_version", "min_data_TLS_version"]',1.19999999999999995,'The misconfiguration of TLS versions (< v1.2) and minimum data TLS version (1.0) allows an attacker to use older, insecure protocols for communication with the server. This can lead to exploitation by downgrade attacks.',0,'2026-06-25T05:13:14.758Z');
INSERT INTO attack_chains VALUES(24,7,'redis','fips-bypass','["fips", "/proc/sys/crypto/fips_enabled"]',1.39999999999999991,'The misconfiguration of FIPS mode (insecure_value) and the setting of fips_enabled to 0 allows an attacker to bypass FIPS restrictions on cryptographic algorithms, potentially leading to the use of weak or insecure algorithms.',0,'2026-06-25T05:13:14.766Z');
INSERT INTO attack_chains VALUES(25,7,'redis','certificate-exploit','["certificate", "persistence"]',1.39999999999999991,'The misconfiguration of the server certificate (insecure_value) and persistence settings allows an attacker to potentially intercept or manipulate SSL/TLS communications. This can lead to man-in-the-middle attacks or data theft.',0,'2026-06-25T05:13:14.773Z');
INSERT INTO attack_chains VALUES(26,7,'redis','lua-scripts-privilege-escalation','["lua_scripts_enabled", "user_role"]',1.19999999999999995,'The misconfiguration of Lua scripts (true) allows an attacker to execute arbitrary code on the server. Combined with the misconfiguration of user role (viewer), an attacker can potentially escalate privileges and gain access to sensitive data.',0,'2026-06-25T05:13:14.780Z');
INSERT INTO attack_chains VALUES(27,8,'tomcat','ldap-password-exposure','["com.sun.management.jmxremote.ssl", "connectionURL"]',1.19999999999999995,'Step 1 (com.sun.management.jmxremote.ssl=false) disables SSL for JMX connections, making them vulnerable to interception. Step 2 (connectionURL=ldap://localhost:389) exposes the LDAP server''s location and port number, enabling an attacker to perform a man-in-the-middle attack and potentially gain access to sensitive data.',0,'2026-06-25T05:54:02.582Z');
INSERT INTO attack_chains VALUES(28,8,'tomcat','tomcat-user-info-disclosure','["showServerInfo", "showReport"]',1.19999999999999995,'Step 1 (showServerInfo=true) discloses server information, potentially revealing sensitive details about the Tomcat installation. Step 2 (showReport=true) provides additional information about the server''s configuration, aiding an attacker in identifying vulnerabilities.',0,'2026-06-25T05:54:02.590Z');
INSERT INTO attack_chains VALUES(29,8,'tomcat','tomcat-session-exposure','["session-timeout", "failureCount"]',1.19999999999999995,'Step 1 (session-timeout=insecure_value) does not set a session timeout, potentially allowing an attacker to maintain an active session for an extended period. Step 2 (failureCount=insecure_value) does not limit the number of failed login attempts, making brute-force attacks easier.',0,'2026-06-25T05:54:02.594Z');
